def _weeknum(s, return_type=2):
    """WEEKNUM 实现。

    Args:
        s: 日期 Series
        return_type: 1=周日开始, 2=周一开始（默认，ISO 标准）
    """
    s = pd.to_datetime(s, errors='coerce')
    # 将 return_type 转为 int（处理标量或 Series）
    if isinstance(return_type, pd.Series):
        return_type = return_type.iloc[0] if len(return_type) > 0 else 2
    if isinstance(return_type, (int, float, np.integer, np.floating)):
        rt = int(return_type)
    else:
        rt = 2
    if rt == 1:
        # 周日开始：%U 从 0 计数，+1 对齐 Excel 从 1 开始
        return s.dt.strftime('%U').astype(int) + 1
    else:
        # 周一开始（ISO 8601）
        return s.dt.isocalendar().week.astype(int)


def _datedif(start, end, unit):
    """DATEDIF 实现（单位: "Y"/"M"/"D"）。"""
    start = pd.to_datetime(start, errors='coerce')
    end = pd.to_datetime(end, errors='coerce')
    diff = end - start
    unit = str(unit).upper().strip('"\'')
    if unit == 'Y':
        return (diff.dt.days / 365.25).astype(int)
    elif unit == 'M':
        return (diff.dt.days / 30.44).astype(int)
    elif unit == 'D':
        return diff.dt.days
    return diff.dt.days


# ==================== 公式解析与求值 ====================

def _tokenize_excel_formula(expr: str) -> list[tuple[str, str]]:
    """将 Excel 公式拆分为 token 列表。

    每项为 (type, value)，type 包括:
      'func'   - 函数名（后跟 '('）
      'lparen' - '('
      'rparen' - ')'
      'comma'  - ','
      'col'    - 列引用（会被替换）
      'literal' - 字符串字面量 'xxx' 或 "xxx"
      'number' - 数字
      'op'     - 运算符 + - * / > < = & 等
      'ident'  - 其他标识符
    """
    tokens = []
    i = 0
    n = len(expr)

    while i < n:
        ch = expr[i]

        # 空白
        if ch.isspace():
            i += 1
            continue

        # 字符串字面量
        if ch in ("'", '"'):
            quote = ch
            j = i + 1
            while j < n and expr[j] != quote:
                if expr[j] == '\\':
                    j += 1
                j += 1
            tokens.append(('literal', expr[i:j + 1]))
            i = j + 1
            continue

        # 数字
        if ch.isdigit() or (ch == '.' and i + 1 < n and expr[i + 1].isdigit()):
            j = i
            while j < n and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            tokens.append(('number', expr[i:j]))
            i = j
            continue

        # 括号 / 逗号
        if ch == '(':
            # 前一个 token 是标识符 → 函数名
            if tokens and tokens[-1][0] == 'ident':
                prev_val = tokens.pop()[1]
                if prev_val.upper() in _EXCEL_FUNC_REGISTRY:
                    tokens.append(('func', prev_val.upper()))
                else:
                    # 不是注册的函数，还原为 ident
                    tokens.append(('ident', prev_val))
            tokens.append(('lparen', '('))
            i += 1
            continue
        if ch == ')':
            tokens.append(('rparen', ')'))
            i += 1
            continue
        if ch == ',':
            tokens.append(('comma', ','))
            i += 1
            continue

        # 运算符
        if ch in '+-*/><=&|^%':
            if i + 1 < n and expr[i:i + 2] in ('>=', '<=', '!=', '<>', '=='):
                tokens.append(('op', expr[i:i + 2]))
                i += 2
            else:
                tokens.append(('op', ch))
                i += 1
            continue

        # 标识符（列名、函数名、关键字）
        j = i
        while j < n and not expr[j].isspace() and expr[j] not in '(),\'"+-*/><=&|^%':
            j += 1
        ident = expr[i:j]
        # 如果紧接着是 (, 会作为函数名处理
        tokens.append(('ident', ident))
        i = j

    return tokens


def _convert_tokens_to_python(tokens: list[tuple[str, str]],
                               col_map: dict[str, str]) -> str:
    """将 Excel token 列表转换为 Python 表达式。

    Args:
        tokens: token 列表
        col_map: {原始列名: 安全 DF 列名} 映射（实际已被替换）

    Returns:
        Python 表达式字符串
    """
    parts = []
    for ttype, tval in tokens:
        if ttype == 'func':
            # Excel 函数 → Python 函数引用（通过 _EF 命名空间访问）
            parts.append(f"_EF['{tval}']")
        elif ttype == 'lparen':
            parts.append('(')
        elif ttype == 'rparen':
            parts.append(')')
        elif ttype == 'comma':
            parts.append(',')
        elif ttype == 'op':
            parts.append(tval)
        elif ttype == 'number':
            parts.append(tval)
        elif ttype == 'literal':
            parts.append(tval)
        elif ttype == 'ident':
            # 标识符可能是列名 → 替换为 _df[...] 访问
            # 先检查是否匹配任一列名
            if tval in col_map:
                parts.append(f"_df['{tval}']")
            else:
                parts.append(tval)
        else:
            parts.append(tval)

    return ' '.join(parts)


def _eval_formula(expr: str, df: pd.DataFrame) -> pd.Series:
    """对 DataFrame 求值单个 Excel 公式。

    算法:
    1. 解析 token
    2. 识别列名（通过 _find_col_refs_in_tokens 辅助匹配 df 的列）
    3. 转换成 Python 表达式
    4. 在受控命名空间中 eval

    Args:
        expr: 规范化后的 Excel 公式（已去等号、已替换中文标点）
        df: 数据 DataFrame

    Returns:
        计算结果 Series
    """
    # 构建列名匹配表
    df_cols = df.columns.tolist()
    col_map = {c: c for c in df_cols}  # 保持原始列名不变

	# 尝试简单情况：纯算术表达式 → 直接用 df.eval
    if not _has_excel_func(expr):
        safe_expr, safe_map, _ = _replace_column_refs(expr, df_cols)
        rename_map = {v: k for k, v in safe_map.items()}
        temp_df = df.rename(columns=rename_map)
        try:
            return temp_df.eval(safe_expr)
        except Exception:
            pass

    # --- 向量化路径：tokenize + 构建 Python 表达式（缓存编译结果） ---
    # 缓存思路：同一公式列对不同 batch 列集相同，tokenize 和 build 可复用
    cache_key = (expr, frozenset(df_cols))
    compiled = getattr(_eval_formula, '_cache', None)
    if compiled is None:
        compiled = {}
        _eval_formula._cache = compiled

    py_expr = compiled.get(cache_key)
    if py_expr is None:
        tokens = _tokenize_excel_formula(expr)
        col_set = set(df_cols)
        for idx, (ttype, tval) in enumerate(tokens):
            if ttype == 'ident':
                stripped = tval.strip('[]') if tval.startswith('[') and tval.endswith(']') else tval
                if stripped in col_set:
                    tokens[idx] = ('col', stripped)
                elif tval in col_set:
                    tokens[idx] = ('col', tval)
                else:
                    for col in df_cols:
                        if col in stripped or stripped in col:
                            tokens[idx] = ('col', col)
                            break
        py_expr = _build_python_expr_from_tokens(tokens, df_cols)
        compiled[cache_key] = py_expr
        if len(compiled) > 128:
            oldest = next(iter(compiled))
            del compiled[oldest]

    namespace = {
        '_df': df,
        '_EF': _build_func_wrappers(),
        'np': np,
        'pd': pd,
    }
    try:
        result = eval(py_expr, {"__builtins__": {}}, namespace)
        return _ensure_series(result, df.index)
    except Exception as e:
        raise ValueError(f"公式求值失败: {e}")


def _has_excel_func(expr: str) -> bool:
    """检查表达式是否包含 Excel 函数调用。"""
    for func_name in _EXCEL_FUNC_REGISTRY:
        pattern = r'\b' + func_name + r'\s*\('
        if re.search(pattern, expr, re.IGNORECASE):
            return True
    return False


def _build_func_wrappers() -> dict:
    """构建函数包装器：从注册表中提取纯函数部分。

    返回 {FUNC_NAME: callable}，但包装了参数处理逻辑。
    """
    wrappers = {}
    for name, (func, min_args, max_args) in _EXCEL_FUNC_REGISTRY.items():
        wrappers[name] = func
    return wrappers


def _build_python_expr_from_tokens(tokens: list[tuple[str, str]],
                                    df_cols: list[str]) -> str:
    """将 token 列表转换为可执行的 Python 表达式字符串。

    转换规则:
    - func(token)  → _EF['FUNC_NAME'](
    - col(token)   → _df['col_name']
    - ident(token) → token（可能是 True/False/None）
    - 其余保持原样
    """
    parts = []
    col_set = set(df_cols)

    for ttype, tval in tokens:
        if ttype == 'func':
            # 函数引用，不追加 '(' — 由紧跟的 lparen 处理
            parts.append(f"_EF['{tval}']")
        elif ttype == 'lparen':
            parts.append('(')
        elif ttype == 'rparen':
            parts.append(')')
        elif ttype == 'comma':
            parts.append(',')
        elif ttype == 'col':
            parts.append(f"_df['{tval}']")
        elif ttype == 'ident':
            upper = tval.upper()
            if upper in ('TRUE', 'FALSE', 'NONE'):
                parts.append(upper == 'TRUE' and 'True' or (upper == 'FALSE' and 'False' or 'None'))
            elif _is_number(tval):
                parts.append(tval)
            elif tval in col_set:
                parts.append(f"_df['{tval}']")
            else:
                # 处理 [列名] 方括号语法
                stripped = tval.strip('[]') if tval.startswith('[') and tval.endswith(']') else tval
                if stripped in col_set:
                    parts.append(f"_df['{stripped}']")
                else:
                    parts.append(tval)
        elif ttype == 'number':
            parts.append(tval)
        elif ttype == 'literal':
            parts.append(tval)
        elif ttype == 'op':
            # Excel 公式中的 = 是比较运算符，Python 中需要 ==；<> 转为 !=
            if tval == '=':
                op = '=='
            elif tval == '<>':
                op = '!='
            else:
                op = tval
            parts.append(' ' + op + ' ')
        else:
            parts.append(tval)

    return ''.join(parts)


def _is_number(s: str) -> bool:
    try:
        float(s)
        return True
    except ValueError:
        return False


def _ensure_series(result, index) -> pd.Series:
    """确保结果是 pandas Series（标量值广播为 Series）。"""
    if isinstance(result, pd.Series):
        return result
    if isinstance(result, pd.DataFrame):
        return result.iloc[:, 0]
    if np.isscalar(result):
        return pd.Series(result, index=index)
    return pd.Series(result, index=index)


# ==================== 公式列入口 ====================

def eval_formula_columns(df: pd.DataFrame, columns: list) -> pd.DataFrame:
    """对 DataFrame 应用所有公式列。

    Args:
        df: 数据 DataFrame
        columns: FieldColumn 对象列表

    Returns:
        增加了计算列的 DataFrame
    """
    formula_count = sum(1 for c in columns if _is_formula(c))
    logger.info(f"[FormulaEngine] 开始计算 {formula_count} 个公式列, DataFrame {len(df)} 行 x {len(df.columns)} 列")
    try:
        return _eval_formula_columns_impl(df, columns)
    except Exception as e:
        import traceback
        logger.error(f"[FormulaEngine] 顶层异常: {e}\n{traceback.format_exc()}")
        return df
    except BaseException as e:
        # 捕获 MemoryError / SystemExit 等，防止闪退
        logger.error(f"[FormulaEngine] 致命异常（BaseException）: {e}")
        return df


def _resolve_api_field_refs(expr: str, api_to_display: dict[str, str]) -> str:
    """将公式中的 CRM API 字段名（如 field_yMJbo__c）替换为 DataFrame 显示名列名。

    按字段名长度降序替换，避免短名误匹配长名的一部分。
    """
    if not api_to_display:
        return expr
    result = expr
    for api_name in sorted(api_to_display, key=len, reverse=True):
        display = api_to_display[api_name]
        if api_name in result:
            result = result.replace(api_name, display)
    return result


def _eval_formula_columns_impl(df: pd.DataFrame, columns: list) -> pd.DataFrame:
    """eval_formula_columns 的实际实现。"""
    # 构建 CRM API 字段名 → 显示名 的映射（用于公式中引用内部字段名的场景）
    api_to_display = {}
    for col in columns:
        sf = col.source_field if hasattr(col, 'source_field') else col.get('source_field', '')
        dn = col.display_name if hasattr(col, 'display_name') else col.get('display_name', '')
        if sf and dn and dn in df.columns:
            api_to_display[sf] = dn

    for col in columns:
        if not _is_formula(col):
            continue
        raw_expr = col.formula_expression if hasattr(col, 'formula_expression') else col.get('formula_expression', '')
        if not raw_expr or not str(raw_expr).strip():
            continue

        # 将公式中的 CRM API 字段名替换为 DataFrame 中的显示名列名
        display = (col.display_name if hasattr(col, 'display_name') else col.get('display_name', '')) or '计算列'

        try:
            resolved_expr = _resolve_api_field_refs(str(raw_expr), api_to_display)
            expr = _normalize_expr_with_cols(resolved_expr, df.columns.tolist())
            result = _eval_formula(expr, df)
            df[display] = result
        except Exception as e:
            import traceback
            logger.warning(f"[FormulaEngine] 公式计算失败 '{display}': {e}\n  原始公式: {raw_expr}\n  列名: {df.columns.tolist()[:10]}...\n  {traceback.format_exc()}")
            df[display] = f"[公式错误]"

    return df


def _is_formula(col) -> bool:
    """检查 FieldColumn 是否为公式类型。"""
    if hasattr(col, 'computation_type'):
        return col.computation_type == 'formula'
    return False


# ==================== 汇总行计算 ====================

def compute_summary_row(df: pd.DataFrame, columns: list) -> dict:
    """计算汇总行。

    对每个可见列的数值列计算 SUM，文本列留空。
    如果列定义了 aggregate_func，优先使用对应的聚合函数。
    """
    summary = {}
    for col in columns:
        if hasattr(col, 'visible') and not col.visible:
            continue
        name = col.display_name if hasattr(col, 'display_name') else col
        if name not in df.columns:
            continue

        series = df[name]
        agg_func = getattr(col, 'aggregate_func', '') if hasattr(col, 'aggregate_func') else ''

        if agg_func:
            summary[name] = _apply_agg(series, agg_func)
        elif pd.api.types.is_numeric_dtype(series):
            summary[name] = series.sum()
        else:
            summary[name] = ""

    return summary


def _apply_agg(series, agg_func: str):
    """对 Series 应用聚合函数。"""
    func = agg_func.upper().strip()
    try:
        if func == 'SUM':
            return series.sum()
        elif func == 'AVG':
            return series.mean()
        elif func == 'COUNT':
            return series.count()
        elif func == 'MAX':
            return series.max()
        elif func == 'MIN':
            return series.min()
    except Exception:
        return ""
    return ""


# ==================== 跨页准确汇总（SQL 层）====================

def build_summary_sql(table_name: str, columns: list, db_columns: list[str]) -> str:
    """生成用于汇总查询的 SQL 片段。"""
    agg_parts = []
    for col in columns:
        if hasattr(col, 'visible') and not col.visible:
            continue
        name = col.display_name if hasattr(col, 'display_name') else str(col)
        if name not in db_columns:
            continue
        agg_parts.append(f"SUM(`{name}`) AS `{name}`")

    if not agg_parts:
        return ""
    return f"SELECT {', '.join(agg_parts)} FROM `{table_name}`"


# ==================== Excel 公式 → MySQL SQL 翻译 ====================

# Excel 函数 → MySQL 函数映射（名称不同或参数格式不同才需要映射；同名函数无需列出）
_EXCEL_TO_MYSQL_FUNC: dict[str, str] = {
    'LEN': 'CHAR_LENGTH',
    'MID': 'SUBSTRING',
    'INT': 'FLOOR',
    'CONCATENATE': 'CONCAT',
    'TODAY': 'CURDATE',
    'NOW': 'NOW',
    'ABS': 'ABS',
    'REPT': 'REPEAT',
    'CEILING': 'CEILING',
    'FLOOR': 'FLOOR',
    'LN': 'LN',
    'LOG': 'LOG',
    'EXP': 'EXP',
    'TRUNC': 'TRUNCATE',
}

# 无 MySQL 等价函数的 Excel 函数集合 —— 包含这些函数的公式将退回 pandas 计算
_UNTRANSLATABLE_FUNCS: set[str] = {
    'TEXTJOIN', 'IFS', 'IFERROR',
    'ISNUMBER', 'ISTEXT', 'ISBLANK', 'ISNA',
    'FIND', 'REPLACE', 'SUBSTITUTE',
    'DATEDIF',
    'ROUNDUP', 'ROUNDDOWN',
    'AND', 'OR',
    'WEEKDAY',
    'PROPER', 'SEARCH', 'EXACT',
    'COUNTIF', 'SUMIF', 'AVERAGEIF',
    'EDATE', 'EOMONTH',
    'TIME', 'YEARFRAC', 'ISOWEEKNUM',
    'TRUE', 'FALSE', 'XOR', 'SWITCH',
    'EVEN', 'ODD',
    'FACT', 'PRODUCT', 'QUOTIENT',
    'VALUE', 'FIXED', 'CHAR', 'CODE', 'CLEAN',
    'MEDIAN', 'STDEV', 'STDEVP', 'VAR', 'VARP',
    'LARGE', 'SMALL', 'RANK', 'MODE',
    'LEAD', 'LAG', 'NEXT_IF', 'PREV_IF', 'NEXT_IF_ANY', 'PREV_IF_ANY',
}


def _translate_weeknum(expr: str) -> str:
    """将 Excel WEEKNUM 翻译为 MySQL WEEK。

    WEEKNUM(date)       → WEEK(date, 3)   (默认 return_type=2: 周一开始，含 1/1 的周为第 1 周)
    WEEKNUM(date, 1)    → WEEK(date, 2)   (周日开始)
    WEEKNUM(date, 2)    → WEEK(date, 3)   (周一开始)
    """
    def _replace(m):
        args_str = m.group(1).strip()
        if ',' in args_str:
            # 有第二个参数：找到第一个不在括号内的逗号
            depth = 0
            split_pos = -1
            for i, ch in enumerate(args_str):
                if ch == '(':
                    depth += 1
                elif ch == ')':
                    depth -= 1
                elif ch == ',' and depth == 0:
                    split_pos = i
                    break
            if split_pos > 0:
                date_part = args_str[:split_pos].strip()
                mode_part = args_str[split_pos + 1:].strip()
                if mode_part == '1':
                    return f'WEEK({date_part}, 2)'
                else:
                    return f'WEEK({date_part}, 3)'
        return f'WEEK({args_str}, 3)'

    return re.sub(r'WEEKNUM\s*\(', '__WEEKNUM_START__(', expr, flags=re.IGNORECASE)


# Excel → MySQL 日期格式转换映射
# 按长度降序：长模式优先替换，防止短模式截断长模式的一部分
_EXCEL_TO_MYSQL_DATE_FORMAT = [
    ('yyyy', '%Y'), ('yy', '%y'),
    ('mmmm', '%M'), ('MMMM', '%M'), ('mmm', '%b'), ('MMM', '%b'), ('MM', '%m'), ('mm', '%m'),
    ('dddd', '%W'), ('ddd', '%a'), ('dddd', '%W'), ('ddd', '%a'), ('dd', '%d'),
    ('HH', '%H'), ('hh', '%h'), ('HH', '%H'), ('hh', '%h'),
    ('ss', '%S'),
    ('AM/PM', '%p'), ('A/P', '%p'), ('am/pm', '%p'), ('a/p', '%p'),
]


def _excel_date_format_to_strftime(excel_fmt: str) -> str:
    """将 Excel 日期格式字符串转换为 Python strftime 格式字符串。"""
    mapping = [
        ('yyyy', '%Y'), ('yy', '%y'),
        ('mmmm', '%B'), ('MMMM', '%B'), ('mmm', '%b'), ('MMM', '%b'), ('MM', '%m'), ('mm', '%m'),
        ('dddd', '%A'), ('ddd', '%a'), ('dd', '%d'),
        ('HH', '%H'), ('hh', '%I'),
        ('ss', '%S'),
        ('AM/PM', '%p'), ('A/P', '%p'), ('am/pm', '%p'), ('a/p', '%p'),
    ]
    result = excel_fmt
    for excel_pat, py_pat in sorted(mapping, key=lambda x: -len(x[0])):
        result = result.replace(excel_pat, py_pat)
    return result


def _excel_date_format_to_mysql(excel_fmt: str) -> str:
    """将 Excel 日期格式字符串转换为 MySQL DATE_FORMAT 格式字符串。

    Excel 中 mm 含义取决于上下文：
      - 与 H/h/s 同时出现时 → 分钟 → MySQL %i
      - 否则 → 月份 → MySQL %m
    """
    result = excel_fmt
    # 按长度降序替换，避免短模式（如 'm'）被多次误匹配
    for excel_pat, mysql_pat in sorted(_EXCEL_TO_MYSQL_DATE_FORMAT, key=lambda x: -len(x[0])):
        result = result.replace(excel_pat, mysql_pat)
    # mm 在映射表中已处理为 %m（月份）。如果有时间上下文则覆盖为分钟
    has_time_context = bool(re.search(r'[Hhs]', excel_fmt))
    if has_time_context and 'mm' in excel_fmt:
        # 先恢复 %m（月份），再只对原始格式中出现的 mm 替换为分钟
        result = result.replace('%i', '%m')  # undo any earlier min-based replace
        result = result.replace('%m', '%i', 1)  # only first occurrence → minutes


def _has_date_format_patterns(fmt: str) -> bool:
    """判断格式字符串是否包含日期格式模式（y, M, d, H, h, s 等，含大小写）。"""
    date_indicators = {'y', 'Y', 'M', 'm', 'd', 'D', 'H', 'h', 's', 'S', 'A', 'a', 'P', 'p', '上午', '下午'}
    return any(c in fmt for c in date_indicators)


def _split_func_args(args_str: str, count: int) -> list[str]:
    """按顶层逗号分割函数参数，忽略嵌套括号内的逗号。"""
    parts = []
    depth = 0
    start = 0
    for i, ch in enumerate(args_str):
        if ch == '(':
            depth += 1
        elif ch == ')':
            depth -= 1
        elif ch == ',' and depth == 0:
            parts.append(args_str[start:i].strip())
            start = i + 1
            if len(parts) >= count - 1:
                break
    parts.append(args_str[start:].strip())
    return parts


def _translate_date_to_sql(expr: str) -> str:
    """将 Excel DATE(year, month, day) 翻译为 MySQL STR_TO_DATE 表达式。"""
    def _replace(m):
        args_str = m.group(1).strip()
        parts = _split_func_args(args_str, 3)
        if len(parts) < 3:
            return m.group(0)  # 无法解析，保留原样
        y, m_name, d = parts[0], parts[1], parts[2]
        return (
            f"STR_TO_DATE(CONCAT({y}, '-', LPAD({m_name}, 2, '0'), '-', "
            f"LPAD({d}, 2, '0')), '%Y-%m-%d')"
        )

    # 使用手动字符级匹配来正确处理嵌套括号
    result = []
    i = 0
    n = len(expr)
    while i < n:
        # 查找 DATE(
        if i + 4 < n and expr[i:i+4].upper() == 'DATE':
            j = i + 4
            # 跳过空格
            while j < n and expr[j] == ' ':
                j += 1
            if j < n and expr[j] == '(':
                # 找到匹配的右括号
                depth = 1
                k = j + 1
                while k < n and depth > 0:
                    if expr[k] == '(':
                        depth += 1
                    elif expr[k] == ')':
                        depth -= 1
                    k += 1
                if depth == 0:
                    args_str = expr[j+1:k-1].strip()
                    parts = _split_func_args(args_str, 3)
                    if len(parts) >= 3:
                        y, m_name, d = parts[0], parts[1], parts[2]
                        result.append(
                            f"STR_TO_DATE(CONCAT({y}, '-', LPAD({m_name}, 2, '0'), '-', "
                            f"LPAD({d}, 2, '0')), '%Y-%m-%d')"
                        )
                        i = k
                        continue
            # 未匹配到完整的 DATE(...)，保留原字符
            result.append(expr[i])
            i += 1
        else:
            result.append(expr[i])
            i += 1

    return ''.join(result)


def _translate_text_to_sql(expr: str) -> str:
    """将 Excel TEXT(value, format_string) 翻译为 MySQL DATE_FORMAT 或 CAST。

    对于日期格式 → DATE_FORMAT(value, mysql_format)
    对于数值格式 → CAST(value AS CHAR)
    """
    result = []
    i = 0
    n = len(expr)
    while i < n:
        # 查找 TEXT(
        if i + 4 < n and expr[i:i+4].upper() == 'TEXT':
            j = i + 4
            while j < n and expr[j] == ' ':
                j += 1
            if j < n and expr[j] == '(':
                depth = 1
                k = j + 1
                while k < n and depth > 0:
                    if expr[k] == '(':
                        depth += 1
                    elif expr[k] == ')':
                        depth -= 1
                    k += 1
                if depth == 0:
                    args_str = expr[j+1:k-1].strip()
                    parts = _split_func_args(args_str, 2)
                    if len(parts) >= 2:
                        value_expr = parts[0]
                        fmt_str = parts[1].strip()

                        # 去除外层引号
                        if (fmt_str.startswith('"') and fmt_str.endswith('"')) or \
                           (fmt_str.startswith("'") and fmt_str.endswith("'")):
                            fmt_str = fmt_str[1:-1]

                        if _has_date_format_patterns(fmt_str):
                            mysql_fmt = _excel_date_format_to_mysql(fmt_str)
                            # 用 CASE WHEN 包裹，防止非日期值（如 '1'）触发
                            # MySQL 严格模式的 "Incorrect datetime value" 错误
                            result.append(
                                f"CASE WHEN {value_expr} IS NULL THEN NULL "
                                f"WHEN CHAR_LENGTH({value_expr}) >= 8 "
                                f"THEN DATE_FORMAT({value_expr}, '{mysql_fmt}') "
                                f"ELSE CAST({value_expr} AS CHAR) END"
                            )
                        else:
                            result.append(f"CAST({value_expr} AS CHAR)")
                        i = k
                        continue
            result.append(expr[i])
            i += 1
        else:
            result.append(expr[i])
            i += 1

    return ''.join(result)

def _split_vlookup2_args(inner: str) -> list[str]:
    """按逗号分隔 VLOOKUP2 参数，尊重括号嵌套。"""
    args = []
    depth = 0
    current = []
    for ch in inner:
        if ch == '(':
            depth += 1
            current.append(ch)
        elif ch == ')':
            depth -= 1
            current.append(ch)
        elif ch == ',' and depth == 0:
            args.append(''.join(current))
            current = []
        else:
            current.append(ch)
    args.append(''.join(current))
    return args


def _translate_vlookup2_to_sql(expr: str) -> str:
    """将表达式中的 VLOOKUP2(field_a, field_b, result, mode) 翻译为 MySQL SQL。
    
    当前仅支持 mode='next'，生成：
        CASE WHEN A = LEAD(A) OVER (ORDER BY _row_id)
              AND B = LEAD(B) OVER (ORDER BY _row_id)
             THEN LEAD(C) OVER (ORDER BY _row_id)
             ELSE '' END
    """
    import re
    result_parts = []
    last_end = 0

    for m in re.finditer(r'VLOOKUP2\s*\(', expr, re.IGNORECASE):
        start = m.start()
        depth = 1
        i = m.end()
        while i < len(expr) and depth > 0:
            if expr[i] == '(':
                depth += 1
            elif expr[i] == ')':
                depth -= 1
            i += 1
        if depth != 0:
            continue

        inner = expr[m.end():i - 1]
        args = _split_vlookup2_args(inner)
        if len(args) < 3:
            continue

        field_a = args[0].strip()
        field_b = args[1].strip()
        result_field = args[2].strip()
        mode_arg = args[3].strip() if len(args) > 3 else ''

        mode_clean = mode_arg.strip('"\' ').lower()
        if mode_clean.startswith('\x00l') or mode_clean.startswith('\x00L'):
            mode_clean = 'next'

        if mode_clean == 'next':
            replacement = (
                f"CASE WHEN {field_a} <=> LEAD({field_a}) OVER (ORDER BY _row_id) "
                f"AND {field_b} <=> LEAD({field_b}) OVER (ORDER BY _row_id) "
                f"THEN LEAD({result_field}) OVER (ORDER BY _row_id) "
                f"ELSE '' END"
            )
        else:
            continue

        result_parts.append(expr[last_end:start])
        result_parts.append(replacement)
        last_end = i

    if not result_parts:
        return expr

    result_parts.append(expr[last_end:])
    return ''.join(result_parts)



def translate_formula_to_sql(expr: str, column_names: list[str],
                             table_alias: str = '_base') -> str | None:
    """将 Excel 公式表达式翻译为 MySQL SQL 表达式。

    列引用替换为 `{alias}`.`列名` 形式，Excel 函数映射为 MySQL 等价函数。
    若公式包含 MySQL 不支持的函数，返回 None（由调用方退回 pandas 计算）。

    Args:
        expr: 原始公式表达式（如 '=单价*数量' 或 '=IF(金额>1000, "大额", "小额")'）
        column_names: 内层查询的列名列表（用于匹配并替换列引用）
        table_alias: 子查询别名（默认 '_base'）

    Returns:
        MySQL SQL 表达式字符串，或 None（表示无法翻译）
    """
    expr = _normalize_expr_with_cols(expr, column_names)
    if not expr.strip():
        return 'NULL'

    # 检查公式是否被截断（包含省略号等异常 Unicode 字符）
    _TRUNCATION_INDICATORS = {'…', '‥', '．'}  # …, ‥, ．
    for ch in _TRUNCATION_INDICATORS:
        if ch in expr:
            logger.warning(f"[FormulaSQL] 公式包含截断标记 U+{ord(ch):04X}，退回 pandas 计算")
            return None

    # 检查括号是否成对（防止截断或损毁的公式生成无效 SQL）
    if expr.count('(') != expr.count(')'):
        logger.warning(f"[FormulaSQL] 公式括号不匹配 (左={expr.count('(')} 右={expr.count(')')})，退回 pandas 计算")
        return None

    # 检查是否包含不可翻译的 Excel 函数
    for func in _UNTRANSLATABLE_FUNCS:
        if re.search(r'\b' + func + r'\s*\(', expr, re.IGNORECASE):
            logger.info(f"[FormulaSQL] 公式包含不支持的函数 '{func}'，退回 pandas 计算")
            return None

    # 先处理字符串字面量：保护起来避免列名误匹配
    literals = {}

    def _save_literal(m):
        key = f'\x00L{len(literals)}\x00'
        literals[key] = m.group(0)
        return key

    expr = re.sub(r"'[^']*'", _save_literal, expr)
    expr = re.sub(r'"[^"]*"', _save_literal, expr)

    # 列引用中的方括号：Excel 结构化引用 [列名] → 列名
    expr = re.sub(r'(?<!_)\.?(?<!\\[)`?\[([^\]]+)\]`?', r'`\1`', expr)

    # 特殊处理 WEEKNUM → MySQL WEEK
    expr = _translate_weeknum(expr)
    # 还原 WEEKNUM 占位符（_translate_weeknum 替换了函数名开头，这里补全参数处理）
    # 简化处理：直接匹配完整的 WEEKNUM(...) 调用
    if '__WEEKNUM_START__' in expr:
        expr = _finish_weeknum_translation(expr)
    # 特殊处理 VLOOKUP2 → MySQL CASE WHEN + LEAD 窗口函数
    expr = _translate_vlookup2_to_sql(expr)


    # 按列名长度降序替换列引用（避免短列名错误匹配长列名的一部分）
    sorted_cols = sorted([str(c) for c in column_names], key=len, reverse=True)
    for col in sorted_cols:
        if col in expr:
            quoted = f"`{col.replace('`', '``')}`"
            expr = expr.replace(col, f"{table_alias}.{quoted}")

    # 恢复字面量
    for key, val in literals.items():
        expr = expr.replace(key, val)

    # 特殊处理 DATE → MySQL STR_TO_DATE
    expr = _translate_date_to_sql(expr)
    # 特殊处理 TEXT → MySQL DATE_FORMAT / CAST
    expr = _translate_text_to_sql(expr)

    # 翻译 Excel 函数 → MySQL 函数
    expr = _translate_functions(expr)

    # 翻译后再次检查括号是否成对（防止翻译过程引入问题）
    if expr.count('(') != expr.count(')'):
        logger.warning(f"[FormulaSQL] 翻译后括号不匹配 (左={expr.count('(')} 右={expr.count(')')})，退回 pandas 计算")
        return None

    return expr


def _finish_weeknum_translation(expr: str) -> str:
    """完成 WEEKNUM → WEEK 的翻译（处理括号内的参数）。"""
    def _replace_full(m):
        args_str = m.group(1).strip()
        if ',' in args_str:
            depth = 0
            split_pos = -1
            for i, ch in enumerate(args_str):
                if ch == '(':
                    depth += 1
                elif ch == ')':
                    depth -= 1
                elif ch == ',' and depth == 0:
                    split_pos = i
                    break
            if split_pos > 0:
                date_part = args_str[:split_pos].strip()
                mode_part = args_str[split_pos + 1:].strip()
                if mode_part == '1':
                    return f'WEEK({date_part}, 2)'
                else:
                    return f'WEEK({date_part}, 3)'
        return f'WEEK({args_str}, 3)'

    return re.sub(r'__WEEKNUM_START__\s*\(([^()]*(?:\([^()]*\)[^()]*)*)\)',
                  _replace_full, expr)


def _translate_functions(expr: str) -> str:
    """将表达式中的 Excel 函数名替换为 MySQL 等价函数名。"""
    for excel_func, mysql_func in _EXCEL_TO_MYSQL_FUNC.items():
        pattern = r'\b' + excel_func + r'\s*\('
        if re.search(pattern, expr, re.IGNORECASE):

            def _replace(m, mf=mysql_func):
                return mf + m.group(0)[len(excel_func):]

            expr = re.sub(pattern, _replace, expr, flags=re.IGNORECASE)
    return expr


