# -*- coding: utf-8 -*-
"""报表列表页"""

import sys
from PyQt6.QtCore import Qt, pyqtSignal
from PyQt6.QtWidgets import (
    QWidget, QVBoxLayout, QHBoxLayout, QLineEdit, QPushButton,
    QTableWidget, QTableWidgetItem, QHeaderView, QLabel,
    QComboBox, QAbstractItemView, QMenu, QMessageBox,
)
from PyQt6.QtGui import QFont, QColor, QAction



class JoinType(Enum):
    """两张表之间的 JOIN 方式"""
    LEFT_JOIN = "left"           # 保留左表所有行，匹配不到填 NULL
    INNER_JOIN = "inner"         # 只保留两表都匹配成功的行
    ONE_TO_ONE = "one_to_one"    # 一对一：匹配到多行时只取第一条（不膨胀）

    @classmethod
    def from_str(cls, s: str):
        for m in cls:
            if m.value == s:
                return m
        return cls.LEFT_JOIN


class MultiMatchStrategy(Enum):
    """当关联表匹配到多行时的处理策略"""
    EXPAND = "expand"      # 展开为多行（默认，类似 SQL JOIN）
    FIRST = "first"        # 只取第一条匹配
    CONCAT = "concat"      # 拼接为字符串（用分隔符连接）
    COUNT = "count"        # 计数
    SUM = "sum"            # 求和（仅数字字段）
    AVG = "avg"            # 平均值（仅数字字段）

    @classmethod
    def from_str(cls, s: str):
        for m in cls:
            if m.value == s:
                return m
        return cls.EXPAND


class FilterOperator(Enum):
    # 文本操作符
    EQ = "EQ"
    NEQ = "NEQ"
    CONTAINS = "CONTAINS"
    NOT_CONTAINS = "NOT_CONTAINS"
    IN = "IN"
    NOT_IN = "NOT_IN"
    GT = "GT"
    LT = "LT"
    GTE = "GTE"
    LTE = "LTE"
    EMPTY = "EMPTY"
    NOT_EMPTY = "NOT_EMPTY"
    STARTS_WITH = "STARTS_WITH"
    ENDS_WITH = "ENDS_WITH"
    # 日期操作符
    DATE_BEFORE = "DATE_BEFORE"
    DATE_AFTER = "DATE_AFTER"
    DATE_BEFORE_EQ = "DATE_BEFORE_EQ"
    DATE_AFTER_EQ = "DATE_AFTER_EQ"
    DATE_RANGE = "DATE_RANGE"
    PAST_N_DAYS_EXCLUSIVE = "PAST_N_DAYS_EXCLUSIVE"
    PAST_N_DAYS_INCLUSIVE = "PAST_N_DAYS_INCLUSIVE"
    FUTURE_N_DAYS_EXCLUSIVE = "FUTURE_N_DAYS_EXCLUSIVE"
    FUTURE_N_DAYS_INCLUSIVE = "FUTURE_N_DAYS_INCLUSIVE"
    PAST_N_WEEKS_EXCLUSIVE = "PAST_N_WEEKS_EXCLUSIVE"
    PAST_N_WEEKS_INCLUSIVE = "PAST_N_WEEKS_INCLUSIVE"
    FUTURE_N_WEEKS_EXCLUSIVE = "FUTURE_N_WEEKS_EXCLUSIVE"
    FUTURE_N_WEEKS_INCLUSIVE = "FUTURE_N_WEEKS_INCLUSIVE"
    PAST_N_MONTHS_EXCLUSIVE = "PAST_N_MONTHS_EXCLUSIVE"
    PAST_N_MONTHS_INCLUSIVE = "PAST_N_MONTHS_INCLUSIVE"
    FUTURE_N_MONTHS_EXCLUSIVE = "FUTURE_N_MONTHS_EXCLUSIVE"
    FUTURE_N_MONTHS_INCLUSIVE = "FUTURE_N_MONTHS_INCLUSIVE"
    PAST_N_QUARTERS_INCLUSIVE = "PAST_N_QUARTERS_INCLUSIVE"
    N_DAYS_AGO = "N_DAYS_AGO"
    N_DAYS_LATER = "N_DAYS_LATER"
    N_WEEKS_AGO = "N_WEEKS_AGO"
    N_WEEKS_LATER = "N_WEEKS_LATER"

    @classmethod
    def from_str(cls, s: str):
        for m in cls:
            if m.value == s:
                return m
        return cls.EQ


# ==================== 核心数据模型 ====================

@dataclass
class MatchKey:
    """单个匹配键：两表之间一对字段的关联"""
    left_field: str          # 左表字段 API 名（如 sales_order_id）
    right_field: str         # 右表字段 API 名（如 order_id）


@dataclass
class JoinDefinition:
    """两张表之间的拼表关系"""
    id: str = field(default_factory=lambda: uuid.uuid4().hex[:8])
    left_object_api: str = ""          # 左表对象 API 名
    right_object_api: str = ""         # 右表对象 API 名
    match_keys: list = field(default_factory=list)    # list[MatchKey]
    join_type: str = "left"            # left / inner / one_to_one
    multi_match: str = "expand"        # expand / first / concat / count / sum / avg
    concat_separator: str = "、"

    def __post_init__(self):
        # 反序列化时 match_keys 可能是 dict 列表，转为 MatchKey 对象
        if self.match_keys and isinstance(self.match_keys[0], dict):
            self.match_keys = [MatchKey(**m) if isinstance(m, dict) else m for m in self.match_keys]


@dataclass
class FieldColumn:
    """报表中的一个显示列"""
    id: str = field(default_factory=lambda: uuid.uuid4().hex[:8])
    display_name: str = ""             # 列显示名（中文表头）
    source_object_api: str = ""        # 字段来源对象 API 名
    source_field: str = ""             # 字段 API 名
    visible: bool = True               # 是否在预览/结果表中显示
    sort_order: int = 0                # 列顺序
    column_width: Optional[int] = None
    # 计算字段（Excel 风格）
    computation_type: str = "direct"   # "direct" | "aggregate" | "formula" | "address_extract" | "date_part"
    aggregate_func: str = ""           # "SUM" | "AVG" | "COUNT" | "MAX" | "MIN"
    formula_expression: str = ""       # 如 "=单价*数量", "=IF(金额>1000, '大额', '小额')"
    # 字段格式（MySQL 存储类型），默认文本
    field_format: str = "text"         # "text" | "integer" | "float" | "currency" | "date_ymd" | "date_ymd_cn" | "datetime" | "time"
    # 地址提取字段
    address_source_fields: list = field(default_factory=list)
    # 候选列显示名列表，最多 5 个，按优先级排列
    address_target_level: str = ""     # "province" | "province_short" | "city_full" | "city_short"
    # 日期成分提取字段
    date_part_source_field: str = ""   # 源日期字段 API 名（如 create_time）
    date_part_unit: str = ""           # "year" | "month" | "week" | "quarter"


@dataclass
class FilterCondition:
    """行级筛选条件"""
    field_api: str = ""                # 筛选字段 API 名
    operator: str = "EQ"              # 操作符（支持文字和日期操作符）
    value: str = ""
    target_object_api: str = ""       # 筛选字段所属对象（默认主表）
    field_label: str = ""             # 字段中文显示名
    expose: bool = False              # "外露"标记
    is_date_field: bool = False       # 是否为日期字段


@dataclass
class ReportDefinition:
    """一份报表的完整定义"""
    id: str = field(default_factory=lambda: uuid.uuid4().hex[:12])
    name: str = "未命名报表"
    description: str = ""

    # 拼表定义
    main_object_api: str = ""
    joins: list = field(default_factory=list)          # list[JoinDefinition]

    # 显示列
    columns: list = field(default_factory=list)         # list[FieldColumn]

    # 筛选
    filters: list = field(default_factory=list)         # list[FilterCondition]
    date_range_enabled: bool = False
    date_field: str = "create_time"
    date_start: str = ""
    date_end: str = ""

    # 画布布局（记录每张卡片的位置，用于还原）
    canvas_positions: dict = field(default_factory=dict)
    # {"NewOpportunityObj": (100.0, 200.0), "DeliveryNoteObj": (450.0, 200.0)}

    # 分组与汇总（Excel 风格聚合）
    group_by_fields: list = field(default_factory=list)   # ["field_api_1", ...]
    show_summary_row: bool = False                         # 预览表底部显示汇总行

    # 文件夹（报表分类管理）
    folder_path: str = ""              # 文件夹路径，如 ""（根目录）、"销售报表"、"销售/月度"

    # 元信息
    created_at: str = ""
    modified_at: str = ""
    version: int = 1

    # 结果表信息
    result_table_name: str = ""        # cr_{id}
    result_row_count: int = 0
    last_refresh_time: str = ""

    # 写入方式
    write_mode: str = "overwrite"      # "overwrite" (覆盖) | "incremental" (增量)

    # 同步主键配置（多字段拼接）
    sync_id_fields: list = field(default_factory=list)   # 列显示名列表，如 ["销售订单号", "发货单号"]
    sync_id_separator: str = "_"                          # 拼接分隔符

    # 排序配置
    sort_config: list = field(default_factory=list)        # [{"field": "列显示名", "direction": "asc"|"desc"}, ...]

    # AI 助手对话管理
    ai_conversations: list = field(default_factory=list)  # [{id, title, created_at, messages, context_texts}]
    ai_active_conversation_id: str = ""                    # 当前活跃对话 ID

    # 旧版兼容字段（不再写入，仅用于迁移）
    ai_chat_messages: list = field(default_factory=list)

    def __post_init__(self):
        # 反序列化时修复嵌套对象类型
        if self.joins and isinstance(self.joins[0], dict):
            self.joins = [JoinDefinition(**j) if isinstance(j, dict) else j for j in self.joins]
        if self.columns and isinstance(self.columns[0], dict):
            fixed = []
            for c in self.columns:
                if isinstance(c, dict):
                    # 兼容旧数据：source_object → source_object_api
                    if 'source_object' in c and 'source_object_api' not in c:
                        c = dict(c)
                        c['source_object_api'] = c.pop('source_object')
                    fixed.append(FieldColumn(**c))
                else:
                    fixed.append(c)
            self.columns = fixed
        if self.filters and isinstance(self.filters[0], dict):
            self.filters = [FilterCondition(**f) if isinstance(f, dict) else f for f in self.filters]

        # 兼容旧数据：ai_chat_messages → ai_conversations
        if self.ai_chat_messages and not self.ai_conversations:
            import uuid as _uuid
            conv_id = _uuid.uuid4().hex[:8]
            self.ai_conversations = [{
                'id': conv_id,
                'title': '对话 1',
                'created_at': self.modified_at or '',
                'messages': list(self.ai_chat_messages),
                'context_texts': [],
            }]
            self.ai_active_conversation_id = conv_id
            self.ai_chat_messages = []  # 清空旧字段

    def to_dict(self) -> dict:
        """序列化为可 JSON 存储的 dict"""
        return _serialize(self)

    @classmethod
    def from_dict(cls, data: dict) -> "ReportDefinition":
        """从 dict 反序列化"""
        return cls(**_deserialize_report(data))

    @property
    def source_table_name(self) -> str:
        """主表对应的 MySQL source 表名"""
        return f"sr_{self.main_object_api}"

    @property
    def result_table(self) -> str:
        """结果表名"""
        return self.result_table_name or f"cr_{self.id}"

    def get_object_apis(self) -> list[str]:
        """获取报表涉及的所有对象 API 名"""
        apis = [self.main_object_api] if self.main_object_api else []
        for j in self.joins:
            jd = j if isinstance(j, JoinDefinition) else JoinDefinition(**j)
            for api in (jd.left_object_api, jd.right_object_api):
                if api and api not in apis:
                    apis.append(api)
        return apis


# ==================== 序列化辅助 ====================

def _serialize(obj):
    """递归转换 dataclass/dict/list 为纯 dict"""
    if isinstance(obj, list):
        return [_serialize(item) for item in obj]
    if isinstance(obj, dict):
        return {k: _serialize(v) for k, v in obj.items()}
    if hasattr(obj, '__dataclass_fields__'):
        result = {}
        for k, v in asdict(obj).items():
            vv = getattr(obj, k, None)
            if isinstance(vv, list):
                result[k] = [_serialize(item) for item in vv]
            elif isinstance(vv, dict):
                result[k] = {kk: _serialize(vv) for kk, vv in vv.items()}
            elif hasattr(vv, '__dataclass_fields__'):
                result[k] = _serialize(vv)
            else:
                result[k] = v
        return result
    return obj


def _deserialize_report(data: dict) -> dict:
    """将 dict 转为 ReportDefinition 构造函数参数"""
    result = {}
    for k, v in data.items():
        if k == 'joins':
            result[k] = [JoinDefinition(**j) if isinstance(j, dict) else j for j in (v or [])]
        elif k == 'columns':
            fixed_cols = []
            for c in (v or []):
                if isinstance(c, dict):
                    # 兼容旧数据：source_object → source_object_api
                    if 'source_object' in c and 'source_object_api' not in c:
                        c = dict(c)
                        c['source_object_api'] = c.pop('source_object')
                    fixed_cols.append(FieldColumn(**c))
                else:
                    fixed_cols.append(c)
            result[k] = fixed_cols
        elif k == 'filters':
            result[k] = [FilterCondition(**f) if isinstance(f, dict) else f for f in (v or [])]
        else:
            result[k] = v
    return result


# -- custom_report/persistence.py --
# -*- coding: utf-8 -*-
"""报表持久化层 —— MySQL 优先，JSON 配置文件回退"""

import json
import logging
from abc import ABC, abstractmethod
from datetime import datetime


logger = logging.getLogger(__name__)


class ReportStoreError(Exception):
    """报表存储异常"""
    pass


class AbstractReportStore(ABC):
    """报表存储抽象基类"""

    @abstractmethod
    def save_preset(self, name, config):
        """保存报表预设。config 为 ReportConfig 或 dict。"""

    @abstractmethod
    def load_preset(self, name):
        """加载报表预设。返回 ReportConfig 或 None。"""

    @abstractmethod
    def list_presets(self, filter_text=None):
        """列出所有预设。返回 list[ReportPreset]。"""

    @abstractmethod
    def delete_preset(self, name):
        """删除报表预设。"""

    @abstractmethod
    def save_last_state(self, config):
        """保存最近一次编辑状态。"""

    @abstractmethod
    def load_last_state(self):
        """加载最近一次编辑状态。返回 ReportConfig 或 None。"""

    @abstractmethod
    def is_available(self):
        """存储是否可用。"""


class JsonConfigReportStore(AbstractReportStore):
    """JSON 配置文件存储（兼容旧版行为）。

    数据存储在 config['custom_reports']['presets'] 和
    config['custom_reports']['last_state'] 中。
    """

    def __init__(self, get_config_fn, save_config_fn):
        """Args:
            get_config_fn: callable，返回完整配置 dict
            save_config_fn: callable(config_dict)，保存配置
        """
        self._get_config = get_config_fn
        self._save_config = save_config_fn

    def is_available(self):
        return True

    def _get_custom_reports(self):
        config = self._get_config()
        if 'custom_reports' not in config:
            config['custom_reports'] = {}
        return config['custom_reports']

    def save_preset(self, name, config):
        cr = self._get_custom_reports()
        if 'presets' not in cr:
            cr['presets'] = {}

        state_dict = config.to_dict() if isinstance(config, ReportConfig) else config
        cr['presets'][name] = {
            'name': name,
            'type': state_dict.get('report_type', 'report'),
            'main_source': state_dict.get('main_source', ''),
            'state': state_dict,
            'modifier': '',
            'modified': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            'status': 'enabled',
        }
        self._save_config(self._get_config())

    def load_preset(self, name):
        cr = self._get_custom_reports()
        presets = cr.get('presets', {})
        entry = presets.get(name)
        if not entry:
            return None
        state = entry.get('state', {})
        return ReportConfig.from_dict(state) if state else None

    def list_presets(self, filter_text=None):
        cr = self._get_custom_reports()
        presets = cr.get('presets', {})
        result = []
        for key, entry in presets.items():
            if not isinstance(entry, dict):
                continue
            name = entry.get('name', key)
            if filter_text and filter_text.lower() not in name.lower():
                continue
            result.append(ReportPreset(
                key=key,
                name=name,
                preset_type=entry.get('type', 'report'),
                main_source=entry.get('main_source', ''),
                modifier=entry.get('modifier', ''),
                modified=entry.get('modified', ''),
                status=entry.get('status', 'enabled'),
            ))
        # 按修改时间倒序
        result.sort(key=lambda p: p.modified, reverse=True)
        return result

    def delete_preset(self, name):
        cr = self._get_custom_reports()
        presets = cr.get('presets', {})
        if name in presets:
            del presets[name]
            self._save_config(self._get_config())

    def save_last_state(self, config):
        cr = self._get_custom_reports()
        state_dict = config.to_dict() if isinstance(config, ReportConfig) else config
        cr['last_state'] = state_dict
        self._save_config(self._get_config())

    def load_last_state(self):
        cr = self._get_custom_reports()
        state = cr.get('last_state')
        return ReportConfig.from_dict(state) if state else None


class MysqlReportStore(AbstractReportStore):
    """MySQL 报表存储"""

    def __init__(self, mysql_config):
        self._cfg = mysql_config
        self._conn = None
        self._available = False

    def is_available(self):
        return self._available

    def ensure_schema(self):
        """创建报表表结构（如果不存在）。"""
        try:
            conn = self._get_connection()
            if not conn:
                return False
            with conn.cursor() as cur:
                cur.execute("""
                    CREATE TABLE IF NOT EXISTS custom_reports (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        name VARCHAR(255) NOT NULL,
                        type VARCHAR(32) DEFAULT 'report',
                        config_json LONGTEXT,
                        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                        modified_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                        status VARCHAR(32) DEFAULT 'enabled',
                        INDEX idx_type (type),
                        INDEX idx_name (name)
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
                """)
            conn.commit()
            self._available = True
            return True
        except Exception as e:
            logger.warning(f"[MysqlReportStore] 建表失败: {e}")
            self._available = False
            return False

    def _get_connection(self):
        if self._conn is not None:
            try:
                self._conn.ping(reconnect=True)
                return self._conn
            except Exception:
                self._conn = None

        try:
            import pymysql
            self._conn = pymysql.connect(
                host=self._cfg.get('host', 'localhost'),
                port=int(self._cfg.get('port', 3306)),
                user=self._cfg.get('user', 'root'),
                password=self._cfg.get('password', ''),
                database=self._cfg.get('database', ''),
                charset='utf8mb4',
                autocommit=False,
            )
            return self._conn
        except ImportError:
            logger.warning("[MysqlReportStore] pymysql 未安装")
            return None
        except Exception as e:
            logger.warning(f"[MysqlReportStore] 连接失败: {e}")
            return None

    def save_preset(self, name, config):
        conn = self._get_connection()
        if not conn:
            raise ReportStoreError("MySQL 不可用")
        state_dict = config.to_dict() if isinstance(config, ReportConfig) else config
        config_json = json.dumps(state_dict, ensure_ascii=False)
        try:
            with conn.cursor() as cur:
                cur.execute(
                    """INSERT INTO custom_reports (name, type, config_json, modified_at)
                       VALUES (%s, %s, %s, NOW())
                       ON DUPLICATE KEY UPDATE config_json=%s, modified_at=NOW()""",
                    (name, state_dict.get('report_type', 'report'), config_json, config_json)
                )
            conn.commit()
        except Exception as e:
            conn.rollback()
            raise ReportStoreError(f"保存预设失败: {e}")

    def load_preset(self, name):
        conn = self._get_connection()
        if not conn:
            return None
        try:
            with conn.cursor() as cur:
                cur.execute(
                    "SELECT config_json FROM custom_reports WHERE name=%s",
                    (name,)
                )
                row = cur.fetchone()
            if row:
                state = json.loads(row[0])
                return ReportConfig.from_dict(state)
            return None
        except Exception as e:
            logger.warning(f"[MysqlReportStore] 加载预设失败: {e}")
            return None

    def list_presets(self, filter_text=None):
        conn = self._get_connection()
        if not conn:
            return []
        try:
            with conn.cursor() as cur:
                if filter_text:
                    cur.execute(
                        """SELECT name, type, config_json, modified_at, status
                           FROM custom_reports WHERE name LIKE %s
                           ORDER BY modified_at DESC""",
                        (f'%{filter_text}%',)
                    )
                else:
                    cur.execute(
                        """SELECT name, type, config_json, modified_at, status
                           FROM custom_reports ORDER BY modified_at DESC"""
                    )
                rows = cur.fetchall()
            result = []
            for row in rows:
                name, rtype, config_json, modified, status = row
                state = json.loads(config_json) if config_json else {}
                result.append(ReportPreset(
                    key=name,
                    name=name,
                    preset_type=rtype or 'report',
                    main_source=state.get('main_source', ''),
                    modifier='',
                    modified=str(modified) if modified else '',
                    status=status or 'enabled',
                ))
            return result
        except Exception as e:
            logger.warning(f"[MysqlReportStore] 列出预设失败: {e}")
            return []

    def delete_preset(self, name):
        conn = self._get_connection()
        if not conn:
            return
        try:
            with conn.cursor() as cur:
                cur.execute("DELETE FROM custom_reports WHERE name=%s", (name,))
            conn.commit()
        except Exception as e:
            conn.rollback()
            logger.warning(f"[MysqlReportStore] 删除预设失败: {e}")

    def save_last_state(self, config):
        try:
            config_dict = config.to_dict() if isinstance(config, ReportConfig) else config
            self.save_preset('__last_state__', config_dict)
        except Exception:
            pass

    def load_last_state(self):
        return self.load_preset('__last_state__')

    def close(self):
        if self._conn:
            try:
                self._conn.close()
            except Exception:
                pass
            self._conn = None


def build_store(mysql_config, get_config_fn=None, save_config_fn=None):
    """构建报表存储实例。

    Args:
        mysql_config: MySQL 配置 dict
        get_config_fn: JSON 模式的配置读取回调
        save_config_fn: JSON 模式的配置保存回调

    Returns:
        AbstractReportStore
    """
    if mysql_config.get('enabled'):
        store = MysqlReportStore(mysql_config)
        if store.ensure_schema():
            logger.info("[ReportStore] 使用 MySQL 存储")
            # 尝试从 JSON 迁移数据
            if get_config_fn:
                try:
                    _migrate_json_to_mysql(store, get_config_fn)
                except Exception:
                    pass
            return store
        logger.info("[ReportStore] MySQL 不可用，回退到 JSON")

    # JSON 回退
    if get_config_fn and save_config_fn:
        logger.info("[ReportStore] 使用 JSON 配置文件存储")
        return JsonConfigReportStore(get_config_fn, save_config_fn)

    raise ReportStoreError("无法初始化任何报表存储")


def _migrate_json_to_mysql(mysql_store, get_config_fn):
    """将 JSON 配置中的预设迁移到 MySQL。"""
    config = get_config_fn()
    presets = config.get('custom_reports', {}).get('presets', {})
    if not presets:
        return
    existing = mysql_store.list_presets()
    existing_names = {p.name for p in existing}
    migrated = 0
    for name, entry in presets.items():
        if not isinstance(entry, dict):
            continue
        if name in existing_names:
            continue
        state = entry.get('state', {})
        if state:
            mysql_store.save_preset(name, ReportConfig.from_dict(state))
            migrated += 1
    if migrated:
        logger.info(f"[ReportStore] 从 JSON 迁移了 {migrated} 个预设到 MySQL")


# -- custom_report/repository.py --
"""
报表持久化层

支持两种存储后端:
1. JSON 文件 (默认) — 兼容旧版 config.json
2. MySQL 元数据表 — 可选，多用户共享

v1→v2 迁移: 将 config.json → custom_reports → presets 转为 ReportDefinition 格式
"""

import json
import os
import logging
from datetime import datetime
from typing import Optional
from copy import deepcopy


logger = logging.getLogger(__name__)


# 配置文件路径
def _get_storage_path() -> str:
    """获取报表配置存储文件路径"""
    config_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                              '.config')
    os.makedirs(config_dir, exist_ok=True)
    return os.path.join(config_dir, 'custom_reports_v2.json')


class ReportRepository:
    """报表配置 CRUD"""

    def __init__(self, storage_path: str = None):
        self._path = storage_path or _get_storage_path()
        self._cache: dict[str, ReportDefinition] = {}
        self._empty_folders: set = set()  # 空文件夹集合
        self._load()

    def _load(self):
        """从文件加载所有报表"""
        if not os.path.exists(self._path):
            self._cache = {}
            self._empty_folders = set()
            return
        try:
            with open(self._path, 'r', encoding='utf-8') as f:
                data = json.load(f)
            reports_data = data.get('reports', {}) if isinstance(data, dict) else {}
            for rid, rdata in reports_data.items():
                try:
                    self._cache[rid] = ReportDefinition.from_dict(rdata)
                except Exception as e:
                    logger.warning(f"加载报表 {rid} 失败: {e}")
            # 加载空文件夹列表
            folders_data = data.get('empty_folders', [])
            self._empty_folders = set(folders_data) if isinstance(folders_data, list) else set()
        except Exception as e:
            logger.error(f"加载报表配置失败: {e}")
            self._cache = {}
            self._empty_folders = set()

    def _save(self):
        """保存所有报表到文件（原子写入：先写临时文件，再重命名）"""
        import os
        data = {
            'version': 2,
            'reports': {rid: rpt.to_dict() for rid, rpt in self._cache.items()},
            'empty_folders': sorted(list(self._empty_folders)),
        }
        tmp_path = self._path + '.tmp'
        try:
            with open(tmp_path, 'w', encoding='utf-8') as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            os.replace(tmp_path, self._path)  # 原子操作（同文件系统内）
        except Exception:
            # 清理临时文件
            if os.path.exists(tmp_path):
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass
            raise

    # ---------- CRUD ----------

    def get(self, report_id: str) -> Optional[ReportDefinition]:
        return self._cache.get(report_id)

    def get_by_name(self, name: str) -> Optional[ReportDefinition]:
        for rpt in self._cache.values():
            if rpt.name == name:
                return rpt
        return None

    def list_all(self, search: str = None) -> list[ReportDefinition]:
        """列出所有报表（支持按名称搜索），按修改时间倒序"""
        reports = list(self._cache.values())
        if search:
            kw = search.lower()
            reports = [r for r in reports if kw in r.name.lower()]
        reports.sort(key=lambda r: r.modified_at or r.created_at or '', reverse=True)
        return reports

    def save(self, report: ReportDefinition):
        """保存报表（新增或更新）"""
        now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        if not report.created_at:
            report.created_at = now
        report.modified_at = now
        report.version += 1
        self._cache[report.id] = report
        self._save()

    def update_refresh_meta(self, report_id: str, row_count: int, refresh_time: str):
        """仅更新刷新元数据（不改动 modified_at 和 version）"""
        rpt = self._cache.get(report_id)
        if not rpt:
            return
        rpt.result_row_count = row_count
        rpt.last_refresh_time = refresh_time
        rpt.result_table_name = ReportDatabase.result_table_name(report_id)
        self._save()

    def save_filters(self, report_id: str, filters: list):
        """仅更新筛选条件（不递增版本号，避免无意义的版本变化）"""
        rpt = self._cache.get(report_id)
        if not rpt:
            return
        rpt.filters = list(filters)
        rpt.modified_at = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        self._save()

    def delete(self, report_id: str) -> bool:
        if report_id in self._cache:
            del self._cache[report_id]
            self._save()
            return True
        return False

    def duplicate(self, report_id: str, new_name: str) -> Optional[ReportDefinition]:
        """复制报表"""
        original = self._cache.get(report_id)
        if not original:
            return None
        new_report = ReportDefinition.from_dict(deepcopy(original.to_dict()))
        new_report.id = ''  # 由 __post_init__ 重新生成
        # 让 dataclass 重新生成 id
        from uuid import uuid4
        new_report.id = uuid4().hex[:12]
        new_report.name = new_name
        new_report.created_at = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        new_report.modified_at = new_report.created_at
        new_report.result_table_name = f"cr_{new_report.id}"
        new_report.result_row_count = 0
        new_report.last_refresh_time = ''
        self._cache[new_report.id] = new_report
        self._save()
        return new_report

    def count(self) -> int:
        return len(self._cache)

    # ---------- 文件夹管理 ----------

    def list_folders(self) -> list[dict]:
        """扫描所有报表的 folder_path，构建文件夹树结构。
        Returns:
            [{name, path, count, children: [...]}, ...]
            根节点: {name: "全部报表", path: "__root__", count, children}
        """
        # 统计每个文件夹路径下的报表数量
        folder_counts: dict[str, int] = {}
        for rpt in self._cache.values():
            fp = (rpt.folder_path or "").strip()
            if fp:
                # 统计所有层级
                parts = fp.replace("\\", "/").split("/")
                for i in range(len(parts)):
                    sub = "/".join(parts[:i + 1])
                    folder_counts[sub] = folder_counts.get(sub, 0) + 1
            else:
                folder_counts["__root__"] = folder_counts.get("__root__", 0) + 1

        # 补充空文件夹（count=0 但有子文件夹的也会显示）
        for ef in self._empty_folders:
            fp = ef.strip()
            if fp and fp not in folder_counts:
                folder_counts[fp] = 0
                # 确保所有父级路径也存在
                parts = fp.replace("\\", "/").split("/")
                for i in range(len(parts) - 1):
                    parent = "/".join(parts[:i + 1])
                    if parent not in folder_counts:
                        folder_counts[parent] = folder_counts.get(parent, 0)

        # 构建嵌套树
        def _build_tree(parent_path: str, entries: dict[str, int]) -> list[dict]:
            children = []
            # 找出直接子节点
            direct_children = set()
            for path in entries:
                if path == parent_path:
                    continue
                parent = "/".join(path.split("/")[:-1]) if "/" in path else "__root__"
                if parent == parent_path:
                    direct_children.add(path)

            for path in sorted(direct_children):
                name = path.split("/")[-1]
                sub_children = _build_tree(path, entries)
                children.append({
                    "name": name,
                    "path": path,
                    "count": entries.get(path, 0),
                    "children": sub_children,
                })
            return children

        root_count = folder_counts.get("__root__", 0)
        total_count = len(self._cache)
        tree = _build_tree("__root__", folder_counts)

        return [{
            "name": "全部报表",
            "path": "__root__",
            "count": total_count,
            "children": tree,
        }]

    def list_by_folder(self, folder_path: str, search: str = None) -> list:
        """按文件夹过滤报表（支持搜索）。
        Args:
            folder_path: "__root__" 表示根目录，空字符串也视为根目录，其他为具体路径
        """
        reports = list(self._cache.values())
        if search:
            kw = search.lower()
            reports = [r for r in reports if kw in r.name.lower()]

        if not folder_path or folder_path == "__root__":
            reports = [r for r in reports if not (r.folder_path or "").strip()]
        else:
            reports = [r for r in reports if (r.folder_path or "").strip() == folder_path]

        reports.sort(key=lambda r: r.modified_at or r.created_at or "", reverse=True)
        return reports

    def create_folder(self, folder_path: str) -> bool:
        """创建空文件夹。"""
        fp = folder_path.strip()
        if not fp or fp in self._empty_folders:
            return False
        # 检查是否已被报表使用
        for rpt in self._cache.values():
            if (rpt.folder_path or "").strip() == fp:
                return False  # 文件夹已存在（有报表使用）
        self._empty_folders.add(fp)
        self._save()
        return True

    def move_to_folder(self, report_id: str, folder_path: str):
        """移动报表到指定文件夹。"""
        rpt = self._cache.get(report_id)
        if not rpt:
            return False
        rpt.folder_path = folder_path.strip()
        rpt.modified_at = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        # 如果目标文件夹之前是空文件夹，移除空标记
        target = folder_path.strip()
        if target and target in self._empty_folders:
            self._empty_folders.discard(target)
        self._save()
        return True

    def rename_folder(self, old_path: str, new_path: str):
        """重命名文件夹，批量更新所有匹配路径前缀的报表。
        例如 old_path="销售" → new_path="销售管理"，则 "销售/月度" → "销售管理/月度"。
        """
        old = old_path.strip()
        new = new_path.strip()
        if not old or old == new:
            return 0
        count = 0
        for rpt in self._cache.values():
            fp = (rpt.folder_path or "").strip()
            if fp == old or fp.startswith(old + "/"):
                if fp == old:
                    rpt.folder_path = new
                else:
                    rpt.folder_path = new + fp[len(old):]
                rpt.modified_at = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                count += 1
        # 更新空文件夹
        new_empty = set()
        for ef in self._empty_folders:
            if ef == old:
                new_empty.add(new)
                count += 1
            elif ef.startswith(old + "/"):
                new_empty.add(new + ef[len(old):])
                count += 1
            else:
                new_empty.add(ef)
        self._empty_folders = new_empty
        if count > 0:
            self._save()
        return count

    def delete_folder(self, folder_path: str, delete_reports: bool = False) -> int:
        """删除文件夹。
        Args:
            folder_path: 要删除的文件夹路径
            delete_reports: True=同时删除文件夹下的报表，False=将报表移到根目录
        Returns: 受影响的报表数量
        """
        fp = folder_path.strip()
        if not fp:
            return 0
        count = 0
        ids_to_delete = []
        for rid, rpt in list(self._cache.items()):
            rfp = (rpt.folder_path or "").strip()
            if rfp == fp or rfp.startswith(fp + "/"):
                if delete_reports:
                    ids_to_delete.append(rid)
                else:
                    rpt.folder_path = ""
                    rpt.modified_at = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                count += 1
        for rid in ids_to_delete:
            del self._cache[rid]

        # 删除空文件夹及其子文件夹
        to_remove = {ef for ef in self._empty_folders if ef == fp or ef.startswith(fp + "/")}
        self._empty_folders -= to_remove
        count += len(to_remove)

        if count > 0:
            self._save()
        return count


# ==================== v1 → v2 迁移 ====================

def migrate_v1_to_v2(config: dict) -> dict[str, ReportDefinition]:
    """
    将 v1 格式 (config.json → custom_reports → presets) 迁移为 ReportDefinition 列表

    v1 格式:
      {
        "报表名": {
          "data_objects": [{"name": "商机", "api_name": "NewOpportunityObj", "enabled": true, "match_field": "..."}],
          "main_source": "NewOpportunityObj",
          "field_configs": [
            {
              "display_name": "商机名称",
              "source_api_name": "NewOpportunityObj",
              "field_name": "name",
              "main_link_field": "",
              "source_link_field": ""
            }
          ],
          "date_start": "2026-01-01",
          "date_end": "2026-05-24",
          "filter_conditions": [...],
          "visible_headers": [...],
          "header_order": [...]
        }
      }
    """
    custom_reports = config.get('custom_reports', {})
    if not isinstance(custom_reports, dict):
        return {}

    presets = custom_reports.get('presets', {})
    if not isinstance(presets, dict):
        return {}

    migrated = {}
    for name, state in presets.items():
        if not isinstance(state, dict):
            continue
        if state.get('type') == 'folder':
            continue

        # 解析 data_objects → 提取 joins
        data_objects = state.get('data_objects', [])
        main_source = state.get('main_source', '')
        if not main_source and data_objects:
            main_source = data_objects[0].get('api_name', 'NewOpportunityObj')

        joins = []
        for obj in data_objects:
            if not isinstance(obj, dict):
                continue
            api = obj.get('api_name', '')
            match_raw = obj.get('match_field', '')
            if not api or api == main_source:
                continue
            if match_raw:
                try:
                    match_info = json.loads(match_raw) if isinstance(match_raw, str) else match_raw
                    if isinstance(match_info, dict):
                        joins.append(JoinDefinition(
                            left_object_api=main_source,
                            right_object_api=api,
                            match_keys=[MatchKey(
                                left_field=match_info.get('main', ''),
                                right_field=match_info.get('source', ''),
                            )],
                        ))
                except (json.JSONDecodeError, TypeError):
                    pass

        # 解析 field_configs → columns
        field_configs = state.get('field_configs', [])
        columns = []
        for i, fc in enumerate(field_configs):
            if not isinstance(fc, dict):
                continue
            display_name = fc.get('display_name', '')
            field_name = fc.get('field_name', '')
            if not display_name and not field_name:
                continue
            columns.append(FieldColumn(
                display_name=display_name or field_name,
                source_object_api=fc.get('source_api_name', main_source),
                source_field=field_name,
                sort_order=i,
            ))

        # 解析 filter_conditions → filters
        v1_filters = state.get('filter_conditions', [])
        filters = []
        for fc in v1_filters:
            if not isinstance(fc, dict):
                continue
            filters.append(FilterCondition(
                field_api=fc.get('field', ''),
                operator=fc.get('operator', 'EQ'),
                value=fc.get('value', ''),
            ))

        report = ReportDefinition(
            name=name,
            main_object_api=main_source,
            joins=joins,
            columns=columns,
            filters=filters,
            date_start=state.get('date_start', ''),
            date_end=state.get('date_end', ''),
            date_range_enabled=bool(state.get('date_start')),
            created_at=state.get('created', datetime.now().strftime('%Y-%m-%d %H:%M:%S')),
            modified_at=state.get('modified', datetime.now().strftime('%Y-%m-%d %H:%M:%S')),
        )
        migrated[report.id] = report

    return migrated


def run_migration_if_needed(config: dict) -> Optional[dict[str, ReportDefinition]]:
    """检查并执行 v1→v2 迁移，返回迁移后的报表或 None"""
    custom_reports = config.get('custom_reports', {})
    if not isinstance(custom_reports, dict):
        return None

    presets = custom_reports.get('presets', {})
    if not presets or not isinstance(presets, dict):
        return None

    # 检查是否已经有 v2 配置
    v2_path = _get_storage_path()
    if os.path.exists(v2_path):
        return None  # 已迁移

    logger.info("检测到 v1 报表配置，开始迁移...")
    migrated = migrate_v1_to_v2(config)

    if migrated:
        repo = ReportRepository()
        for rpt in migrated.values():
            repo.save(rpt)
        logger.info(f"已迁移 {len(migrated)} 个报表到 v2 格式")

    return migrated


# -- custom_report/sql_builder.py --
"""
拼表 SQL 生成器

核心职责: 根据 ReportDefinition 生成 MySQL 拼表 SQL

支持的 JOIN 拓扑:
1. 星型: 主表 ←→ 多个关联表（各关联表独立与主表 JOIN）
2. 链式: 主表 → 表B → 表C（通过拓扑排序确定 JOIN 顺序）
3. 混合: 以上两种并存

输出: CREATE TABLE xxx AS SELECT ... FROM ... JOIN ... ON ... WHERE ...
"""

import logging
from collections import deque

logger = logging.getLogger(__name__)


# 相对日期操作符集合（需要 N 值参数）
_RELATIVE_DATE_RANGE_OPS = frozenset({
    'PAST_N_DAYS_EXCLUSIVE', 'PAST_N_DAYS_INCLUSIVE',
    'FUTURE_N_DAYS_EXCLUSIVE', 'FUTURE_N_DAYS_INCLUSIVE',
    'PAST_N_WEEKS_EXCLUSIVE', 'PAST_N_WEEKS_INCLUSIVE',
    'FUTURE_N_WEEKS_EXCLUSIVE', 'FUTURE_N_WEEKS_INCLUSIVE',
    'PAST_N_MONTHS_EXCLUSIVE', 'PAST_N_MONTHS_INCLUSIVE',
    'FUTURE_N_MONTHS_EXCLUSIVE', 'FUTURE_N_MONTHS_INCLUSIVE',
    'PAST_N_QUARTERS_INCLUSIVE',
})

# 相对日期（N天前/N天后)操作符集合 — 前后边界判断
_RELATIVE_DATE_BOUND_OPS = frozenset({
    'N_DAYS_AGO', 'N_DAYS_LATER',
    'N_WEEKS_AGO', 'N_WEEKS_LATER',
})


class JoinSQLBuilder:
    """根据 ReportDefinition 生成拼表 SQL"""

    def __init__(self, report: ReportDefinition, db=None):
        self._report = report
        self._db = db
        self._aliases: dict[str, str] = {}   # {api_name: "t0", "t1", ...}
        self._alias_counter = 0
        self._join_order: list[str] = []      # 拓扑排序后的对象顺序
        self._field_labels = self._load_field_labels()
        self._table_columns_cache: dict[str, set] = {}  # {api: {col_name, ...}}

    @staticmethod
    def _load_field_labels() -> dict:
        """从配置加载字段映射 {api_name: {field_key: field_label}}。"""
        import sys, json, os
        cfg = None
        # 方法1: 从主模块的 load_config 函数加载
        try:
            main = sys.modules.get('__main__')
            if main and hasattr(main, 'load_config'):
                cfg = main.load_config()
        except Exception:
            pass
        # 方法2: 从 get_config_path 直接读取 JSON 文件（后台线程兜底）
        if not cfg:
            try:
                if main and hasattr(main, 'get_config_path'):
                    config_path = main.get_config_path()
                    if os.path.exists(str(config_path)):
                        with open(str(config_path), 'r', encoding='utf-8') as f:
                            cfg = json.load(f)
            except Exception:
                pass
        # 方法3: 直接搜索 .config 目录下的配置文件（后台线程兜底，不依赖主模块全局变量）
        if not cfg:
            try:
                # 程序目录下的 .config 子目录
                config_dir_candidates = []
                if main and hasattr(main, '__file__'):
                    base = os.path.dirname(os.path.abspath(main.__file__))
                    config_dir_candidates.append(os.path.join(base, '.config'))
                # 当前工作目录下的 .config
                cwd = os.getcwd()
                config_dir_candidates.append(os.path.join(cwd, '.config'))
                for config_dir in config_dir_candidates:
                    if not os.path.isdir(config_dir):
                        continue
                    # 优先加载 admin.json（含完整字段配置），其次加载 001.json（默认配置）
                    # 也搜索 profiles 子目录（用户个性化配置）
                    search_paths = [config_dir]
                    profiles_dir = os.path.join(config_dir, 'profiles')
                    if os.path.isdir(profiles_dir):
                        search_paths.append(profiles_dir)
                    for search_dir in search_paths:
                        for fname in ('admin.json', '001.json', 'default.json'):
                            fpath = os.path.join(search_dir, fname)
                            if os.path.exists(fpath):
                                try:
                                    with open(fpath, 'r', encoding='utf-8') as f:
                                        cfg = json.load(f)
                                    if cfg:
                                        break
                                except Exception:
                                    pass
                        if cfg:
                            break
                    if cfg:
                        break
            except Exception:
                pass
        if not cfg:
            return {}
        # 兼容两种路径：直接根级 crm_object_fields，或嵌套在 fxiaoke 下
        crm_fields = cfg.get('crm_object_fields', {})
        if not crm_fields:
            crm_fields = cfg.get('fxiaoke', {}).get('crm_object_fields', {})
        result = {}
        for api, fields in (crm_fields or {}).items():
            if isinstance(fields, dict):
                result[api] = {
                    k: (v.get('label', k) if isinstance(v, dict) else str(v))
                    for k, v in fields.items()
                }
        return result

    def _is_literal_table(self, api: str) -> bool:
        """判断 api 是否是非 CRM 的直连表名（ex_ 前缀等）。"""
        if not api:
            return False
        if api.startswith('ex_'):
            return True
        # 不在 CRM field_labels 中，且不是对象- / sr_ 前缀
        if api not in self._field_labels and not api.startswith(('对象-', 'sr_')):
            return True
        return False

    def _resolve_field(self, api: str, field_key: str) -> str:
        """将字段 API 名解析为 MySQL 表中的中文列名。
        优先使用 field_labels 映射，回退到原始 field_key。
        同时支持按标签值反查（处理 _normalize_field_key 返回标签的情况）。
        """
        if self._is_literal_table(api):
            return field_key
        if self._field_labels:
            obj_labels = self._field_labels.get(api, {})
            if field_key in obj_labels:
                return obj_labels[field_key]
            # 按标签值反查：field_key 可能是中文标签（含括号等特殊字符）
            for k, v in obj_labels.items():
                if v == field_key:
                    return v
        return field_key

    def _field_has_key(self, api: str, field_key: str) -> bool:
        """检查 field_key（API 名或中文标签）是否存在于指定对象的字段映射中。"""
        if not self._field_labels:
            return False
        obj_labels = self._field_labels.get(api, {})
        if not obj_labels:
            return False
        if field_key in obj_labels:
            return True
        # 也按中文标签（value）匹配
        return field_key in obj_labels.values()

    def _get_table_columns(self, api: str) -> set:
        """获取指定对象 MySQL 清洗表的所有列名（带缓存）。"""
        if api in self._table_columns_cache:
            return self._table_columns_cache[api]
        cols = set()
        if self._db and hasattr(self._db, 'resolve_existing_table'):
            try:
                table = self._db.resolve_existing_table(api)
                rows = self._db.execute(f"SHOW COLUMNS FROM `{table}`")
                if rows:
                    cols = {r['Field'] for r in rows}
                    logger.info(f"[SQLBuilder] 获取列信息: api={api} → table=`{table}` | {len(cols)} 列")
                else:
                    logger.warning(f"[SQLBuilder] 获取列信息为空: api={api} → table=`{table}` | 表可能不存在")
            except Exception as e:
                logger.warning(f"[SQLBuilder] 获取列信息失败: api={api} | {e}")
        else:
            logger.warning(f"[SQLBuilder] 无法获取列信息: db={self._db is not None}, has_resolve={hasattr(self._db, 'resolve_existing_table') if self._db else 'N/A'}")
        self._table_columns_cache[api] = cols
        return cols

    def _find_column_owner(self, field_name: str, exclude_apis: set = None) -> str | None:
        """在所有 JOIN 对象中查找哪个对象的 MySQL 表实际包含指定列名。

        返回对象 API 名，未找到返回 None。
        exclude_apis: 要排除的 API 集合（避免返回已经验证不存在的 API）。
        """
        exclude = exclude_apis or set()
        # 第一遍：按原始列名精确匹配
        for api in self._aliases:
            if api in exclude:
                continue
            if field_name in self._get_table_columns(api):
                return api
        # 第二遍：将 CRM API 字段名翻译为中文标签后匹配
        # （MySQL 表使用中文列名，而 field_name 可能是 CRM API 名如 'opportunity_id'）
        for api in self._aliases:
            if api in exclude:
                continue
            labels = self._field_labels.get(api, {})
            for api_key, label in labels.items():
                if label == field_name or api_key == field_name:
                    if label in self._get_table_columns(api):
                        return api
        return None

    @staticmethod
    def _quote_ident(name: str) -> str:
        """安全引用 MySQL 标识符（支持中文等 Unicode 字符）。
        将内部的 ` 转义为 ``，然后用反引号包裹。
        """
        return f"`{name.replace('`', '``')}`"

    # ==================== 主入口 ====================

    def build_create_sql(self) -> str:
        """
        生成完整的 CREATE TABLE AS SELECT 语句

        公式列通过外层子查询计算并写入结果表：
            SELECT _base.*, 公式表达式 AS '显示名', ...
            FROM (内层拼表 SELECT) _base

        Returns:
            CREATE TABLE cr_xxx AS SELECT ... FROM ... JOIN ... WHERE ... GROUP BY ...
        """
        self._assign_aliases()
        select, base_names = self._build_select()
        from_clause = self._build_from()

        # 拆分筛选条件：主表→WHERE，JOIN表→ON（避免 LEFT JOIN 退化为 INNER JOIN）
        where_conds, join_conds = self._split_filter_conditions()
        joins, orphan_conds = self._build_joins(join_conds)

        # 孤儿条件（未匹配到 JOIN 的）追加到 WHERE
        all_where = where_conds + orphan_conds
        where = "WHERE " + "\n  AND ".join(all_where) if all_where else ""
        group_by = self._build_group_by()

        # 构建内层 SQL
        inner_sql = f"{select} {from_clause}"
        if joins:
            inner_sql += f" {joins}"
        if where:
            inner_sql += f" {where}"
        if group_by:
            inner_sql += f" {group_by}"

        # 获取公式列
        formula_cols = self._get_formula_columns()

        if not formula_cols:
            logger.info(f"[SQLBuilder] 无公式列，直接返回内层 SQL ({len(inner_sql)} 字符)")
            return inner_sql

        # 有公式列：外层包装子查询
        base_name_set = self._get_base_display_names()
        outer_parts = ["_base.*"]
        translated_count = 0
        for fc in formula_cols:
            display = fc.display_name if hasattr(fc, 'display_name') else fc.get('display_name', '计算列')
            display = display or '计算列'
            if display in base_name_set:
                logger.warning(
                    f"[SQLBuilder] 公式列 '{display}' 与基础列重名，"
                    f"退回 pandas 计算（避免 MySQL Duplicate column 错误）"
                )
                continue
            expr = getattr(fc, 'formula_expression', '') or ''
            try:
                sql_expr = translate_formula_to_sql(expr, base_names, table_alias='_base')
            except Exception as e:
                logger.warning(f"[SQLBuilder] 公式翻译异常 '{display}': {e}")
                continue
            if sql_expr is None:
                logger.info(f"[SQLBuilder] 公式 '{display}' 含不支持的函数，退回 pandas 计算")
                continue
            outer_parts.append(f"{sql_expr} AS {self._quote_ident(display)}")
            base_name_set.add(display)  # 避免后续公式列与已翻译的公式列重名
            translated_count += 1

        if translated_count == 0:
            return inner_sql

        outer_select = "SELECT " + ",\n       ".join(outer_parts)

        # 记录生成的 SQL 便于排查问题
        logger.info(f"[SQLBuilder] 生成拼表 SQL ({translated_count} 个公式列, {len(sql)} 字符):\n{sql}")

        return sql

    def build_preview_sql(self, page: int = 1, page_size: int = 50) -> str:
        """生成预览查询 SQL（从结果表查询）"""
        table = self._report.result_table
        return f"SELECT * FROM {self._quote_ident(table)} LIMIT {page_size} OFFSET {(page - 1) * page_size}"

    # ==================== 别名分配 + 拓扑排序 ====================

    def _assign_aliases(self):
        """为每个涉及的对象分配表别名 (t0, t1, t2 ...)。
        ✅ 跳过不存在的表，避免生成引用不存在表的 SQL。
        """
        apis = list(dict.fromkeys(self._get_apis_in_join_order()))
        # 过滤掉 MySQL 中不存在的表
        if self._db:
            filtered = []
            for api in apis:
                table = self._table_name(api)
                if self._db.table_exists(table):
                    filtered.append(api)
                else:
                    logger.warning(f"[SQLBuilder] 跳过不存在的表: api={api} → table=`{table}`")
            apis = filtered
        self._aliases = {api: f"t{i}" for i, api in enumerate(apis)}
        self._join_order = apis

    def _get_apis_in_join_order(self) -> list[str]:
        """
        拓扑排序，确定 JOIN 顺序。

        规则:
        1. 主表永远排第一 (t0)
        2. 以主表为起点 BFS：找出所有与已排序表直接关联的表
        3. 未连通的表（孤立表）放到最后
        """
        main = self._report.main_object_api
        if not main:
            return []

        apis = set()
        joins = self._normalize_joins()
        for j in joins:
            apis.add(j.left_object_api)
            apis.add(j.right_object_api)
        if main not in apis:
            apis.add(main)

        # BFS 排序
        ordered = [main]
        visited = {main}
        remaining = apis - visited

        while remaining:
            added = False
            for api in list(remaining):
                for j in joins:
                    left = j.left_object_api
                    right = j.right_object_api
                    if (left in visited and right == api) or (right in visited and left == api):
                        ordered.append(api)
                        visited.add(api)
                        remaining.discard(api)
                        added = True
                        break
            if not added:
                # 有孤立表，直接追加
                ordered.extend(remaining)
                break

        # 不在 JOIN 中的表不加到别名列表（避免产生无 FROM/JOIN 的悬挂引用）
        return ordered

    def _normalize_joins(self) -> list[JoinDefinition]:
        """确保所有 JoinDefinition 的左右表方向一致（左表在右表之前出现于拓扑序）

        拓扑序在 _assign_aliases() 中确定。此方法在拓扑序确定前也会被调用
        （仅用于收集参与 JOIN 的对象集合），此时不做方向归一化。
        """
        result = []
        for j in self._report.joins:
            jd = j if isinstance(j, JoinDefinition) else JoinDefinition(**j)
            result.append(jd)

        # 拓扑序确定后：确保左表在序中先于右表，保证 JOIN 链正确
        if self._join_order:
            api_order = {api: i for i, api in enumerate(self._join_order)}
            for jd in result:
                left_order = api_order.get(jd.left_object_api, 999)
                right_order = api_order.get(jd.right_object_api, 999)
                if left_order > right_order:
                    # 交换左右表，同时交换所有 match_keys
                    jd.left_object_api, jd.right_object_api = jd.right_object_api, jd.left_object_api
                    new_keys = []
                    for mk in jd.match_keys:
                        mk_obj = mk if isinstance(mk, MatchKey) else MatchKey(**mk)
                        mk_obj.left_field, mk_obj.right_field = mk_obj.right_field, mk_obj.left_field
                        new_keys.append(mk_obj)
                    jd.match_keys = new_keys

        return result

    # ==================== SQL 子句生成 ====================

    def _build_select(self) -> tuple[str, list[str]]:
        """生成 SELECT 子句（支持聚合列、GROUP BY，公式列由外层处理）。

        Returns:
            (select_sql, base_display_names) — base_display_names 供公式列 SQL 翻译用
        """
        main_alias = self._aliases.get(self._report.main_object_api, 't0')
        has_aggregate = self._has_aggregate_columns()
        has_group_by = bool(self._report.group_by_fields)
        has_joins = bool(self._report.joins)
        # 有 JOIN 无聚合时，GROUP BY 主表 _id 去重，JOIN 表列需要 ANY_VALUE() 包裹
        need_any_value = has_joins and not has_aggregate

        if not self._report.columns:
            return f"SELECT {main_alias}.*", []

        # 始终包含主表 _id（除非是分组聚合模式，聚合结果无单一 _id）
        # Excel 导入表没有 CRM 的 _id 列，需跳过
        parts = []
        if not (has_aggregate and has_group_by):
            main_api = self._report.main_object_api
            if main_api.startswith('ex_') and self._db and '_id' not in self._db._get_columns(main_api):
                pass  # Excel 表无 _id，跳过
            else:
                parts = [f"{main_alias}.`_id` AS '_id'"]

        # 第一遍：收集所有列信息（按 sort_order 排序，保证 MySQL 表列顺序与编辑界面一致）
        col_infos = []
        sorted_columns = sorted(
            self._report.columns,
            key=lambda c: c.sort_order if isinstance(c, FieldColumn) else (c.get('sort_order', 0) if isinstance(c, dict) else 0)
        )

        # 预扫描：为 date_part 列建立 display_name → (alias, quoted_field) 映射
        direct_col_map = {}
        for col in sorted_columns:
            if not isinstance(col, FieldColumn):
                col = FieldColumn(**col)
            if not col.visible:
                continue
            comp_type = getattr(col, 'computation_type', 'direct')
            if comp_type == 'direct' and col.source_field:
                api = col.source_object_api or self._report.main_object_api
                alias = self._aliases.get(api)
                if alias:
                    resolved_field = self._resolve_field(api, col.source_field)
                    if not self._is_literal_table(api):
                        real_columns = self._get_table_columns(api)
                        if real_columns and resolved_field not in real_columns and col.source_field in real_columns:
                            resolved_field = col.source_field
                    direct_col_map[col.display_name] = (alias, resolved_field)

        for col in sorted_columns:
            if not isinstance(col, FieldColumn):
                col = FieldColumn(**col)
            if not col.visible:
                continue

            # 公式列不进入内层 SQL，由外层子查询包装计算
            if getattr(col, 'computation_type', 'direct') == 'formula':
                continue
            if col.source_field and str(col.source_field).startswith('='):
                continue

            # 地址提取列：SQL 阶段留 NULL 占位，刷新后由 Python 后处理填充
            if getattr(col, 'computation_type', 'direct') == 'address_extract':
                display = col.display_name or '地址提取'
                col_infos.append({
                    'alias': '',
                    'field': '',
                    'display': display,
                    'api': '',
                    'is_aggregate': False,
                    'agg_func': '',
                    'is_address_extract': True,
                })
                continue

            # 时间成分列：直接生成 SQL 日期函数表达式
            if getattr(col, 'computation_type', 'direct') == 'date_part':
                display = col.display_name or '时间成分'
                src_field_display = getattr(col, 'date_part_source_field', '') or ''
                unit = getattr(col, 'date_part_unit', 'year') or 'year'
                # 优先从报表已选列中查找（direct_col_map）
                src_info = direct_col_map.get(src_field_display, (None, None))
                src_alias, src_quoted_field = src_info
                # 回退：在所有 JOIN 表的字段标签中搜索（源字段可能不在报表列中）
                if not (src_alias and src_quoted_field):
                    for api, alias in self._aliases.items():
                        labels = self._field_labels.get(api, {})
                        for field_key, field_label in labels.items():
                            if field_label == src_field_display or field_key == src_field_display:
                                resolved = self._resolve_field(api, field_key)
                                if not self._is_literal_table(api):
                                    real_columns = self._get_table_columns(api)
                                    if real_columns and resolved not in real_columns and field_key in real_columns:
                                        resolved = field_key
                                src_alias = alias
                                src_quoted_field = self._quote_ident(resolved)
                                break
                        if src_alias and src_quoted_field:
                            break
                if src_alias and src_quoted_field:
                    func_map = {
                        'year': f"YEAR({src_alias}.{src_quoted_field})",
                        'month': f"MONTH({src_alias}.{src_quoted_field})",
                        'week': f"WEEK({src_alias}.{src_quoted_field}, 3)",
                        'quarter': f"QUARTER({src_alias}.{src_quoted_field})",
                    }
                    sql_expr = func_map.get(unit, f"YEAR({src_alias}.{src_quoted_field})")
                else:
                    sql_expr = "NULL"
                col_infos.append({
                    'alias': '',
                    'field': '',
                    'display': display,
                    'api': '',
                    'is_aggregate': False,
                    'agg_func': '',
                    'is_date_part': True,
                    '_sql_expr': sql_expr,
                })
                continue

            # 聚合列：source_field 仍然指向原始字段，但 SELECT 使用聚合函数包裹
            if getattr(col, 'computation_type', 'direct') == 'aggregate' and col.aggregate_func:
                if not col.source_field:
                    continue
                api = col.source_object_api or self._report.main_object_api
                resolved_field = self._resolve_field(api, col.source_field)
                alias = self._aliases.get(api)
                if not alias:
                    continue
                # DB 层校验：确认该列在指定对象的 MySQL 清洗表中确实存在
                if self._db and hasattr(self._db, 'resolve_existing_table'):
                    db_cols_agg = self._get_table_columns(api)
                    if db_cols_agg and resolved_field not in db_cols_agg:
                        correct_api_agg = self._find_column_owner(resolved_field, exclude_apis={api})
                        if not correct_api_agg:
                            correct_api_agg = self._find_column_owner(col.source_field, exclude_apis={api})
                        if correct_api_agg and correct_api_agg in self._aliases:
                            api = correct_api_agg
                            alias = self._aliases[api]
                            resolved_field = self._resolve_field(api, col.source_field)
                        else:
                            # 回退：用 display_name 匹配列名（MySQL 表用中文列名）
                            display_agg = col.display_name or ''
                            if display_agg and display_agg in db_cols_agg:
                                resolved_field = display_agg
                            elif display_agg:
                                owner_api = self._find_column_owner(display_agg, exclude_apis={api})
                                if owner_api and owner_api in self._aliases:
                                    api = owner_api
                                    alias = self._aliases[api]
                                    resolved_field = display_agg
                display = col.display_name or f"{col.aggregate_func}({col.source_field})"
                agg_func = col.aggregate_func.upper()
                # 最终校验：聚合列的字段也必须在目标表中存在
                final_agg_cols = self._get_table_columns(api)
                if final_agg_cols and resolved_field not in final_agg_cols:
                    # 回退：尝试用 source_field (API 原始名) 匹配
                    if col.source_field and col.source_field in final_agg_cols:
                        resolved_field = col.source_field
                        logger.info(
                            f"[SQLBuilder] 聚合列 '{display}' 的字段 '"
                            f"{resolved_field}' 使用 source_field '{col.source_field}' 作为列名"
                        )
                    else:
                        logger.warning(
                            f"[SQLBuilder] 聚合列 '{display}' 的字段 '{resolved_field}' "
                            f"在表 {api} 中不存在，已跳过"
                        )
                        continue
                col_infos.append({
                    'alias': alias,
                    'field': resolved_field,
                    'display': display,
                    'api': api,
                    'is_aggregate': True,
                    'agg_func': agg_func,
                })
                continue

            # 直接列（现有逻辑）
            if not col.source_field:
                continue
            api = col.source_object_api or self._report.main_object_api
            # 解析 MySQL 列名
            resolved_field = self._resolve_field(api, col.source_field)
            original_api = api
            # DB 层校验：确认该列在指定对象的 MySQL 清洗表中确实存在
            if self._db and hasattr(self._db, 'resolve_existing_table'):
                db_cols = self._get_table_columns(api)
                # 仅当 db_cols 非空时才做列存在性校验（空集合说明表不存在/无列，不应触发重分配）
                if db_cols and resolved_field not in db_cols:
                    # 当前对象表中不存在该列 → 在所有 JOIN 对象中搜索
                    correct_api = self._find_column_owner(resolved_field, exclude_apis={api})
                    if not correct_api:
                        # 也尝试用原始 field_key 搜索
                        correct_api = self._find_column_owner(col.source_field, exclude_apis={api})
                    if correct_api and correct_api in self._aliases:
                        logger.info(
                            f"[SQLBuilder] 列 '{resolved_field}' 从 {api} 重分配到 {correct_api}"
                        )
                        api = correct_api
                    else:
                        # 在所有表中都找不到该列名 → 尝试用 display_name 作为列名回退
                        # （MySQL 清洗表以中文显示名作为列名，而 CRM API 字段名可能未被翻译）
                        display = col.display_name or ''
                        if display and display in db_cols:
                            logger.info(
                                f"[SQLBuilder] 列 '{resolved_field}' 在表 {api} 中不存在，"
                                f"使用 display_name '{display}' 作为列名"
                            )
                            resolved_field = display
                        elif display:
                            # 当前表没有，尝试在关联表中搜索 display_name
                            owner_api = self._find_column_owner(display, exclude_apis={api})
                            if owner_api and owner_api in self._aliases:
                                logger.info(
                                    f"[SQLBuilder] 列 '{display}' 在表 {owner_api} 中找到，"
                                    f"从 {api} 重分配"
                                )
                                api = owner_api
                                resolved_field = display
                elif not db_cols:
                    logger.warning(
                        f"[SQLBuilder] 表 '{api}' 的列信息为空（表不存在或无数据），"
                        f"列 '{resolved_field}' 保持原分配"
                    )
            alias = self._aliases.get(api)
            if not alias:
                # api 可能是中文显示名而非 CRM API 名，尝试在所有已关联表中查找该列
                correct_api = self._find_column_owner(resolved_field)
                if not correct_api:
                    correct_api = self._find_column_owner(col.source_field)
                if correct_api and correct_api in self._aliases:
                    api = correct_api
                    alias = self._aliases[api]
            if not alias:
                logger.warning(f"[SQLBuilder] 列 '{col.display_name or col.source_field}' 无法关联到任何表，已跳过")
                continue
            # 仅当 api 被更正时才重新解析字段名（保留 display_name 回退的结果）
            if api != original_api:
                resolved_field = self._resolve_field(api, col.source_field)
            # 最终校验：确认 resolved_field 在目标表中确实存在
            final_cols = self._get_table_columns(api)
            if final_cols and resolved_field not in final_cols:
                # 回退1: 尝试用 display_name 匹配
                display = col.display_name or ''
                if display and display in final_cols:
                    resolved_field = display
                    logger.info(
                        f"[SQLBuilder] 列 '{col.display_name or col.source_field}' "
                        f"使用 display_name '{display}' 作为列名"
                    )
                # 回退2: 尝试用 source_field (API 原始名) 匹配
                elif col.source_field and col.source_field in final_cols:
                    resolved_field = col.source_field
                    logger.info(
                        f"[SQLBuilder] 列 '{col.display_name or col.source_field}' "
                        f"使用 source_field '{col.source_field}' 作为列名"
                    )
                else:
                    logger.warning(
                        f"[SQLBuilder] 列 '{col.display_name or col.source_field}' "
                        f"(解析为 '{resolved_field}') 在表 {api} 中不存在，已跳过"
                    )
                    continue
            display = col.display_name or col.source_field
            col_infos.append({
                'alias': alias,
                'field': resolved_field,
                'display': display,
                'api': api,
                'is_aggregate': False,
                'agg_func': '',
            })

        # 汇总日志：记录哪些列被包含、哪些被跳过
        included_names = {ci['display'] for ci in col_infos}
        skipped = []
        for col in sorted_columns:
            if not isinstance(col, FieldColumn):
                col = FieldColumn(**col)
            if not col.visible:
                continue
            comp = getattr(col, 'computation_type', 'direct')
            if comp == 'formula':
                continue  # 公式列由外层处理，不算跳过
            dn = col.display_name or ''
            if dn and dn not in included_names:
                skipped.append(f"{dn}(src={col.source_field}, api={col.source_object_api})")
        if skipped:
            import sys
            print(f"[SQLBuilder] 跳过的列({len(skipped)}个): {skipped}", file=sys.stderr, flush=True)

        if not col_infos:
            if not (has_aggregate and has_group_by):
                logger.warning(f"[SQLBuilder] 所有列解析失败，回退为 SELECT {main_alias}.*")
                main_alias = self._aliases.get(self._report.main_object_api, 't0')
                return f"SELECT {main_alias}.*", []
            logger.warning(f"[SQLBuilder] 聚合模式下所有列解析失败，回退为 SELECT 1")
            return "SELECT 1", []

        # 第二遍：检测重复的 display 名，冲突时追加 _N 后缀去重
        display_counts: dict[str, int] = {}
        if not (has_aggregate and has_group_by):
            display_counts['_id'] = 1
        dedup_names: dict[str, int] = {}

        for ci in col_infos:
            display = ci['display']
            if display_counts.get(display, 0) > 0:
                base = display
                idx = dedup_names.get(base, 2)
                while True:
                    candidate = f"{base}_{idx}"
                    if candidate not in display_counts:
                        break
                    idx += 1
                dedup_names[base] = idx + 1
                if display_counts.get(display, 0) == 1:
                    for j, p in enumerate(parts):
                        if p.endswith(f"AS {self._quote_ident(display)}"):
                            parts[j] = p.replace(
                                f"AS {self._quote_ident(display)}",
                                f"AS {self._quote_ident(display + '_1')}"
                            )
                            break
                    display_counts[display] = 2
                    dedup_names[base] = max(dedup_names.get(base, 2), 3)
                display = candidate
                display_counts[display] = 1
            else:
                display_counts[display] = 1

            quoted_field = self._quote_ident(ci['field'])
            if ci.get('is_address_extract'):
                parts.append(f"CAST(NULL AS CHAR(100)) AS {self._quote_ident(display)}")
            elif ci.get('is_date_part'):
                sql_expr = ci.get('_sql_expr', 'NULL')
                parts.append(f"{sql_expr} AS {self._quote_ident(display)}")
            elif ci['is_aggregate']:
                parts.append(
                    f"{ci['agg_func']}({ci['alias']}.{quoted_field}) AS {self._quote_ident(display)}"
                )
            else:
                col_expr = f"{ci['alias']}.{quoted_field}"
                # 有 JOIN 无聚合时，JOIN 表列用 ANY_VALUE() 防止 MySQL strict mode 报错
                if need_any_value and ci['alias'] != main_alias:
                    col_expr = f"ANY_VALUE({col_expr})"
                parts.append(f"{col_expr} AS {self._quote_ident(display)}")

        # 拼接 ID 列（如果配置了 sync_id_fields）
        composite_id_sql = self._build_composite_id_sql(col_infos, main_alias)
        if composite_id_sql:
            parts.append(composite_id_sql)

        # 收集基础列显示名（供公式列 SQL 翻译使用）
        base_names = [ci['display'] for ci in col_infos]

        return "SELECT " + ",\n       ".join(parts), base_names

    def _build_composite_id_sql(self, col_infos: list[dict],
                                 main_alias: str) -> str | None:
        """如果配置了 sync_id_fields，生成 CONCAT_WS 表达式 AS '唯一ID'。

        查找逻辑：
        1. 先在 col_infos（报表列）中按 display_name 匹配
        2. 未命中则在所有别名表的 field_labels 中按标签反查
        """
        id_fields = getattr(self._report, 'sync_id_fields', None) or []
        if not id_fields:
            return None
        separator = getattr(self._report, 'sync_id_separator', '_') or '_'

        logger.debug(f"[SQLBuilder] sync_id_fields={id_fields}, separator={separator}")
        logger.debug(f"[SQLBuilder] aliases={self._aliases}")

        # 构建 display → (alias, mysql_field) 映射
        display_map = {}
        for ci in col_infos:
            if not ci.get('is_address_extract') and not ci.get('is_date_part') and ci.get('display'):
                display_map[ci['display']] = (ci['alias'], ci['field'])

        parts = []
        for df in id_fields:
            # 解析格式：可能是 "api|label" 或纯 "label"（兼容旧数据）
            if '|' in df:
                target_api, target_label = df.split('|', 1)
            else:
                target_api, target_label = None, df

            logger.debug(f"[SQLBuilder] 处理字段: df={df}, api={target_api}, label={target_label}")

            if target_label == '_id':
                # _id 是源表直列，不需要翻译
                alias = self._aliases.get(target_api) if target_api else None
                if not alias:
                    alias = main_alias
                parts.append(f"{alias}.`_id`")
                logger.debug(f"[SQLBuilder]   → _id 直列: {alias}._id")
            elif target_label in display_map:
                alias, field = display_map[target_label]
                parts.append(f"{alias}.{self._quote_ident(field)}")
                logger.debug(f"[SQLBuilder]   → display_map 命中: {alias}.`{field}`")
            elif target_api and target_api in self._aliases:
                # 按指定 API 查找
                alias = self._aliases[target_api]
                labels = self._field_labels.get(target_api, {})
                found = False
                for fkey, flabel in labels.items():
                    if flabel == target_label:
                        resolved = self._resolve_field(target_api, fkey)
                        parts.append(f"{alias}.{self._quote_ident(resolved)}")
                        logger.debug(f"[SQLBuilder]   → field_labels 命中 ({target_api}): {alias}.`{resolved}`")
                        found = True
                        break
                if not found:
                    logger.warning(f"[SQLBuilder] 拼接 ID 字段 '{df}' 在表 {target_api} 中未找到")
                    parts.append(f"'?'")
            else:
                # 在 field_labels 中按标签反查
                found = False
                for api, alias in self._aliases.items():
                    labels = self._field_labels.get(api, {})
                    for fkey, flabel in labels.items():
                        if flabel == target_label:
                            resolved = self._resolve_field(api, fkey)
                            parts.append(f"{alias}.{self._quote_ident(resolved)}")
                            logger.debug(f"[SQLBuilder]   → 全扫描命中 ({api}): {alias}.`{resolved}`")
                            found = True
                            break
                    if found:
                        break
                if not found:
                    logger.warning(f"[SQLBuilder] 拼接 ID 字段 '{df}' 未在任何表中找到")
                    parts.append(f"'?'")

        if not parts:
            logger.debug(f"[SQLBuilder] 无有效字段，跳过")
            return None

        concat = f"CONCAT_WS('{separator}', {', '.join(parts)})"
        result = f"{concat} AS {self._quote_ident('唯一ID')}"
        logger.debug(f"[SQLBuilder] 生成 SQL: {result}")
        return result

    def _get_base_display_names(self) -> set[str]:
        """获取基础列（非公式列）的所有显示名，用于冲突检测。"""
        names = set()
        has_aggregate = self._has_aggregate_columns()
        has_group_by = bool(self._report.group_by_fields)
        if not (has_aggregate and has_group_by):
            names.add('_id')
        for col in self._report.columns:
            if isinstance(col, dict):
                if not col.get('visible', True):
                    continue
                comp_type = col.get('computation_type', 'direct')
                if comp_type in ('formula', 'address_extract', 'date_part'):
                    continue
                sf = col.get('source_field', '')
            else:
                if not col.visible:
                    continue
                if getattr(col, 'computation_type', 'direct') in ('formula', 'address_extract'):
                    continue
                sf = col.source_field or ''
            if sf and str(sf).startswith('='):
                continue
            display = col.get('display_name', '') if isinstance(col, dict) else col.display_name
            if display:
                names.add(display)
        return names

    def _get_formula_columns(self) -> list[FieldColumn]:
        """获取所有可见的公式列（computation_type='formula' 或有非空 formula_expression）。"""
        result = []
        for col in self._report.columns:
            if isinstance(col, dict):
                if not col.get('visible', True):
                    continue
                comp_type = col.get('computation_type', 'direct')
                formula_expr = col.get('formula_expression', '')
                sf = col.get('source_field', '')
            else:
                if not col.visible:
                    continue
                comp_type = getattr(col, 'computation_type', 'direct')
                formula_expr = getattr(col, 'formula_expression', '') or ''
                sf = col.source_field or ''
            if comp_type == 'formula' or (sf and str(sf).startswith('=')):
                if formula_expr.strip():
                    result.append(col if not isinstance(col, dict) else FieldColumn(**col))
        return result

    def _table_name(self, api: str) -> str:
        """解析 API 名对应的 MySQL 实际表名。
        优先使用「对象-{name}」已有表，回退到 sr_{api_name}。
        对于非 CRM 表（ex_ 前缀或直接表名），直接返回 api。
        """
        if self._db and hasattr(self._db, 'resolve_existing_table'):
            resolved = self._db.resolve_existing_table(api)
            # 如果解析结果是默认的 sr_{api} 模式但该表不存在，
            # 且 api 本身是一个存在的表名 → 使用 api 直接作为表名
            if resolved == f"sr_{api}" and not self._db.table_exists(resolved):
                if self._db.table_exists(api):
                    return api
            # 最终兜底：确认表确实存在，不存在则回退到 sr_{api}
            if not self._db.table_exists(resolved):
                return f"sr_{api}"
            return resolved
        return f"sr_{api}"

    def _build_from(self) -> str:
        """生成 FROM 子句"""
        main = self._report.main_object_api
        alias = self._aliases.get(main, 't0')
        table = self._table_name(main)
        logger.info(f"[SQLBuilder] FROM: api={main} → table=`{table}` alias={alias}")
        return f"FROM {self._quote_ident(table)} {alias}"

    def _build_joins(self, join_conds: dict[str, list[str]] = None) -> str:
        """
        生成 JOIN 子句

        对每个 JoinDefinition：
        - 确定左右表别名
        - 生成 ON 条件（包含 match_keys + 该 JOIN 表专属的筛选条件）
        - 根据 join_type 选择 JOIN 关键字

        Args:
            join_conds: {right_api: [cond_str, ...]} — JOIN 表专属的筛选条件
                        从 _split_filter_conditions 获取，挂载到 ON 子句
                        避免 LEFT JOIN 时 WHERE 条件将之退化为 INNER JOIN
        """
        join_conds = join_conds or {}
        main = self._report.main_object_api
        joins = self._normalize_joins()
        parts = []

        for jd in joins:
            left_api = jd.left_object_api
            right_api = jd.right_object_api

            # ✅ 检查右表是否存在，不存在则跳过该 JOIN 并记录警告
            right_table = self._table_name(right_api)
            if self._db and not self._db.table_exists(right_table):
                logger.warning(f"[SQLBuilder] JOIN 跳过: 右表 `{right_table}` (api={right_api}) 不存在")
                continue

            left_alias = self._aliases.get(left_api)
            right_alias = self._aliases.get(right_api)

            if not left_alias or not right_alias:
                if not left_alias:
                    left_alias = f"t{self._alias_counter}"
                    self._aliases[left_api] = left_alias
                    self._alias_counter += 1
                if not right_alias:
                    right_alias = f"t{self._alias_counter}"
                    self._aliases[right_api] = right_alias
                    self._alias_counter += 1

            join_keyword = self._join_keyword(jd.join_type)
            right_table = self._table_name(right_api)
            multi_match = getattr(jd, 'multi_match', 'expand') or 'expand'
            logger.info(f"[SQLBuilder] JOIN: api={right_api} → table=`{right_table}` alias={right_alias} type={jd.join_type} multi_match={multi_match}")

            # ON 条件：match_keys
            on_conditions = []
            match_key_fields = []  # (left_field, right_field) 用于 multi_match 子查询
            for mk in jd.match_keys:
                mk_obj = mk if isinstance(mk, MatchKey) else MatchKey(**mk)
                if mk_obj.left_field and mk_obj.right_field:
                    left_field = self._resolve_field(left_api, mk_obj.left_field)
                    right_field = self._resolve_field(right_api, mk_obj.right_field)
                    on_conditions.append(
                        f"{left_alias}.{self._quote_ident(left_field)} = "
                        f"{right_alias}.{self._quote_ident(right_field)}"
                    )
                    match_key_fields.append((left_field, right_field))

            # ON 条件：该 JOIN 表专属的筛选条件（防止 LEFT JOIN 退化为 INNER JOIN）
            extra_conds = join_conds.pop(right_api, [])
            on_conditions.extend(extra_conds)

            if not on_conditions:
                continue

            on_clause = " AND ".join(on_conditions)

            # ── multi_match 策略：非 expand 时用子查询去重 ──
            if multi_match == 'first' and match_key_fields:
                # 每组取第一条：GROUP BY join_key + MIN(_id) → 自 JOIN 取完整行
                gk = match_key_fields[0][1]  # 右表 join key 列名
                mm_sub = (
                    f"(SELECT _src.* FROM `{right_table}` _src "
                    f"INNER JOIN (SELECT `{gk}` AS _mm_gk, MIN(`_id`) AS _mm_id "
                    f"FROM `{right_table}` GROUP BY `{gk}`) _mm "
                    f"ON _src.`_id` = _mm._mm_id)"
                )
                parts.append(
                    f"{join_keyword} {mm_sub} {right_alias}\n"
                    f"    ON {on_clause}"
                )
            elif multi_match == 'concat' and match_key_fields:
                # 拼接所有匹配值：GROUP BY join_key + GROUP_CONCAT
                sep = getattr(jd, 'concat_separator', '、') or '、'
                gk = match_key_fields[0][1]
                cols = self._get_table_columns(right_api)
                if cols:
                    select_parts = [f"`{gk}` AS `{gk}`"]
                    for c in sorted(cols):
                        if c != gk:
                            select_parts.append(
                                f"GROUP_CONCAT(DISTINCT `{c}` SEPARATOR '{sep}') AS `{c}`"
                            )
                    mm_sub = f"(SELECT {', '.join(select_parts)} FROM `{right_table}` GROUP BY `{gk}`)"
                else:
                    mm_sub = f"`{right_table}`"
                parts.append(
                    f"{join_keyword} {mm_sub} {right_alias}\n"
                    f"    ON {on_clause}"
                )
            else:
                # expand 或无 match_key：普通 JOIN（一对多展开行）
                parts.append(
                    f"{join_keyword} {self._quote_ident(right_table)} {right_alias}\n"
                    f"    ON {on_clause}"
                )

        # 剩余未匹配到任何 JOIN 的筛选条件（罕见：过滤字段在别名表中但没有对应 JOIN）
        # 放回 WHERE 子句作为兜底
        orphan_conds = []
        for conds in join_conds.values():
            orphan_conds.extend(conds)
        if orphan_conds:
            logger.info(f"[SQLBuilder] {len(orphan_conds)} 个筛选条件未匹配到 JOIN，放入 WHERE")

        return "\n".join(parts), orphan_conds

    def _build_where(self) -> str:
        """生成 WHERE 子句（仅包含主表的筛选条件）。

        JOIN 表的筛选条件移至 ON 子句，避免 LEFT JOIN 退化为 INNER JOIN
        导致主表中无匹配右表的行被静默丢弃。
        """
        where_conds, _ = self._split_filter_conditions()
        if where_conds:
            return "WHERE " + "\n  AND ".join(where_conds)
        return ""

    def _split_filter_conditions(self) -> tuple[list[str], dict[str, list[str]]]:
        """拆分筛选条件为 WHERE 条件（主表）和 JOIN ON 条件（各 JOIN 表）。

        Returns:
            (where_conditions, join_conditions)
            其中 join_conditions = {target_api: [cond_str, ...]}
        """
        main_api = self._report.main_object_api
        where_conds = []
        join_conds: dict[str, list[str]] = {}  # {target_api: [cond_str, ...]}

        for fc in self._report.filters:
            if isinstance(fc, dict):
                field_api = fc.get('field_api', '') or fc.get('field', '')
                operator = fc.get('operator', 'EQ')
                value = fc.get('value', '')
                target_api = fc.get('target_object_api', '') or fc.get('target_api', '')
            elif hasattr(fc, 'field_api'):
                field_api = fc.field_api
                operator = fc.operator
                value = fc.value
                target_api = fc.target_object_api
            else:
                continue

            if not field_api:
                continue

            # 解析字段所属对象
            if not target_api:
                target_api = self._find_field_owner(field_api)
            if not target_api:
                target_api = main_api

            alias = self._aliases.get(target_api, 't0')
            resolved_field = self._resolve_field(target_api, field_api)
            # 校验：用实际 MySQL 列名修正（中文标签可能在表中不存在）
            real_cols = self._get_table_columns(target_api)
            if real_cols and resolved_field not in real_cols and field_api in real_cols:
                resolved_field = field_api
            cond = self._build_filter_condition(alias, resolved_field, operator, value)
            if not cond:
                continue

            # 主表条件 → WHERE；JOIN 表条件 → ON
            if target_api == main_api or not target_api:
                where_conds.append(cond)
            else:
                join_conds.setdefault(target_api, []).append(cond)

        return where_conds, join_conds

    def _has_aggregate_columns(self) -> bool:
        """检查是否有任何聚合列。"""
        for col in self._report.columns:
            if isinstance(col, dict):
                if col.get('computation_type') == 'aggregate' and col.get('aggregate_func'):
                    return True
            elif getattr(col, 'computation_type', 'direct') == 'aggregate' and col.aggregate_func:
                return True
        return False

    def _build_group_by(self) -> str:
        """生成 GROUP BY 子句。

        两种情况：
        1. 有聚合列 → GROUP BY 所有直接列（原有逻辑）
        2. 有 JOIN 但无聚合列 → GROUP BY 主表 _id（防止一对多 JOIN 产生重复行）
        """
        main_alias = self._aliases.get(self._report.main_object_api, 't0')
        has_joins = bool(self._report.joins)

        # 情况 2：有 JOIN 无聚合 → GROUP BY 主表 _id 去重
        if has_joins and not self._has_aggregate_columns():
            return f"GROUP BY {main_alias}.`_id`"

        # 情况 1：有聚合列 → GROUP BY 所有直接列
        if not self._has_aggregate_columns():
            return ""
        if not self._report.columns:
            return ""

        group_parts = []
        for col in self._report.columns:
            if isinstance(col, dict):
                if col.get('computation_type', 'direct') != 'direct':
                    continue
                if not col.get('visible', True):
                    continue
                api = col.get('source_object_api') or self._report.main_object_api
                sf = col.get('source_field', '')
            else:
                if getattr(col, 'computation_type', 'direct') != 'direct':
                    continue
                if not col.visible:
                    continue
                api = col.source_object_api or self._report.main_object_api
                sf = col.source_field

            if not sf:
                continue

            resolved = self._resolve_field(api, sf)
            alias = self._aliases.get(api)
            if not alias:
                continue

            group_parts.append(f"{alias}.{self._quote_ident(resolved)}")

        if not group_parts:
            return ""

        # 如果有显式指定的分组键，优先使用
        if self._report.group_by_fields:
            explicit_parts = []
            for gf in self._report.group_by_fields:
                api = self._report.main_object_api
                resolved = self._resolve_field(api, gf)
                alias = self._aliases.get(api, 't0')
                explicit_parts.append(f"{alias}.{self._quote_ident(resolved)}")
            if explicit_parts:
                group_parts = explicit_parts

        return "GROUP BY " + ", ".join(group_parts)

    def _build_filter_condition(self, alias: str, field: str,
                                 operator: str, value: str) -> str:
        """生成单个筛选条件的 SQL（支持文字和日期操作符）"""
        col = f"{alias}.{self._quote_ident(field)}"
        op = operator.upper()
        escaped = self._escape(value)

        # --- 文字操作符 ---
        if op == 'EQ':
            return f"{col} = '{escaped}'"
        if op == 'NEQ':
            return f"{col} != '{escaped}'"
        if op == 'CONTAINS':
            return f"{col} LIKE '%{escaped}%'"
        if op == 'NOT_CONTAINS':
            return f"({col} IS NULL OR {col} NOT LIKE '%{escaped}%')"
        if op == 'STARTS_WITH':
            return f"{col} LIKE '{escaped}%'"
        if op == 'ENDS_WITH':
            return f"{col} LIKE '%{escaped}'"
        if op == 'IN':
            raw = value.replace('；', ',').replace(';', ',')
            vals = [v.strip() for v in raw.split(',') if v.strip()]
            if not vals:
                return ""
            quoted = ", ".join(f"'{self._escape(v)}'" for v in vals)
            return f"{col} IN ({quoted})"
        if op == 'NOT_IN':
            raw = value.replace('；', ',').replace(';', ',')
            vals = [v.strip() for v in raw.split(',') if v.strip()]
            if not vals:
                return ""
            quoted = ", ".join(f"'{self._escape(v)}'" for v in vals)
            return f"({col} IS NULL OR {col} NOT IN ({quoted}))"
        if op == 'GT':
            return f"{col} > '{escaped}'"
        if op == 'LT':
            return f"{col} < '{escaped}'"
        if op == 'GTE':
            return f"{col} >= '{escaped}'"
        if op == 'LTE':
            return f"{col} <= '{escaped}'"
        if op in ('EMPTY', 'IS_NULL'):
            return f"({col} IS NULL OR {col} = '')"
        if op in ('NOT_EMPTY', 'IS_NOT_NULL'):
            return f"({col} IS NOT NULL AND {col} != '')"

        # --- 日期操作符 ---
        # 使用字符串日期比较（MySQL datetime 字符串格式 'yyyy-mm-dd HH:MM:SS'）
        # 直接用字符串比较即可，无需转时间戳
        escaped_date = self._escape(value)
        if op == 'DATE_BEFORE':
            return f"{col} < '{escaped_date}'"
        if op == 'DATE_AFTER':
            return f"{col} > '{escaped_date} 23:59:59'"
        if op == 'DATE_BEFORE_EQ':
            return f"{col} <= '{escaped_date} 23:59:59'"
        if op == 'DATE_AFTER_EQ':
            return f"{col} >= '{escaped_date}'"
        if op == 'DATE_RANGE':
            parts = value.split('~')
            if len(parts) == 2:
                start = self._escape(parts[0].strip())
                end = self._escape(parts[1].strip())
                return f"({col} >= '{start}' AND {col} <= '{end} 23:59:59')"
            return ""

        # --- 相对日期（范围）操作符 ---
        if op in _RELATIVE_DATE_RANGE_OPS:
            pair = self._compute_relative_date_range_str(op, value)
            if pair:
                return f"({col} >= '{pair[0]}' AND {col} <= '{pair[1]}')"
            return ""

        # --- 相对日期（边界）操作符: N天前/N天后等 ---
        if op in _RELATIVE_DATE_BOUND_OPS:
            bound = self._compute_relative_date_bound_str(op, value)
            if bound is not None:
                if 'AGO' in op:
                    return f"{col} <= '{bound}'"
                else:
                    return f"{col} >= '{bound}'"
            return ""

        return ""

    def _find_field_owner(self, field_api: str) -> str:
        """查找字段所属的对象 API 名。

        在所有已知对象的字段映射中按 API 名和中文标签搜索 field_api，
        返回对象 API 名；未找到时返回主表 API 名。
        """
        # 先按 key（API 名）精确匹配
        for api in self._aliases:
            field_labels = self._field_labels.get(api, {})
            if field_api in field_labels:
                return api
        # 再按 value（中文标签）匹配
        for api in self._aliases:
            field_labels = self._field_labels.get(api, {})
            if field_api in field_labels.values():
                return api
        main = self._report.main_object_api
        return main or ''

    # ==================== 工具方法 ====================

    def _join_keyword(self, join_type: str) -> str:
        """JOIN 类型 → SQL 关键字"""
        return {
            'left': 'LEFT JOIN',
            'inner': 'INNER JOIN',
            'one_to_one': 'LEFT JOIN',  # one_to_one 通过 multi_match='first' 子查询实现
        }.get(join_type, 'LEFT JOIN')

    @staticmethod
    def _date_to_ts(date_str: str, end_of_day: bool = False) -> int:
        """日期字符串 (yyyy-mm-dd) → Unix 毫秒时间戳"""
        from datetime import datetime
        try:
            if end_of_day:
                dt = datetime.strptime(date_str, '%Y-%m-%d')
                dt = dt.replace(hour=23, minute=59, second=59)
            else:
                dt = datetime.strptime(date_str, '%Y-%m-%d')
            return int(dt.timestamp() * 1000)
        except Exception:
            return 0

    @staticmethod
    def _compute_relative_ts_range(operator: str, n_str: str):
        """计算相对日期范围操作符的时间戳区间。

        Returns:
            (start_ts, end_ts) 毫秒时间戳对，或 None
        """
        from datetime import datetime, timedelta
        try:
            n = int(n_str)
        except (ValueError, TypeError):
            return None
        now = datetime.now()
        today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
        today_end = now.replace(hour=23, minute=59, second=59, microsecond=0)

        def _ts(dt):
            return int(dt.timestamp() * 1000)

        op = operator.upper()
        if op == 'PAST_N_DAYS_EXCLUSIVE':
            start = today_start - timedelta(days=n)
            end = today_start - timedelta(seconds=1)
            return (_ts(start), _ts(end))
        if op == 'PAST_N_DAYS_INCLUSIVE':
            start = today_start - timedelta(days=n)
            return (_ts(start), _ts(today_end))
        if op == 'FUTURE_N_DAYS_EXCLUSIVE':
            end = today_start + timedelta(days=n)
            start = today_end + timedelta(seconds=1)
            return (_ts(start), _ts(end - timedelta(seconds=1)))
        if op == 'FUTURE_N_DAYS_INCLUSIVE':
            end = today_start + timedelta(days=n)
            return (_ts(today_start), _ts(end.replace(hour=23, minute=59, second=59)))

        if op == 'PAST_N_WEEKS_EXCLUSIVE':
            start = today_start - timedelta(weeks=n)
            end = today_start - timedelta(seconds=1)
            return (_ts(start), _ts(end))
        if op == 'PAST_N_WEEKS_INCLUSIVE':
            start = today_start - timedelta(weeks=n)
            return (_ts(start), _ts(today_end))
        if op == 'FUTURE_N_WEEKS_EXCLUSIVE':
            end = today_start + timedelta(weeks=n)
            start = today_end + timedelta(seconds=1)
            return (_ts(start), _ts(end - timedelta(seconds=1)))
        if op == 'FUTURE_N_WEEKS_INCLUSIVE':
            end = today_start + timedelta(weeks=n)
            return (_ts(today_start), _ts(end.replace(hour=23, minute=59, second=59)))

        if op == 'PAST_N_MONTHS_EXCLUSIVE':
            start_month = now.month - 1 - n
            start_year = now.year + start_month // 12
            start_month = start_month % 12 + 1
            start = datetime(start_year, start_month, 1)
            end = today_start - timedelta(seconds=1)
            return (_ts(start), _ts(end))
        if op == 'PAST_N_MONTHS_INCLUSIVE':
            start_month = now.month - 1 - n
            start_year = now.year + start_month // 12
            start_month = start_month % 12 + 1
            start = datetime(start_year, start_month, 1)
            return (_ts(start), _ts(today_end))
        if op == 'FUTURE_N_MONTHS_EXCLUSIVE':
            end_month = now.month - 1 + n
            end_year = now.year + end_month // 12
            end_month = end_month % 12 + 1
            if end_month == 12:
                end_dt = datetime(end_year + 1, 1, 1) - timedelta(seconds=1)
            else:
                end_dt = datetime(end_year, end_month + 1, 1) - timedelta(seconds=1)
            start = today_end + timedelta(seconds=1)
            return (_ts(start), _ts(end_dt))
        if op == 'FUTURE_N_MONTHS_INCLUSIVE':
            end_month = now.month - 1 + n
            end_year = now.year + end_month // 12
            end_month = end_month % 12 + 1
            if end_month == 12:
                end_dt = datetime(end_year + 1, 1, 1) - timedelta(seconds=1)
            else:
                end_dt = datetime(end_year, end_month + 1, 1) - timedelta(seconds=1)
            return (_ts(today_start), _ts(end_dt))

        if op == 'PAST_N_QUARTERS_INCLUSIVE':
            current_quarter = (now.month - 1) // 3
            total_months = current_quarter * 3 - n * 3
            start_year = now.year + total_months // 12
            start_month = total_months % 12 + 1
            start = datetime(start_year, start_month, 1)
            return (_ts(start), _ts(today_end))

        return None

    @staticmethod
    def _compute_relative_ts_bound(operator: str, n_str: str):
        """计算相对日期边界操作符的时间戳。

        Returns:
            毫秒时间戳，或 None
        """
        from datetime import datetime, timedelta
        try:
            n = int(n_str)
        except (ValueError, TypeError):
            return None
        now = datetime.now()
        today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)

        def _ts(dt):
            return int(dt.timestamp() * 1000)

        op = operator.upper()
        if op == 'N_DAYS_AGO':
            target = today_start - timedelta(days=n)
            return _ts(target.replace(hour=23, minute=59, second=59))
        if op == 'N_DAYS_LATER':
            return _ts(today_start + timedelta(days=n))
        if op == 'N_WEEKS_AGO':
            target = today_start - timedelta(weeks=n)
            return _ts(target.replace(hour=23, minute=59, second=59))
        if op == 'N_WEEKS_LATER':
            return _ts(today_start + timedelta(weeks=n))
        return None

    @staticmethod
    def _compute_relative_date_range_str(operator: str, n_str: str):
        """计算相对日期范围，返回日期字符串对 (start, end)。"""
        from datetime import datetime, timedelta
        try:
            n = int(n_str)
        except (ValueError, TypeError):
            return None
        now = datetime.now()
        today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
        today_end = now.replace(hour=23, minute=59, second=59, microsecond=0)

        def _s(dt):
            return dt.strftime('%Y-%m-%d %H:%M:%S')

        op = operator.upper()
        if op == 'PAST_N_DAYS_EXCLUSIVE':
            return (_s(today_start - timedelta(days=n)), _s(today_start - timedelta(seconds=1)))
        if op == 'PAST_N_DAYS_INCLUSIVE':
            return (_s(today_start - timedelta(days=n)), _s(today_end))
        if op == 'FUTURE_N_DAYS_EXCLUSIVE':
            return (_s(today_end + timedelta(seconds=1)), _s(today_start + timedelta(days=n) - timedelta(seconds=1)))
        if op == 'FUTURE_N_DAYS_INCLUSIVE':
            return (_s(today_start), _s((today_start + timedelta(days=n)).replace(hour=23, minute=59, second=59)))
        if op == 'PAST_N_WEEKS_EXCLUSIVE':
            return (_s(today_start - timedelta(weeks=n)), _s(today_start - timedelta(seconds=1)))
        if op == 'PAST_N_WEEKS_INCLUSIVE':
            return (_s(today_start - timedelta(weeks=n)), _s(today_end))
        if op == 'FUTURE_N_WEEKS_EXCLUSIVE':
            return (_s(today_end + timedelta(seconds=1)), _s(today_start + timedelta(weeks=n) - timedelta(seconds=1)))
        if op == 'FUTURE_N_WEEKS_INCLUSIVE':
            return (_s(today_start), _s((today_start + timedelta(weeks=n)).replace(hour=23, minute=59, second=59)))
        if op in ('PAST_N_MONTHS_EXCLUSIVE', 'PAST_N_MONTHS_INCLUSIVE'):
            sm = now.month - 1 - n
            sy = now.year + sm // 12
            sm = sm % 12 + 1
            start = datetime(sy, sm, 1)
            end = today_end if 'INCLUSIVE' in op else today_start - timedelta(seconds=1)
            return (_s(start), _s(end))
        if op in ('FUTURE_N_MONTHS_EXCLUSIVE', 'FUTURE_N_MONTHS_INCLUSIVE'):
            em = now.month - 1 + n
            ey = now.year + em // 12
            em = em % 12 + 1
            end_dt = datetime(ey + 1, 1, 1) - timedelta(seconds=1) if em == 12 else datetime(ey, em + 1, 1) - timedelta(seconds=1)
            start = today_start if 'INCLUSIVE' in op else today_end + timedelta(seconds=1)
            return (_s(start), _s(end_dt))
        if op == 'PAST_N_QUARTERS_INCLUSIVE':
            cq = (now.month - 1) // 3
            tm = cq * 3 - n * 3
            sy = now.year + tm // 12
            sm = tm % 12 + 1
            return (_s(datetime(sy, sm, 1)), _s(today_end))
        return None

    @staticmethod
    def _compute_relative_date_bound_str(operator: str, n_str: str):
        """计算相对日期边界，返回日期字符串。"""
        from datetime import datetime, timedelta
        try:
            n = int(n_str)
        except (ValueError, TypeError):
            return None
        now = datetime.now()
        today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)

        def _s(dt):
            return dt.strftime('%Y-%m-%d %H:%M:%S')

        op = operator.upper()
        if op == 'N_DAYS_AGO':
            return _s((today_start - timedelta(days=n)).replace(hour=23, minute=59, second=59))
        if op == 'N_DAYS_LATER':
            return _s(today_start + timedelta(days=n))
        if op == 'N_WEEKS_AGO':
            return _s((today_start - timedelta(weeks=n)).replace(hour=23, minute=59, second=59))
        if op == 'N_WEEKS_LATER':
            return _s(today_start + timedelta(weeks=n))
        return None

    @staticmethod
    def _escape(value: str) -> str:
        """转义 SQL 字符串中的特殊字符"""
        return value.replace("\\", "\\\\").replace("'", "\\'")


class PreviewQueryBuilder:
    """生成预览查询 SQL"""

    @staticmethod
    def query(report: ReportDefinition,
              page: int = 1,
              page_size: int = 50,
              search: str = None) -> tuple[str, list]:
        """
        生成结果表的查询 SQL

        Returns:
            (sql, params)
        """
        table = report.result_table
        params = []
        where = ""
        if search:
            # 搜索所有可见列
            cols = [c for c in report.columns
                    if (isinstance(c, FieldColumn) and c.visible) or
                       (isinstance(c, dict) and c.get('visible', True))]
            if cols:
                conditions = []
                for col in cols:
                    name = col.display_name if isinstance(col, FieldColumn) else col.get('display_name', '')
                    if name:
                        conditions.append(f"`{name.replace('`', '``')} LIKE %s")
                        params.append(f"%{search}%")
                if conditions:
                    where = "WHERE " + " OR ".join(conditions)

        offset = (page - 1) * page_size
        sql = f"SELECT * FROM `{table}` {where} LIMIT {page_size} OFFSET {offset}"
        return sql, params

    @staticmethod
    def count(report: ReportDefinition, search: str = None) -> tuple[str, list]:
        """生成计数 SQL"""
        table = report.result_table
        params = []
        if search:
            cols = [c for c in report.columns
                    if (isinstance(c, FieldColumn) and c.visible) or
                       (isinstance(c, dict) and c.get('visible', True))]
            conditions = []
            for col in cols:
                name = col.display_name if isinstance(col, FieldColumn) else col.get('display_name', '')
                if name:
                    conditions.append(f"`{name.replace('`', '``')} LIKE %s")
                    params.append(f"%{search}%")
            where = "WHERE " + " OR ".join(conditions) if conditions else ""
        else:
            where = ""
        return f"SELECT COUNT(*) AS cnt FROM `{table}` {where}", params


# -- custom_report/syncer.py --
"""
Source 表同步器

职责: 将 CRM API 数据同步到 MySQL source 表（sr_{api_name}）

流程:
1. DataFetcher 从 CRM API 拉取数据
2. 增量写入 MySQL source 表（upsert: 新ID插入，同ID比对hash有变更则更新，无变更跳过）
3. 不清空历史数据
"""

import logging
import time
from datetime import datetime
from typing import Optional, Callable


logger = logging.getLogger(__name__)


class SourceTableSyncer:
    """CRM 对象 → MySQL source 表同步器"""

    def __init__(self, db: ReportDatabase, fetcher: DataFetcher = None):
        self._db = db
        self._fetcher = fetcher or DataFetcher()

    @property
    def available(self) -> bool:
        return self._db.available

    def _is_literal_table(self, api: str) -> bool:
        """判断是否为非 CRM 直连表（Excel导入 / 直连MySQL表）。

        判断逻辑：该名称不需要 CRM 翻译，直接在 MySQL 中作为表名存在。
        """
        if not api:
            return False
        if api.startswith('ex_'):
            return True
        # CRM API 名通常为驼峰式（如 NewOpportunityObj），不存在为直接 MySQL 表名
        # 如果 resolve_existing_table 返回的 sr_{api} 不存在，且 api 本身是表 → 直连表
        if self._db and hasattr(self._db, 'resolve_existing_table'):
            resolved = self._db.resolve_existing_table(api)
            if resolved.startswith('sr_') and not self._db.table_exists(resolved):
                return self._db.table_exists(api)
        return False

    def sync_all_for_report(self,
                            report: ReportDefinition,
                            progress_callback: Callable = None) -> dict:
        """
        同步报表涉及的所有对象的 source 表

        Args:
            report: 报表定义
            progress_callback: 进度回调 (step, message, percent)

        Returns:
            {api_name: {'rows': int, 'error': str|None, 'duration': float}}
        """
        apis = report.get_object_apis()
        if not apis:
            return {}

        # 拆分为 CRM API（需拉取）和直连表（已验证存在即可）
        crm_apis = [a for a in apis if not self._is_literal_table(a)]
        literal_tables = [a for a in apis if self._is_literal_table(a)]

        # 直连表：只需验证存在
        results = {}
        for table_name in literal_tables:
            if self._db.table_exists(table_name):
                row_count = self._db.table_row_count(table_name)
                results[table_name] = {'rows': row_count, 'error': None, 'duration': 0}
            else:
                results[table_name] = {'rows': 0,
                    'error': f'表 {table_name} 不存在', 'duration': 0}
            if progress_callback:
                progress_callback('sync', f"已就绪: {table_name} ({results[table_name]['rows']} 行)", 10)

        total = len(crm_apis)
        if total == 0:
            return results

        # 并行拉取 CRM 对象（互不依赖，可安全并发）
        from concurrent.futures import ThreadPoolExecutor, as_completed
        import threading

        results_lock = threading.Lock()
        _completed = [0]  # mutable for closure

        def _sync_one(api, idx):
            """在后台线程中同步单个 CRM 对象"""
            if progress_callback:
                progress_callback('sync', f"正在同步 {api} ({idx+1}/{total})...",
                                  int((idx / total) * 40))

            # 子进度: 对象内拉取进度
            def _fetch_progress(fetched, obj_total):
                if progress_callback and obj_total:
                    pct = int((min(idx + 1, total) / total) * 40)
                    progress_callback('sync',
                        f"正在同步 {api}: {fetched}/{obj_total} 条", pct)

            t0 = time.time()
            rows, total_count, err = self._fetcher.fetch_object(
                api, progress_callback=_fetch_progress)
            duration = time.time() - t0

            if err:
                with results_lock:
                    _completed[0] += 1
                if progress_callback:
                    progress_callback('sync', f"{api} 同步失败: {err}",
                                      int((_completed[0] / total) * 40))
                return api, {'rows': 0, 'error': err, 'duration': duration}

            if progress_callback:
                progress_callback('sync', f"正在写入 {api}: {len(rows)} 条...",
                                  int((min(idx + 1, total) / total) * 40))

            # 增量写入 MySQL source 表(不清空,按 _id 比对更新)
            if not self._db.ensure_source_table(api, sample_row=rows[0] if rows else None):
                with results_lock:
                    _completed[0] += 1
                if progress_callback:
                    progress_callback('sync', f"{api} 建表失败",
                                      int((_completed[0] / total) * 40))
                return api, {'rows': 0, 'error': '建表失败: ' + str(api), 'duration': duration}
            self._db.upsert_rows(api, rows)

            result = {
                'rows': len(rows),
                'total': total_count,
                'error': None,
                'duration': duration,
            }

            with results_lock:
                _completed[0] += 1

            if progress_callback:
                progress_callback('sync', f"已同步 {api}: {len(rows)} 条",
                                  int((_completed[0] / total) * 40))

            return api, result

        max_workers = min(total, 3)  # 最多 3 个并发,避免 CRM API 限流
        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            futures = {executor.submit(_sync_one, api, i): api
                       for i, api in enumerate(crm_apis)}
            for f in as_completed(futures):
                try:
                    api, result = f.result()
                    results[api] = result
                except Exception as e:
                    api = futures.get(f, '?')
                    results[api] = {'rows': 0, 'error': str(e), 'duration': 0}

        return results
    def sync_single(self, object_api: str,
                    max_records: int = 10000,
                    progress_callback: Callable = None) -> dict:
        """
        同步单个对象

        Returns:
            {'rows': int, 'error': str|None, 'duration': float}
        """
        t0 = time.time()
        rows, total, err = self._fetcher.fetch_object(object_api, max_records=max_records)
        duration = time.time() - t0

        if err:
            return {'rows': 0, 'error': err, 'duration': duration}

        self._db.ensure_source_table(object_api, sample_row=rows[0] if rows else None)
        self._db.upsert_rows(object_api, rows)

        return {'rows': len(rows), 'total': total, 'error': None, 'duration': duration}

    def check_source_status(self, report: ReportDefinition) -> dict:
        """
        检查报表所需的 source 表状态

        Returns:
            {api_name: {'exists': bool, 'row_count': int}}
        """
        status = {}
        for api in report.get_object_apis():
            table = ReportDatabase.source_table_name(api)
            exists = self._db.table_exists(table)
            count = self._db.get_source_count(api) if exists else 0
            status[api] = {'exists': exists, 'row_count': count}
        return status


def _wrap_phase2_progress(progress_callback):
    """将 refresh 内部的 0–100 进度映射到 full_refresh 的 45–90 区间。"""
    if not progress_callback:
        return None
    def _wrapped(phase, message, percent):
        mapped = 45 + int(percent * 0.45)
        progress_callback(phase, message, mapped)
    return _wrapped


class ReportRefreshWorker:
    """
    报表刷新流程编排器

    完整刷新流程:
    1. sync: 同步 source 表（CRM API → MySQL）
    2. join: 生成拼表 SQL 并执行（CREATE TABLE AS SELECT）
    3. done: 更新元数据
    """

    def __init__(self, db: ReportDatabase, syncer: SourceTableSyncer = None):
        self._db = db
        self._syncer = syncer or SourceTableSyncer(db)

    def full_refresh(self,
                     report: ReportDefinition,
                     progress_callback: Callable = None) -> dict:
        """
        完整刷新：从 CRM 拉取最新数据 → 写入 MySQL → 拼表生成结果表。

        Args:
            report: 报表定义
            progress_callback: (phase, message, percent) 三阶段进度

        Returns:
            {'success': bool, 'row_count': int, 'error': str, 'duration': float,
             'sync_results': dict}
        """
        t0 = time.time()
        apis = report.get_object_apis()
        if not apis:
            return {'success': False, 'row_count': 0,
                    'error': '报表未配置数据对象', 'duration': 0}

        # Phase 1: 同步 source 表（CRM → MySQL） 0%–40%
        if progress_callback:
            progress_callback('sync', f'开始同步 {len(apis)} 个对象...', 0)

        sync_results = self._syncer.sync_all_for_report(report, progress_callback)

        sync_errors = {k: v for k, v in sync_results.items() if v.get('error')}
        if sync_errors:
            err_msgs = [f"{k}: {v['error']}" for k, v in sync_errors.items()]
            return {'success': False, 'row_count': 0,
                    'error': 'CRM 同步失败:\n' + '\n'.join(err_msgs),
                    'duration': time.time() - t0, 'sync_results': sync_results}

        if progress_callback:
            progress_callback('join', '正在执行拼表...', 45)

        # Phase 2: 拼表生成结果表 45%–90%
        result = self.refresh(report, progress_callback=_wrap_phase2_progress(progress_callback))

        if not result['success']:
            result['sync_results'] = sync_results
            return result

        if progress_callback:
            progress_callback('done', result.get('message', '刷新完成'),
                              100)

        result['sync_results'] = sync_results
        return result

    def refresh(self,
                report: ReportDefinition,
                progress_callback: Callable = None) -> dict:
        """
        拼表生成结果表（直接使用已有 MySQL source 表，不从 CRM 拉取数据）。

        Args:
            report: 报表定义
            progress_callback: (phase, message, percent) 三阶段进度

        Returns:
            {'success': bool, 'row_count': int, 'error': str, 'duration': float}
        """

        t0 = time.time()

        # Phase 1: 检查已有表（不再从 CRM 同步）
        if progress_callback:
            progress_callback('sync', '检查已有数据表...', 5)

        apis = report.get_object_apis()
        if not apis:
            return {'success': False, 'row_count': 0,
                    'error': '报表未配置数据对象', 'duration': 0}

        # 检查各对象对应的 MySQL 表是否存在
        missing = []
        for api in apis:
            # 非 CRM 直连表：直接用 api 作为表名
            if self._syncer._is_literal_table(api):
                table = api
            else:
                table = self._db.resolve_existing_table(api)
            row_count = self._db.table_row_count(table) if self._db.table_exists(table) else 0
            logger.info(f"[ReportRefresh] 对象 '{api}' → 表 `{table}` | 存在={self._db.table_exists(table)} | 行数={row_count}")
            if not self._db.table_exists(table):
                missing.append(f"{api}（表 {table} 不存在）")
        if missing:
            return {'success': False, 'row_count': 0,
                    'error': f"以下数据表不存在，请先在对象查询中同步数据：\n" + '\n'.join(missing),
                    'duration': time.time() - t0}

        if progress_callback:
            has_filters = bool(report.filters)
            msg = '正在执行拼表（含筛选条件）...' if has_filters else '正在执行拼表...'
            progress_callback('join', msg, 20)

        # Phase 2: 生成并执行拼表 SQL
        try:
            builder = JoinSQLBuilder(report, db=self._db)
            select_sql = builder.build_create_sql()
            filter_count = len(report.filters) if report.filters else 0
            if filter_count > 0:
                for i, fc in enumerate(report.filters):
                    if isinstance(fc, dict):
                        fn = fc.get('field_api', '') or fc.get('field', '')
                        fo = fc.get('operator', '')
                        fv = fc.get('value', '')
                    else:
                        fn = getattr(fc, 'field_api', '')
                        fo = getattr(fc, 'operator', '')
                        fv = getattr(fc, 'value', '')
                    logger.info(f"[ReportRefresh] 筛选条件 {i+1}: {fn} {fo} '{fv}'")
            logger.info(f"[ReportRefresh] 拼表 SQL 已生成 | 筛选条件: {filter_count} 个 | SQL长度: {len(select_sql)}")
            # 诊断：采样字段值 + 打印 SQL 片段
            if filter_count > 0:
                logger.info(f"[ReportRefresh] === 拼表SQL (前600字符) ===\n{select_sql[:600]}")
                try:
                    main_api = report.main_object_api
                    main_table = self._db.resolve_existing_table(main_api)
                    for fc in (report.filters or []):
                        fn = getattr(fc, 'field_api', '') if not isinstance(fc, dict) else (fc.get('field_api', '') or fc.get('field', ''))
                        if not fn:
                            continue
                        resolved = builder._resolve_field(main_api, fn)
                        rows = self._db.execute(f"SELECT `{resolved}` FROM `{main_table}` WHERE `{resolved}` IS NOT NULL AND `{resolved}` != '' LIMIT 3")
                        if rows:
                            vals = [str(list(r.values())[0]) for r in rows]
                            logger.info(f"[ReportRefresh] 诊断 - '{fn}' → 列 '{resolved}' | 样本: {vals}")
                except Exception as diag_e:
                    logger.warning(f"[ReportRefresh] 诊断失败: {diag_e}")
            self._db.create_result_table_as(report.id, select_sql,
                                            write_mode=report.write_mode)
        except Exception as e:
            logger.error(f"[ReportRefresh] 拼表失败: {e}")
            return {'success': False, 'row_count': 0, 'error': f"拼表 SQL 执行失败: {e}",
                    'duration': time.time() - t0}

        if progress_callback:
            progress_callback('join', '拼表完成，正在统计...', 80)

        # Phase 2.5: 地址提取后处理
        try:
            self._run_address_extraction(report, progress_callback)
        except Exception as e:
            logger.error(f"[ReportRefresh] 地址提取后处理异常（不阻断）: {e}")

        # Phase 2.6: 时间成分后处理（年/月/周/季度提取，对 SQL 已生成 NULL 的列做 pandas 回填）
        try:
            self._run_date_part_extraction(report, progress_callback)
        except Exception as e:
            logger.error(f"[ReportRefresh] 时间成分后处理异常（不阻断）: {e}")

        # Phase 2.7: 公式列后处理（对 SQL 无法翻译的公式列，通过 pandas 计算并写回 MySQL）
        try:
            self._run_formula_backfill(report, progress_callback)
        except Exception as e:
            logger.error(f"[ReportRefresh] 公式列后处理异常（不阻断）: {e}")

        # Phase 3: 更新元数据
        row_count = self._db.get_result_count(report.id)
        report.result_row_count = row_count
        report.result_table_name = ReportDatabase.result_table_name(report.id)
        report.last_refresh_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

        # 保存定义 JSON 到元数据表
        import json
        self._db.save_report_meta(
            report.id, report.name,
            json.dumps(report.to_dict(), ensure_ascii=False),
            row_count=row_count,
            refresh_time=report.last_refresh_time,
        )

        duration = time.time() - t0

        if progress_callback:
            progress_callback('done', f'刷新完成: {row_count} 条记录 ({duration:.1f}s)', 100)

        return {
            'success': True,
            'row_count': row_count,
            'error': None,
            'duration': duration,
        }

    def _run_address_extraction(self, report: ReportDefinition,
                                 progress_callback: Callable = None):
        """对结果表中地址提取列进行后处理填充。

        读取结果表 → 逐行匹配 ChinaCitys.json → UPDATE 写回。
        """
        addr_cols = []
        for col in report.columns:
            if isinstance(col, dict):
                if col.get('computation_type') == 'address_extract' and col.get('visible', True):
                    addr_cols.append(col)
            elif hasattr(col, 'computation_type'):
                if col.computation_type == 'address_extract' and col.visible:
                    addr_cols.append(col)

        logger.info(
            f"[AddressExtract] 共 {len(report.columns)} 列，"
            f"其中地址提取列 {len(addr_cols)} 个"
        )

        if not addr_cols:
            logger.info("[AddressExtract] 无地址提取列，跳过")
            return

        table = report.result_table
        logger.info(f"[AddressExtract] 结果表: {table}")

        if not self._db.table_exists(table):
            logger.warning(f"[AddressExtract] 结果表 `{table}` 不存在，跳过")
            return

        # 获取结果表实际列名（用于诊断）
        try:
            db_cols = set()
            cols_info = self._db.execute(f"SHOW COLUMNS FROM `{table}`")
            if cols_info:
                db_cols = {r['Field'] for r in cols_info}
            logger.info(f"[AddressExtract] 结果表列名({len(db_cols)}): {sorted(db_cols)[:20]}...")
        except Exception as e:
            logger.warning(f"[AddressExtract] 获取表列信息失败: {e}")
            db_cols = set()

        total = len(addr_cols)
        for i, col in enumerate(addr_cols):
            # Resolve fields (handles both dict and FieldColumn)
            if isinstance(col, dict):
                source_cols = col.get('address_source_fields', []) or []
                level = col.get('address_target_level', 'city') or 'city'
                display_name = col.get('display_name', '地址提取') or '地址提取'
            else:
                source_cols = getattr(col, 'address_source_fields', []) or []
                level = getattr(col, 'address_target_level', 'city') or 'city'
                display_name = col.display_name or '地址提取'

            logger.info(
                f"[AddressExtract] [{i+1}/{total}] 列='{display_name}' "
                f"level={level} source_cols={source_cols}"
            )

            if progress_callback:
                progress_callback(
                    'extract',
                    f"正在提取地址信息 ({display_name}) {i+1}/{total}...",
                    80 + int((i / total) * 15)
                )

            if not source_cols:
                logger.warning(f"[AddressExtract] '{display_name}' 未配置候选列，跳过")
                continue

            # 诊断：检查候选列是否在结果表中
            missing_cols = [c for c in source_cols if c not in db_cols]
            if missing_cols:
                logger.warning(
                    f"[AddressExtract] '{display_name}' 候选列在结果表中不存在: {missing_cols}"
                )
            if display_name not in db_cols:
                logger.warning(
                    f"[AddressExtract] 目标列 '{display_name}' 不在结果表中"
                )

            try:
                extractor = AddressExtractor()
                self._db.update_address_column(
                    table, display_name, source_cols, extractor, level
                )
            except Exception as e:
                logger.error(f"[AddressExtract] '{display_name}' 提取失败: {e}")
                import traceback
                traceback.print_exc()

    def _run_date_part_extraction(self, report: ReportDefinition,
                                   progress_callback: Callable = None):
        """对结果表中时间成分列进行后处理填充（用单次 SQL UPDATE 完成，无逐行网络往返）。

        通过读取结果表的源日期列 → 用 MySQL 内置的 YEAR/MONTH/WEEK/QUARTER
        函数直接在 MySQL 侧计算并写回，只发一次 UPDATE 语句。
        """
        from datetime import datetime as dt

        dp_cols = []
        for col in report.columns:
            if isinstance(col, dict):
                if col.get('computation_type') == 'date_part' and col.get('visible', True):
                    dp_cols.append(col)
            elif hasattr(col, 'computation_type'):
                if col.computation_type == 'date_part' and col.visible:
                    dp_cols.append(col)

        if not dp_cols:
            return

        table = report.result_table
        if not self._db.table_exists(table):
            logger.warning(f"[DatePart] 结果表 `{table}` 不存在，跳过")
            return

        # 获取现有列
        try:
            cols_info = self._db.execute(f"SHOW COLUMNS FROM `{table}`")
            existing_cols = {r['Field'] for r in cols_info} if cols_info else set()
        except Exception as e:
            logger.warning(f"[DatePart] 获取列信息失败: {e}")
            return

        # 收集有效的时间成分别
        pending_cols = []
        for dc in dp_cols:
            display_name = dc.get('display_name', '') if isinstance(dc, dict) else dc.display_name
            src_field = dc.get('date_part_source_field', '') if isinstance(dc, dict) else getattr(dc, 'date_part_source_field', '')
            if display_name and src_field:
                pending_cols.append(dc)

        if not pending_cols:
            return

        # 确保目标列存在（缺失则添加为 VARCHAR，避免 INT 列 + 空字符串报错）
        for dc in pending_cols[:]:
            display_name = dc.get('display_name', '') if isinstance(dc, dict) else dc.display_name
            if display_name not in existing_cols:
                try:
                    self._db.execute(
                        f"ALTER TABLE `{table}` ADD COLUMN `{display_name}` VARCHAR(32) DEFAULT ''"
                    )
                    existing_cols.add(display_name)
                except Exception as e:
                    logger.warning(f"[DatePart] 添加列 `{display_name}` 失败: {e}")
                    pending_cols.remove(dc)

        if not pending_cols:
            return

        logger.info(f"[DatePart] 发现 {len(pending_cols)} 个时间成分别，用 MySQL 单次 UPDATE 写回")

        # 构建 SET 子句：用 MySQL YEAR/MONTH/WEEK/QUARTER 函数直接在 DB 侧计算
        set_parts = []
        for dc in pending_cols:
            display_name = dc.get('display_name', '') if isinstance(dc, dict) else dc.display_name
            src_field = dc.get('date_part_source_field', '') if isinstance(dc, dict) else getattr(dc, 'date_part_source_field', '')
            unit = dc.get('date_part_unit', 'year') if isinstance(dc, dict) else getattr(dc, 'date_part_unit', 'year') or 'year'

            # 校验源字段是否在结果表中（SELECT 可能已用 API 名）
            if src_field not in existing_cols:
                logger.warning(f"[DatePart] 源字段 `{src_field}` 不在结果表中，跳过（SELECT 已计算）")
                continue

            if unit == 'year':
                mysql_expr = f"YEAR(`{src_field}`)"
            elif unit == 'month':
                mysql_expr = f"MONTH(`{src_field}`)"
            elif unit == 'week':
                mysql_expr = f"WEEK(`{src_field}`, 3)"
            elif unit == 'quarter':
                mysql_expr = f"QUARTER(`{src_field}`)"
            else:
                continue
            # 仅对源日期非 NULL 的行更新，避免空字符串写入问题
            set_parts.append(
                f"`{display_name}` = IF(`{src_field}` IS NOT NULL AND `{src_field}` != '', "
                f"CAST({mysql_expr} AS CHAR), '')"
            )

        if not set_parts:
            return

        set_clause = ', '.join(set_parts)
        update_sql = f"UPDATE `{table}` SET {set_clause}"
        try:
            self._db.execute(update_sql)
            total = self._db.table_row_count(table)
            logger.info(f"[DatePart] 完成: 用单次 UPDATE 处理了约 {total} 行")
        except Exception as e:
            logger.warning(f"[DatePart] 批量更新失败: {e}")

    @staticmethod
    def _parse_date_value(raw_value):
        """解析日期值 → datetime，失败返回 None。"""
        if raw_value is None:
            return None
        from datetime import datetime as dt
        if isinstance(raw_value, dt):
            return raw_value
        if isinstance(raw_value, (int, float)):
            try:
                ts = float(raw_value)
                if ts > 1e12:
                    return dt.fromtimestamp(ts / 1000)
                else:
                    return dt.fromtimestamp(ts)
            except (ValueError, OSError):
                pass
        if isinstance(raw_value, str):
            raw_value = raw_value.strip()
            if not raw_value:
                return None
            for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d', '%Y-%m-%dT%H:%M:%S',
                         '%Y/%m/%d %H:%M:%S', '%Y/%m/%d', '%Y年%m月%d日',
                         '%Y-%m-%d %H:%M', '%Y/%m/%d %H:%M'):
                try:
                    return dt.strptime(raw_value, fmt)
                except ValueError:
                    continue
        return None

    def _run_formula_backfill(self, report: ReportDefinition,
                               progress_callback: Callable = None):
        """对结果表中未能翻译为 SQL 的公式列进行后处理填充。

        识别结果表中缺失的公式列 → pandas 计算 → 写回 MySQL。
        这确保所有公式列（包括 DATE、TEXT 等已支持翻译的函数兜底）
        都能正确写入 MySQL 结果表。
        """
        # 1. 收集所有公式列
        formula_cols = []
        for col in report.columns:
            if isinstance(col, dict):
                if col.get('computation_type') == 'formula' and col.get('visible', True):
                    formula_cols.append(col)
            elif hasattr(col, 'computation_type'):
                if col.computation_type == 'formula' and col.visible:
                    formula_cols.append(col)

        if not formula_cols:
            return

        table = report.result_table
        if not self._db.table_exists(table):
            return

        # 2. 获取结果表现有列
        try:
            cols_info = self._db.execute(f"SHOW COLUMNS FROM `{table}`")
            existing_cols = {r['Field'] for r in cols_info} if cols_info else set()
            has_row_id = '_row_id' in existing_cols
        except Exception as e:
            logger.warning(f"[FormulaBackfill] 获取列信息失败: {e}")
            return

        if not has_row_id:
            logger.warning("[FormulaBackfill] 结果表无 _row_id 列，无法逐行更新")
            return

        # 3. 找出缺失的公式列
        missing_formula_cols = []
        for fc in formula_cols:
            display_name = fc.get('display_name', '') if isinstance(fc, dict) else fc.display_name
            if display_name and display_name not in existing_cols:
                missing_formula_cols.append(fc)

        if not missing_formula_cols:
            return

        logger.info(
            f"[FormulaBackfill] 发现 {len(missing_formula_cols)} 个缺失的公式列，"
            f"将通过 pandas 计算并写回 MySQL"
        )

        # 4. 先为缺失列执行 ALTER TABLE ADD COLUMN
        for fc in missing_formula_cols:
            display_name = fc.get('display_name', '') if isinstance(fc, dict) else fc.display_name
            try:
                self._db.execute(
                    f"ALTER TABLE `{table}` ADD COLUMN `{display_name}` LONGTEXT"
                )
                logger.info(f"[FormulaBackfill] 已添加列 `{display_name}`")
            except Exception as e:
                logger.warning(f"[FormulaBackfill] 添加列 `{display_name}` 失败: {e}")
                # 移除添加失败的列
                missing_formula_cols.remove(fc)

        if not missing_formula_cols:
            return

        # 5. 全量读取数据、计算并写回（LEAD/LAG 等行间函数需要看到全量数据）
        import pandas as pd

        # 检查是否含有行间引用函数（LEAD/LAG），需要全量计算
        has_row_ref = False
        for fc in missing_formula_cols:
            expr = fc.get('formula_expression', '') if isinstance(fc, dict) else getattr(fc, 'formula_expression', '')
            if expr and re.search(r'\b(LEAD|LAG|NEXT_IF|PREV_IF)\s*\(', str(expr), re.IGNORECASE):
                has_row_ref = True
                break

        if has_row_ref:
            # 全量加载（LEAD/LAG 需要跨行比较，不能分块）
            rows = self._db.execute(f"SELECT * FROM `{table}`")
            if not rows:
                return
            df = pd.DataFrame(rows)
            if df.empty:
                return

            try:
                # 传入 report.columns 让 _resolve_api_field_refs 能建立 API→显示名映射
                df = eval_formula_columns(df, report.columns)
            except Exception as e:
                logger.warning(f"[FormulaBackfill] 公式计算失败: {e}")

            # 批量 UPDATE — 使用 CASE-WHEN 单次 SQL（全量加载路径）
            conn = self._db._get_conn() if hasattr(self._db, '_get_conn') else None
            for fc in missing_formula_cols:
                display_name = fc.get('display_name', '') if isinstance(fc, dict) else fc.display_name
                if display_name not in df.columns:
                    continue

                updated = 0
                if conn:
                    try:
                        cases = []
                        params = []
                        for _, row_data in df.iterrows():
                            row_id = row_data.get('_row_id')
                            if row_id is None:
                                continue
                            val = row_data.get(display_name)
                            if val is None or (isinstance(val, float) and pd.isna(val)):
                                continue
                            val_str = str(val)
                            cases.append("WHEN %s THEN %s")
                            params.append(int(row_id))
                            params.append(val_str)

                        if cases:
                            for i in range(0, len(cases), 500):
                                batch_cases = cases[i:i + 500]
                                batch_params = params[i * 2:(i + 500) * 2]
                                batch_clause = " ".join(batch_cases)
                                batch_sql = (
                                    f"UPDATE `{table}` SET `{display_name}` = "
                                    f"CASE `_row_id` {batch_clause} "
                                    f"ELSE `{display_name}` END"
                                )
                                with conn.cursor() as cur:
                                    cur.execute(batch_sql, batch_params)
                            updated = len(cases)
                    except Exception as e:
                        logger.warning(
                            f"[FormulaBackfill] 更新列 `{display_name}` 失败: {e}"
                        )
                total_updated = updated

            logger.info(
                f"[FormulaBackfill] 完成(全量): {len(missing_formula_cols)} 个公式列, "
                f"共更新 {total_updated} 行"
            )
            return

        # 无行间函数：分批处理即可
        batch_size = 5000
        offset = 0
        total_updated = 0

        while True:
            rows = self._db.execute(
                f"SELECT * FROM `{table}` LIMIT {batch_size} OFFSET {offset}"
            )
            if not rows:
                break

            df = pd.DataFrame(rows)
            if df.empty:
                break

            # 计算所有缺失的公式列（只针对缺失列）
            try:
                # 传入 report.columns 让 _resolve_api_field_refs 能建立 API→显示名映射
                df = eval_formula_columns(df, report.columns)
            except Exception as e:
                logger.warning(f"[FormulaBackfill] 公式计算失败 (offset={offset}): {e}")
                offset += len(rows)
                continue

            # 批量 UPDATE — 使用 CASE-WHEN 单次 SQL，避免逐行网络往返
            conn = self._db._get_conn() if hasattr(self._db, '_get_conn') else None
            for fc in missing_formula_cols:
                display_name = fc.get('display_name', '') if isinstance(fc, dict) else fc.display_name
                if display_name not in df.columns:
                    continue

                updated = 0
                if conn:
                    try:
                        # 构建 CASE-WHEN 批量 UPDATE: UPDATE t SET col = CASE _row_id
                        # WHEN 1 THEN 'val1' WHEN 2 THEN 'val2' ... ELSE col END
                        cases = []
                        params = []
                        for _, row_data in df.iterrows():
                            row_id = row_data.get('_row_id')
                            if row_id is None:
                                continue
                            val = row_data.get(display_name)
                            if val is None or (isinstance(val, float) and pd.isna(val)):
                                continue  # NULL 值不更新（保持原值）
                            val_str = str(val)
                            cases.append("WHEN %s THEN %s")
                            params.append(int(row_id))
                            params.append(val_str)

                        if cases:
                            case_clause = " ".join(cases)
                            sql = (
                                f"UPDATE `{table}` SET `{display_name}` = "
                                f"CASE `_row_id` {case_clause} "
                                f"ELSE `{display_name}` END"
                            )
                            # 分批执行，每批 500 个 WHEN 避免 SQL 过长
                            batch_size = 500
                            for i in range(0, len(cases), batch_size):
                                batch_cases = cases[i:i + batch_size]
                                batch_params = params[i * 2:(i + batch_size) * 2]
                                batch_clause = " ".join(batch_cases)
                                batch_sql = (
                                    f"UPDATE `{table}` SET `{display_name}` = "
                                    f"CASE `_row_id` {batch_clause} "
                                    f"ELSE `{display_name}` END"
                                )
                                with conn.cursor() as cur:
                                    cur.execute(batch_sql, batch_params)
                            updated = len(cases)
                    except Exception as e:
                        logger.warning(
                            f"[FormulaBackfill] 更新列 `{display_name}` 失败: {e}"
                        )
                total_updated += updated

            offset += len(rows)

        logger.info(
            f"[FormulaBackfill] 完成: {len(missing_formula_cols)} 个公式列, "
            f"共更新 {total_updated} 行"
        )

    def _build_composite_id_column(self, report: ReportDefinition,
                                   progress_callback=None):
        """如果配置了 sync_id_fields，在结果表中追加拼接 ID 列供预览。"""
        id_fields = getattr(report, 'sync_id_fields', None) or []
        logger.debug(f"[CompositeID] sync_id_fields={id_fields}")
        if not id_fields:
            return
        separator = getattr(report, 'sync_id_separator', '_') or '_'
        table = report.result_table
        logger.debug(f"[CompositeID] 结果表={table}, 分隔符='{separator}'")
        if not self._db.table_exists(table):
            logger.debug(f"[CompositeID] 跳过：表 {table} 不存在")
            return

        col_name = "唯一ID"

        # 获取结果表实际列名
        try:
            db_cols = set()
            cols_info = self._db.execute(f"SHOW COLUMNS FROM `{table}`")
            if cols_info:
                db_cols = {r['Field'] for r in cols_info}
        except Exception as e:
            logger.warning(f"[CompositeID] 获取列信息失败: {e}")
            return

        logger.debug(f"[CompositeID] 结果表列名({len(db_cols)}): {sorted(db_cols)}")

        # 验证 ID 字段在结果表中存在
        valid_fields = [f for f in id_fields if f in db_cols]
        if not valid_fields:
            missing = [f for f in id_fields if f not in db_cols]
            logger.warning(f"[CompositeID] ID 字段在结果表中不存在: {id_fields}, 缺失: {missing}")
            return

        if progress_callback:
            progress_callback('composite_id', f"正在生成拼接 ID 列...", 87)

        try:
            # 添加列（如不存在）
            if col_name not in db_cols:
                self._db.execute(f"ALTER TABLE `{table}` ADD COLUMN `{col_name}` LONGTEXT")

            # 用 CONCAT_WS 生成拼接值
            concat_parts = ', '.join(f'`{f}`' for f in valid_fields)
            sql = f"UPDATE `{table}` SET `{col_name}` = CONCAT_WS('{separator}', {concat_parts})"
            self._db.execute(sql)
            logger.info(f"[CompositeID] 已生成 '{col_name}' 列: {len(valid_fields)} 字段, 分隔符='{separator}'")
        except Exception as e:
            logger.error(f"[CompositeID] 生成失败: {e}")


# -- custom_report/utils.py --
"""
工具函数

字段标签映射、类型推断、名称清理等
"""

import re
import json
from decimal import Decimal
from datetime import datetime, date
from typing import Optional


# ==================== JSON 序列化辅助 ====================

def json_dumps_safe(obj, **kwargs) -> str:
    """安全的 json.dumps，自动转换 Decimal/datetime 等非标准类型"""
    def _default(o):
        if isinstance(o, Decimal):
            return float(o)
        if isinstance(o, (datetime, date)):
            return str(o)
        if isinstance(o, bytes):
            return o.decode('utf-8', errors='replace')
        raise TypeError(f'Object of type {o.__class__.__name__} is not JSON serializable')
    return json.dumps(obj, default=_default, **kwargs)


# ==================== 字段标签映射 ====================

_COMMON_FIELD_LABELS = {
    '_id': '数据ID',
    'id': 'ID',
    'name': '名称',
    'create_time': '创建时间',
    'submit_time': '提交时间',
    'last_modified_time': '最后修改时间',
    'created_by': '创建人ID',
    'created_by__r': '创建人',
    'created_by_name': '创建人',
    'owner': '负责人ID',
    'owner__r': '负责人',
    'owner_name': '负责人',
    'account_id': '客户ID',
    'account_id__r': '客户名称',
    'contact_id': '联系人ID',
    'contact_id__r': '客户联系人',
    'record_type': '业务类型',
    'life_status': '生命状态',
    'remark': '备注',
    'description': '描述',
    'amount': '金额',
    'price': '单价',
    'quantity': '数量',
    'status': '状态',
    'stage': '阶段',
    'source': '来源',
    'mobile': '手机',
    'phone': '电话',
    'address': '地址',
    'code': '编码',
    'number': '编号',
    'date': '日期',
    'time': '时间',
    'type': '类型',
}


def guess_field_label(field_name: str) -> str:
    """根据 API 字段名猜测中文显示名"""
    field_name = str(field_name or '').strip()
    if not field_name:
        return ''

    # 精确匹配
    if field_name in _COMMON_FIELD_LABELS:
        return _COMMON_FIELD_LABELS[field_name]

    # 去掉后缀
    normalized = field_name
    for suffix in ('__r', '__c'):
        if normalized.endswith(suffix):
            normalized = normalized[:-len(suffix)]

    # 关键词匹配
    keyword_map = [
        ('create', '创建'), ('modified', '修改'), ('submit', '提交'),
        ('owner', '负责人'), ('account', '客户'), ('customer', '客户'),
        ('contact', '联系人'), ('mobile', '手机'), ('phone', '电话'),
        ('address', '地址'), ('amount', '金额'), ('price', '价格'),
        ('quantity', '数量'), ('status', '状态'), ('stage', '阶段'),
        ('source', '来源'), ('remark', '备注'), ('description', '描述'),
        ('date', '日期'), ('time', '时间'), ('type', '类型'), ('name', '名称'),
        ('code', '编码'), ('number', '编号'), ('delivery', '发货'),
        ('product', '产品'), ('order', '订单'), ('project', '项目'),
    ]
    lower = normalized.lower()
    for kw, label in keyword_map:
        if kw in lower:
            return label

    if field_name.startswith('field_'):
        return f"自定义字段({field_name})"

    return field_name


def build_field_labels(field_names: list[str],
                       object_labels: dict = None,
                       custom_config: dict = None) -> dict[str, str]:
    """
    为一组字段名构建中文标签映射

    Args:
        field_names: API 字段名列表
        object_labels: 对象特定的标签映射 {(key: label)}
        custom_config: 用户自定义的标签映射

    Returns:
        {field_name: display_label}
    """
    result = {}
    label_usage = {}  # 检测重复标签

    for key in field_names:
        # 优先级: 自定义 > 对象特定 > 通用猜测
        if custom_config and key in custom_config:
            label = custom_config[key]
        elif object_labels and key in object_labels:
            label = object_labels[key]
        else:
            label = guess_field_label(key)

        # 去重处理
        if label in label_usage:
            label_usage[label] += 1
            result[key] = f"{label}({key})"
        else:
            label_usage[label] = 1
            result[key] = label

    return result


# ==================== 名称清理 ====================

_SAFE_IDENT_RE = re.compile(r'^[a-zA-Z0-9_-]+$')


def safe_sql_ident(name: str) -> str:
    """检查 SQL 标识符是否安全"""
    if not _SAFE_IDENT_RE.match(name):
        raise ValueError(f"非法的 SQL 标识符: {name}")
    return name


def safe_table_name(name: str) -> str:
    """清理表名，只保留安全字符"""
    return re.sub(r'[^a-zA-Z0-9_-]', '_', name)


# ==================== 时间戳转换 ====================

def ts_to_datetime(ts_value) -> Optional[str]:
    """Unix 毫秒时间戳 → yyyy-mm-dd HH:MM:SS"""
    if ts_value is None:
        return None
    try:
        from datetime import datetime
        ts = float(ts_value)
        if ts <= 0:
            return str(ts_value)
        if ts > 1e14:
            ts = ts / 1000000
        elif ts > 1e11:
            ts = ts / 1000
        dt = datetime.fromtimestamp(ts)
        return dt.strftime('%Y-%m-%d %H:%M:%S')
    except (ValueError, OSError, OverflowError):
        return str(ts_value)


def date_str_to_ts(date_str: str, end_of_day: bool = False) -> int:
    """yyyy-mm-dd → Unix 毫秒时间戳"""
    from datetime import datetime
    try:
        dt = datetime.strptime(date_str.strip(), '%Y-%m-%d')
        if end_of_day:
            dt = dt.replace(hour=23, minute=59, second=59)
        return int(dt.timestamp() * 1000)
    except Exception:
        return 0


