# -- custom_report/dashboard/dashboard_list_page.py --
"""
仪表盘列表页

显示所有已保存的仪表盘，支持搜索、CRUD、导入/导出 JSON。
"""

import json
import os
from datetime import datetime

from PyQt6.QtWidgets import (
    QWidget, QVBoxLayout, QHBoxLayout, QGroupBox, QTableWidget,
    QTableWidgetItem, QHeaderView, QPushButton, QLineEdit,
    QLabel, QComboBox, QMenu, QFileDialog, QMessageBox,
    QAbstractItemView,
)
from PyQt6.QtCore import Qt, pyqtSignal
from PyQt6.QtGui import QAction, QFont


PAGE_SIZES = [20, 50, 100]


class DashboardListPage(QWidget):
    """仪表盘列表管理页"""

    viewRequested = pyqtSignal(str)      # dashboard_id
    editRequested = pyqtSignal(str)      # dashboard_id
    newDashboard = pyqtSignal()          # 新建空白仪表盘

    def __init__(self, repo, parent=None):
        """
        Args:
            repo: DashboardRepository 实例
        """
        super().__init__(parent)
        self._repo = repo
        self._all_dashboards: list[DashboardDefinition] = []
        self._current_page = 1
        self._page_size = 20
        self._setup_ui()

    def _setup_ui(self):
        layout = QVBoxLayout(self)
        layout.setContentsMargins(16, 16, 16, 16)
        layout.setSpacing(8)

        # 标题组
        group = QGroupBox("BI 仪表盘")
        group.setStyleSheet("QGroupBox { font-size: 16px; font-weight: bold; border: none; }")
        gl = QVBoxLayout(group)

        # 操作栏
        action_bar = QHBoxLayout()
        self._search_input = QLineEdit()
        self._search_input.setPlaceholderText("🔍 搜索仪表盘名称...")
        self._search_input.setClearButtonEnabled(True)
        self._search_input.setFixedWidth(260)
        self._search_input.returnPressed.connect(self._on_search)
        action_bar.addWidget(self._search_input)

        refresh_btn = QPushButton("刷新")
        refresh_btn.clicked.connect(self.refresh)
        refresh_btn.setFixedHeight(28)
        action_bar.addWidget(refresh_btn)

        action_bar.addStretch()

        import_btn = QPushButton("📤 导入 JSON / PBIX")
        import_btn.clicked.connect(self._on_import_file)
        import_btn.setFixedHeight(28)
        action_bar.addWidget(import_btn)

        export_btn = QPushButton("📥 导出 JSON")
        export_btn.clicked.connect(self._on_export_selected)
        export_btn.setFixedHeight(28)
        action_bar.addWidget(export_btn)

        new_btn = QPushButton("+ 新建仪表盘")
        new_btn.clicked.connect(self.newDashboard.emit)
        new_btn.setFixedHeight(28)
        new_btn.setStyleSheet("QPushButton { background: #FF8C00; color: #FFF; border-radius: 4px; font-weight: bold; } QPushButton:hover { background: #FFA940; }")
        action_bar.addWidget(new_btn)
        gl.addLayout(action_bar)

        # 表格
        self._table = QTableWidget()
        self._table.setColumnCount(5)
        self._table.setHorizontalHeaderLabels(["名称", "图表数", "数据源", "修改时间", "操作"])
        install_autofilter_header(self._table)
        header = self._table.horizontalHeader()
        header.setStretchLastSection(False)
        header.setMinimumSectionSize(30)
        # 所有列设为 Interactive：用户可拖拽调整，不强制拉伸铺满表格
        for c in range(5):
            header.setSectionResizeMode(c, QHeaderView.ResizeMode.Interactive)
        # 默认列宽（总宽约 700px；超出部分留白，不强制铺满）
        self._table.setColumnWidth(0, 28)
        self._table.setColumnWidth(1, 200)
        self._table.setColumnWidth(2, 60)
        self._table.setColumnWidth(3, 180)
        self._table.setColumnWidth(4, 140)
        self._table.setColumnWidth(5, 160)
        # 不自动调整大小以适应内容，让用户自定义的列宽始终生效
        self._table.setSizeAdjustPolicy(
            self._table.sizeAdjustPolicy().AdjustToContentsOnFirstShow
        )
        # 显式启用水平滚动条（列宽总和超出视口时出现）
        self._table.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
        self._table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectItems)
        self._table.setSelectionMode(QAbstractItemView.SelectionMode.SingleSelection)
        self._table.setEditTriggers(QAbstractItemView.EditTrigger.NoEditTriggers)
        self._table.setAlternatingRowColors(True)
        self._table.verticalHeader().setVisible(False)
        self._table.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self._table.customContextMenuRequested.connect(self._on_context_menu)
        self._table.doubleClicked.connect(self._on_double_click)
        # QSS 样式表已删除，与订单转合同表格保持完全一致，让 Qt 默认渲染
        gl.addWidget(self._table)

        # 分页栏
        page_bar = QHBoxLayout()
        self._record_label = QLabel("共 0 个仪表盘")
        page_bar.addWidget(self._record_label)
        page_bar.addStretch()

        page_bar.addWidget(QLabel("每页:"))
        page_size_combo = QComboBox()
        page_size_combo.addItems([str(s) for s in PAGE_SIZES])
        page_size_combo.setCurrentText("20")
        page_size_combo.setFixedWidth(65)
        page_size_combo.currentTextChanged.connect(self._on_page_size_changed)
        page_bar.addWidget(page_size_combo)

        prev_btn = QPushButton("◀")
        prev_btn.setFixedSize(32, 28)
        prev_btn.clicked.connect(self._prev_page)
        page_bar.addWidget(prev_btn)

        self._page_label = QLabel("1")
        page_bar.addWidget(self._page_label)

        next_btn = QPushButton("▶")
        next_btn.setFixedSize(32, 28)
        next_btn.clicked.connect(self._next_page)
        page_bar.addWidget(next_btn)
        gl.addLayout(page_bar)

        layout.addWidget(group)

    def refresh(self, search: str = None):
        """刷新列表"""
        self._all_dashboards = self._repo.list_all(search=search)
        self._current_page = 1
        self._populate()

    def _populate(self):
        """填充表格"""
        total = len(self._all_dashboards)
        start = (self._current_page - 1) * self._page_size
        end = start + self._page_size
        page_items = self._all_dashboards[start:end]

        self._table.setRowCount(len(page_items))
        for i, dashboard in enumerate(page_items):
            self._table.setRowHeight(i, 40)

            # 名称
            name_item = QTableWidgetItem(dashboard.name)
            name_item.setData(Qt.ItemDataRole.UserRole, dashboard.id)
            self._table.setItem(i, 0, name_item)

            # 图表数
            chart_count = len(dashboard.charts) if dashboard.charts else 0
            self._table.setItem(i, 1, QTableWidgetItem(str(chart_count)))

            # 数据源（汇总）
            sources = set()
            for chart in (dashboard.charts or []):
                if chart.data_source_name:
                    sources.add(chart.data_source_name)
            self._table.setItem(i, 2, QTableWidgetItem("、".join(sources) if sources else "—"))

            # 修改时间
            self._table.setItem(i, 3, QTableWidgetItem(dashboard.modified_at or "—"))

            # 操作按钮
            op_widget = QWidget()
            op_layout = QHBoxLayout(op_widget)
            op_layout.setContentsMargins(2, 2, 2, 2)
            op_layout.setSpacing(4)

            view_btn = QPushButton("👁 查看")
            view_btn.setFixedHeight(24)
            view_btn.clicked.connect(lambda checked, did=dashboard.id: self.viewRequested.emit(did))
            op_layout.addWidget(view_btn)

            edit_btn = QPushButton("✏️ 编辑")
            edit_btn.setFixedHeight(24)
            edit_btn.clicked.connect(lambda checked, did=dashboard.id: self.editRequested.emit(did))
            op_layout.addWidget(edit_btn)
            self._table.setCellWidget(i, 4, op_widget)

        self._record_label.setText(f"共 {total} 个仪表盘")
        total_pages = max(1, (total + self._page_size - 1) // self._page_size)
        self._page_label.setText(f"{self._current_page} / {total_pages}")

    def _on_search(self):
        text = self._search_input.text()
        self.refresh(search=text if text else None)

    def _on_double_click(self, index):
        item = self._table.item(index.row(), 0)
        if item:
            dashboard_id = item.data(Qt.ItemDataRole.UserRole)
            self.viewRequested.emit(dashboard_id)

    def _on_context_menu(self, pos):
        """右键菜单"""
        item = self._table.itemAt(pos)
        if not item:
            return
        row = item.row()
        name_item = self._table.item(row, 1)
        if not name_item:
            return
        dashboard_id = name_item.data(Qt.ItemDataRole.UserRole)
        if not dashboard_id:
            return

        menu = QMenu(self)
        menu.setStyleSheet("QMenu { background: #FFF; border: 1px solid #D9D9D9; } QMenu::item { padding: 6px 24px; } QMenu::item:hover { background: #FFF7E6; }")

        menu.addAction("👁 查看", lambda: self.viewRequested.emit(dashboard_id))
        menu.addAction("✏️ 编辑", lambda: self.editRequested.emit(dashboard_id))
        menu.addSeparator()
        menu.addAction("📋 复制", lambda: self._on_duplicate(dashboard_id))
        menu.addAction("✏️ 重命名", lambda: self._on_rename(dashboard_id))
        menu.addAction("📥 导出 JSON", lambda: self._export_dashboard(dashboard_id))
        menu.addSeparator()
        delete_action = QAction("🗑 删除")
        delete_action.triggered.connect(lambda: self._on_delete(dashboard_id))
        menu.addAction(delete_action)

        menu.exec(self._table.viewport().mapToGlobal(pos))

    def _on_import_file(self):
        """统一导入：JSON 仪表盘 / PBIX 元数据 / PBIT 模板"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "导入文件", "",
            "支持格式 (*.json *.pbix *.pbit);;JSON 文件 (*.json);;Power BI (*.pbix *.pbit);;所有文件 (*.*)"
        )
        if not file_path:
            return
        ext = os.path.splitext(file_path)[1].lower()
        if ext in ('.pbix', '.pbit'):
            self._do_import_pbix(file_path)
        else:
            self._do_import_json(file_path)

    def _do_import_json(self, file_path: str):
        """导入 JSON 仪表盘"""
        try:
            # 先读字节，自动处理 UTF-8 BOM
            with open(file_path, 'rb') as f:
                raw = f.read()
            if raw.startswith(b'\xef\xbb\xbf'):
                raw = raw[3:]  # 去掉 UTF-8 BOM
            data = json.loads(raw.decode('utf-8'))
            items = []
            if isinstance(data, list):
                items = data
            elif isinstance(data, dict):
                if 'dashboards' in data:
                    items = list(data['dashboards'].values()) if isinstance(data['dashboards'], dict) else data['dashboards']
                elif 'charts' in data or 'name' in data:
                    items = [data]
            if not items:
                print("[BI 报表] 导入失败: JSON 格式不正确")
                return
            count = 0
            for ddata in items:
                if not isinstance(ddata, dict):
                    continue
                dashboard = DashboardDefinition.from_dict(ddata)
                if not dashboard.name.endswith(" (导入)"):
                    dashboard.name += " (导入)"
                dashboard.id = _new_id(12)
                self._repo.save(dashboard)
                count += 1
            self.refresh()
            print(f"[BI 报表] 成功导入 {count} 个仪表盘")
        except Exception as e:
            print(f"[BI 报表] JSON 导入失败: {e}")

    def _do_import_pbix(self, file_path: str):
        """导入 .pbix / .pbit 文件，直接生成仪表盘图表"""
        try:
            ext = os.path.splitext(file_path)[1].lower()
            kind = 'PBIT 模板' if ext == '.pbit' else 'PBIX'
            print(f"[BI 报表] 正在导入 {kind}: {file_path}")
            result = extract_to_dashboard(file_path)
            if not result['success'] or not result.get('dashboard') or not result['dashboard'].charts:
                print(f"[BI 报表] 生成仪表盘失败: {result.get('error', '无图表')}，回退到元数据提取")
                meta = extract_metadata(file_path)
                if meta['success']:
                    _print_pbix_meta(meta)
                    _show_pbix_meta_panel(meta)
                return
            dashboard = result['dashboard']
            self._repo.save(dashboard)
            self.refresh()
            print(f"[BI 报表] 已生成仪表盘「{dashboard.name}」({len(dashboard.charts)} 个图表)")
            print("[BI 报表] 💡 提示: 每个图表需手动选择数据源（字段映射已自动填充）")
            # 打开仪表盘编辑
            self.editRequested.emit(dashboard.id)
        except Exception as e:
            print(f"[BI 报表] PBIX/PBIT 导入失败: {e}")

    def _on_export_selected(self):
        selected = self._get_selected_id()
        if not selected:
            frameless_message_box(self, "提示", "请先在表格中单击选中一个仪表盘")
            return
        dashboard = self._repo.get(selected)
        if not dashboard:
            frameless_message_box(self, "导出失败", "未找到该仪表盘")
            return

        file_path, _ = QFileDialog.getSaveFileName(
            self, "导出仪表盘 JSON", f"{dashboard.name}.json",
            "JSON 文件 (*.json);;所有文件 (*.*)"
        )
        if not file_path:
            return
        try:
            export_data = {'dashboards': {dashboard.id: dashboard.to_dict()}}
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(export_data, f, ensure_ascii=False, indent=2)
            print(f"[BI 报表] 已导出: {file_path}")
            frameless_message_box(self, "导出成功", f"仪表盘已导出到:\n{file_path}")
        except Exception as e:
            frameless_message_box(self, "导出失败", str(e))
            print(f"[BI 报表] 导出失败: {e}")

    def _export_dashboard(self, dashboard_id: str):
        """导出指定仪表盘为 JSON 文件"""
        dashboard = self._repo.get(dashboard_id)
        if not dashboard:
            frameless_message_box(self, "导出失败", "未找到该仪表盘")
            return
        file_path, _ = QFileDialog.getSaveFileName(
            self, "导出仪表盘 JSON", f"{dashboard.name}.json",
            "JSON 文件 (*.json);;所有文件 (*.*)"
        )
        if not file_path:
            return
        try:
            export_data = {'dashboards': {dashboard.id: dashboard.to_dict()}}
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(export_data, f, ensure_ascii=False, indent=2)
            print(f"[BI 报表] 已导出: {file_path}")
            frameless_message_box(self, "导出成功", f"仪表盘已导出到:\n{file_path}")
        except Exception as e:
            frameless_message_box(self, "导出失败", str(e))
            print(f"[BI 报表] 导出失败: {e}")

    def _on_duplicate(self, dashboard_id: str):
        dashboard = self._repo.get(dashboard_id)
        if dashboard:
            new_name = f"{dashboard.name} (副本)"
            new_db = self._repo.duplicate(dashboard_id, new_name)
            if new_db:
                self.refresh()
                print(f"[BI 报表] 已创建副本: {new_name}")

    def _on_rename(self, dashboard_id: str):
        dashboard = self._repo.get(dashboard_id)
        if dashboard:
            from common import frameless_input_text
            new_name, ok = frameless_input_text(
                self, "重命名", "新名称:", default_text=dashboard.name
            )
            if ok and new_name.strip():
                dashboard.name = new_name.strip()
                self._repo.save(dashboard)
                self.refresh()

    def _on_delete(self, dashboard_id: str):
        dashboard = self._repo.get(dashboard_id)
        if dashboard:
            self._repo.delete(dashboard_id)
            self.refresh()
            print(f"[BI 报表] 仪表盘已删除: {dashboard.name}")

    def _get_selected_id(self) -> str:
        rows = self._table.selectionModel().selectedRows()
        if rows:
            item = self._table.item(rows[0].row(), 0)
            if item:
                return item.data(Qt.ItemDataRole.UserRole)
        return ""

    def _prev_page(self):
        if self._current_page > 1:
            self._current_page -= 1
            self._populate()

    def _next_page(self):
        total = len(self._all_dashboards)
        total_pages = max(1, (total + self._page_size - 1) // self._page_size)
        if self._current_page < total_pages:
            self._current_page += 1
            self._populate()

    def _on_page_size_changed(self, text: str):
        self._page_size = int(text)
        self._current_page = 1
        self._populate()

    def set_repo(self, repo):
        """更新 repo 引用"""
        self._repo = repo


def _save_meta_txt(meta: dict, file_path: str):
    """保存 PBIX 元数据到 txt 文件"""
    lines = [f"PBIX 元数据: {meta['report_name']}", f"页面数: {len(meta.get('pages', []))}  |  字段: {len(meta.get('fields', []))} 个  |  表: {len(meta.get('tables', []))} 个", ""]
    if meta.get('tables'):
        lines.append(f"数据表: {', '.join(meta['tables'])}")
        lines.append("")
    for page in meta.get('pages', []):
        lines.append(f"{'='*60}")
        lines.append(f"📄 {page['name']} ({len(page['visuals'])} 个图表)")
        lines.append(f"{'='*60}")
        for v in page['visuals']:
            fields_str = f" [{', '.join(v['fields'])}]" if v.get('fields') else ''
            lines.append(f"  📊 {v['name']}  →  {v['type']}{fields_str}")
        lines.append("")
    if meta.get('fields'):
        lines.append(f"所有引用字段 ({len(meta['fields'])} 个):")
        for f in meta['fields']:
            lines.append(f"  • {f}")
    with open(file_path, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))


def _print_pbix_meta(meta: dict):
    """输出 PBIX 元数据到运行时窗口"""
    lines = [f"[BI 报表] ====== PBIX 元数据: {meta['report_name']} ======"]
    lines.append(f"[BI 报表] 页面数: {len(meta.get('pages', []))}  |  字段: {len(meta.get('fields', []))} 个  |  表: {len(meta.get('tables', []))} 个")
    if meta.get('tables'):
        lines.append(f"[BI 报表] 数据表: {', '.join(meta['tables'][:15])}")
    for page in meta.get('pages', []):
        lines.append(f"[BI 报表] --- 📄 {page['name']} ({len(page['visuals'])} 个图表) ---")
        for v in page['visuals']:
            fields_str = f" [{', '.join(v['fields'])}]" if v.get('fields') else ''
            lines.append(f"[BI 报表]   📊 {v['name']}  →  {v['type']}{fields_str}")
    lines.append("[BI 报表] ====== PBIX 提取完成，可在悬浮窗口查看详情 ======")
    for line in lines:
        print(line)


def _show_pbix_meta_panel(meta: dict):
    """小型非模态悬浮窗口显示 PBIX 元数据"""
    from PyQt6.QtWidgets import QFrame, QTextEdit
    from PyQt6.QtCore import Qt as QtCore
    from PyQt6.QtGui import QFont

    panel = QFrame(None, QtCore.WindowType.Tool | QtCore.WindowType.WindowStaysOnTopHint)
    panel.setWindowTitle(f"📊 PBIX: {meta['report_name']}")
    panel.setMinimumSize(420, 360)
    panel.resize(460, 420)
    panel.setStyleSheet("QFrame { background: #FFF; border: 1px solid #D9D9D9; }")

    layout = QVBoxLayout(panel)
    layout.setContentsMargins(8, 8, 8, 8)

    info = QLabel(f"<b>{meta['report_name']}</b> — {len(meta.get('pages',[]))}页 {len(meta.get('fields',[]))}字段 "
                  f"{'| 表: '+', '.join(meta.get('tables',[])[:8]) if meta.get('tables') else ''}")
    info.setWordWrap(True)
    info.setStyleSheet("color:#666;font-size:12px;padding:4px;")
    layout.addWidget(info)

    edit = QTextEdit()
    edit.setReadOnly(True)
    edit.setFont(QFont("Microsoft YaHei", 11))
    edit.setStyleSheet("QTextEdit { background: #FAFAFA; border: 1px solid #E8E8E8; border-radius: 4px; }")

    text_lines = []
    for page in meta.get('pages', []):
        text_lines.append(f"\n{'─'*50}")
        text_lines.append(f"📄 {page['name']}  ({len(page['visuals'])} 个图表)")
        text_lines.append(f"{'─'*50}")
        for v in page['visuals']:
            text_lines.append(f"  📊 {v['name']}")
            text_lines.append(f"     类型: {v['type']}")
            if v.get('fields'):
                text_lines.append(f"     字段: {', '.join(v['fields'])}")
            text_lines.append("")
    edit.setPlainText('\n'.join(text_lines))
    layout.addWidget(edit)

    panel.show()


# -- custom_report/dashboard/dashboard_view_page.py --
"""
仪表盘查看页

只读展示模式 + 全屏 + 导出。
用户看到的是 QWebEngineView 渲染的 ECharts 仪表盘。
"""

import os
import json
import base64
import logging
from io import BytesIO

from PyQt6.QtWidgets import (
    QWidget, QVBoxLayout, QHBoxLayout, QLabel, QPushButton,
    QMenu, QFileDialog, QMessageBox, QFrame, QComboBox,
)
from PyQt6.QtCore import Qt, pyqtSignal, QUrl, QTimer
from PyQt6.QtWebEngineWidgets import QWebEngineView
from PyQt6.QtWebEngineCore import QWebEnginePage, QWebEngineProfile
from PyQt6.QtWebChannel import QWebChannel
from PyQt6.QtGui import QColor

# pd 已在文件顶部延迟导入（_LazyPd 代理），此处无需重复 import


class DashboardViewPage(QWidget):
    """仪表盘查看页（只读）"""

    backRequested = pyqtSignal()
    editRequested = pyqtSignal(str)  # dashboard_id
    dataRefreshRequested = pyqtSignal(str)  # dashboard_id

    def __init__(self, bridge: DashboardBridge = None, parent=None):
        super().__init__(parent)
        self._dashboard = None   # DashboardDefinition
        self._data_map = {}      # {chart_id: [rows]}
        self._bridge = bridge or DashboardBridge(self)
        self._fullscreen = False
        self._setup_ui()
        self.setStyleSheet("QToolTip { background-color: #FFFFFF; color: #333333; border: 1px solid #D9D9D9; border-radius: 4px; padding: 4px 6px; }")

    def _setup_ui(self):
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(0)

        # ===== 工具栏 =====
        toolbar = QFrame()
        toolbar.setFixedHeight(40)
        toolbar.setStyleSheet("QFrame { background: #FAFAFA; border-bottom: 1px solid #E8E8E8; }")
        tb_layout = QHBoxLayout(toolbar)
        tb_layout.setContentsMargins(12, 4, 12, 4)

        back_btn = QPushButton("← 返回")
        back_btn.clicked.connect(self.backRequested.emit)
        back_btn.setFixedHeight(28)
        tb_layout.addWidget(back_btn)

        self._title_label = QLabel("仪表盘")
        self._title_label.setStyleSheet("font-size: 15px; font-weight: bold; color: #333;")
        tb_layout.addWidget(self._title_label)

        tb_layout.addStretch()

        refresh_btn = QPushButton("🔄 刷新")
        refresh_btn.setToolTip("重新查询数据")
        refresh_btn.setFixedHeight(28)
        refresh_btn.clicked.connect(lambda: self.dataRefreshRequested.emit(
            self._dashboard.id if self._dashboard else ""))
        tb_layout.addWidget(refresh_btn)

        # 导出下拉菜单
        export_btn = QPushButton("📤 导出 ▼")
        export_btn.setFixedHeight(28)
        export_menu = QMenu(export_btn)
        export_menu.addAction("🖼 导出 PNG 图片", self._export_png)
        export_menu.addAction("📄 导出 PDF 文件", self._export_pdf)
        export_menu.addAction("📊 导出 Excel 数据", self._export_excel)
        export_menu.addAction("🌐 导出 HTML 文件", self._export_html)
        export_btn.setMenu(export_menu)
        tb_layout.addWidget(export_btn)

        edit_btn = QPushButton("✏️ 编辑")
        edit_btn.setFixedHeight(28)
        edit_btn.clicked.connect(lambda: self.editRequested.emit(
            self._dashboard.id if self._dashboard else ""))
        tb_layout.addWidget(edit_btn)

        self._fullscreen_btn = QPushButton("⛶ 全屏")
        self._fullscreen_btn.setFixedHeight(28)
        self._fullscreen_btn.clicked.connect(self._toggle_fullscreen)
        tb_layout.addWidget(self._fullscreen_btn)

        layout.addWidget(toolbar)

        # ===== WebView =====
        self._webview = QWebEngineView()
        self._webview.setStyleSheet("background: #F0F2F5;")
        self._webview.page().setBackgroundColor(QColor("#F0F2F5"))
        self._webview.setContextMenuPolicy(Qt.ContextMenuPolicy.NoContextMenu)
        layout.addWidget(self._webview, 1)

        # 设置 QWebChannel
        self._channel = QWebChannel(self._webview.page())
        self._channel.registerObject("bridge", self._bridge)
        self._webview.page().setWebChannel(self._channel)
        self._bridge.set_page(self._webview.page())
        self._bridge.actionReceived.connect(self._on_js_action)

    def load_dashboard(self, dashboard, data_map: dict[str, list] = None):
        """
        加载仪表盘进行渲染

        Args:
            dashboard: DashboardDefinition 对象
            data_map: {chart_id: [{col: val}, ...]} 聚合数据
        """
        self._dashboard = dashboard
        self._data_map = data_map or {}
        self._title_label.setText(dashboard.name)

        # 构建 HTML
        echarts_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'echarts')
        html = self._build_html_with_data(dashboard, self._data_map, echarts_dir)

        # 加载
        base_url = QUrl.fromLocalFile(echarts_dir)
        self._webview.setHtml(html, base_url)

    def _build_html_with_data(self, dashboard, data_map: dict, echarts_dir: str = '') -> str:
        """构建包含内嵌数据的 HTML"""
        html = build_dashboard_html(dashboard.to_dict(), use_cdn=False, embed_data=True, echarts_dir=echarts_dir)

        # 嵌入中国地图 GeoJSON + 数据
        inject_parts = []
        china_path = os.path.join(echarts_dir, 'china.json') if echarts_dir else ''
        if china_path and os.path.exists(china_path):
            with open(china_path, 'r', encoding='utf-8') as f:
                china_json = f.read()
            inject_parts.append(f'<script>window._CHINA_GEO = {china_json};</script>')
        data_json = json_dumps_safe(data_map, ensure_ascii=False)
        inject_parts.append(f"<script>window._INITIAL_DATA = {data_json};</script>")
        html = html.replace('</body>', '\n'.join(inject_parts) + '\n</body>')

        return html

    def refresh_data(self, data_map: dict[str, list]):
        """刷新数据（不重载整个页面）"""
        self._data_map = data_map
        self._bridge.inject_all_data(data_map)

    def _on_js_action(self, action: str, payload_json: str):
        payload = parse_action_payload(payload_json)

        if action == "page_ready":
            # 数据已通过 _INITIAL_DATA 嵌入 HTML，无需重复注入
            pass
        elif action == "chart_clicked":
            pass  # 交叉筛选在 JS 端完成
        elif action == "change_query":
            # 筛选条件变更，需要重查数据库
            if self._dashboard:
                self.dataRefreshRequested.emit(self._dashboard.id)
        elif action == "export_ready":
            self._save_export_data(payload)

    def _save_export_data(self, payload: dict):
        """保存导出的数据"""
        if payload.get('format') == 'png':
            data = payload.get('data', '')
            if data:
                self._save_png_data(data)

    _pending_export_data = None       # 保存待导出的 base64 数据
    _pending_export_file = None       # 保存待导出的文件路径

    # ===== 导出功能 =====

    def _export_png(self):
        """请求 JS 端合成 PNG"""
        if self._dashboard:
            file_path, _ = QFileDialog.getSaveFileName(
                self, "导出 PNG 图片",
                f"{self._dashboard.name}.png",
                "PNG 图片 (*.png)"
            )
            if file_path:
                self._pending_export_file = file_path
                self._bridge.export_png()

    def _save_png_data(self, base64_data: str):
        """保存 PNG base64 数据到文件"""
        file_path = getattr(self, '_pending_export_file', None)
        if not file_path:
            return
        try:
            # 去掉可能的 data:image/png;base64, 前缀
            if ',' in base64_data:
                base64_data = base64_data.split(',', 1)[1]
            data = base64.b64decode(base64_data)
            with open(file_path, 'wb') as f:
                f.write(data)
            print(f"[BI 报表] PNG 导出成功: {file_path}")
        except Exception as e:
            print(f"[BI 报表] 导出失败: {e}")
        finally:
            self._pending_export_file = None

    def _export_pdf(self):
        """导出 PDF（QWebEnginePage 原生支持）"""
        if not self._dashboard:
            return
        file_path, _ = QFileDialog.getSaveFileName(
            self, "导出 PDF 文件",
            f"{self._dashboard.name}.pdf",
            "PDF 文件 (*.pdf)"
        )
        if file_path:
            self._webview.page().printToPdf(file_path)
            print(f"[BI 报表] PDF 导出成功: {file_path}")

    def _export_excel(self):
        """导出 Excel（每图表一个 Sheet）"""
        if not self._dashboard or not self._data_map:
            print("[BI 报表] 导出失败: 没有可导出的数据")
            return
        file_path, _ = QFileDialog.getSaveFileName(
            self, "导出 Excel 数据",
            f"{self._dashboard.name}.xlsx",
            "Excel 文件 (*.xlsx)"
        )
        if not file_path:
            return
        try:
            with pd.ExcelWriter(file_path, engine='openpyxl') as writer:
                # 汇总 Sheet
                summary_rows = []
                for chart in self._dashboard.charts:
                    rows = self._data_map.get(chart.id, [])
                    summary_rows.append({
                        '图表名称': chart.title,
                        '图表类型': chart.chart_type,
                        '数据源': chart.data_source_name,
                        '数据行数': len(rows),
                    })
                pd.DataFrame(summary_rows).to_excel(writer, sheet_name='图表汇总', index=False)

                # 每个图表数据 Sheet
                for chart in self._dashboard.charts:
                    data = self._data_map.get(chart.id, [])
                    if data:
                        df = pd.DataFrame(data)
                        sheet_name = chart.title[:31]  # Excel sheet 名最长 31 字符
                        df.to_excel(writer, sheet_name=sheet_name, index=False)

            print(f"[BI 报表] Excel 导出成功: {file_path}")
        except Exception as e:
            print(f"[BI 报表] 导出失败: {e}")

    def _export_html(self):
        """导出独立 HTML 文件"""
        if not self._dashboard:
            return
        file_path, _ = QFileDialog.getSaveFileName(
            self, "导出 HTML 文件",
            f"{self._dashboard.name}.html",
            "HTML 文件 (*.html)"
        )
        if not file_path:
            return
        try:
            # 生成使用 CDN 的独立 HTML
            data_json = json_dumps_safe(self._data_map, ensure_ascii=False)
            html = build_dashboard_html(
                self._dashboard.to_dict(),
                use_cdn=True,
                embed_data=True,
            )
            html = html.replace(
                "</body>",
                f"<script>window._INITIAL_DATA = {data_json};</script>\n</body>"
            )
            with open(file_path, 'w', encoding='utf-8') as f:
                f.write(html)
            print(f"[BI 报表] HTML 导出成功: {file_path}")
        except Exception as e:
            print(f"[BI 报表] 导出失败: {e}")

    # ===== 全屏 =====

    def _toggle_fullscreen(self):
        self._fullscreen = not self._fullscreen
        if self._fullscreen:
            self.window().showFullScreen()
            self._fullscreen_btn.setText("⛶ 退出全屏")
        else:
            self.window().showNormal()
            self._fullscreen_btn.setText("⛶ 全屏")

    def keyPressEvent(self, event):
        """ESC 退出全屏"""
        if event.key() == Qt.Key.Key_Escape and self._fullscreen:
            self._toggle_fullscreen()
        super().keyPressEvent(event)


# -- custom_report/dashboard/data_source_panel.py --
"""
数据源选择面板

在仪表盘设计器左侧显示可用数据源（自定义报表 / Excel 数据集 / MySQL 表），
双击数据源可查看字段详情，支持搜索过滤。
"""

from PyQt6.QtWidgets import (
    QWidget, QVBoxLayout, QHBoxLayout, QLabel, QLineEdit,
    QTreeWidget, QTreeWidgetItem, QPushButton, QFileDialog,
    QDialog, QDialogButtonBox, QMessageBox,
)
from PyQt6.QtCore import Qt, pyqtSignal
from PyQt6.QtGui import QFont


class DataSourcePanel(QWidget):
    """数据源选择面板"""

    # 信号
    sourceSelected = pyqtSignal(str, str, list)  # (source_type, source_id, fields)
    sourceDoubleClicked = pyqtSignal(str, str, str, list)  # (type, id, name, fields)
    tableClicked = pyqtSignal(str, str, str, list)  # 单击选中表 (type, id, name, fields)
    sourcesLoaded = pyqtSignal(dict)  # 数据源加载完成
    importExcelRequested = pyqtSignal(str)  # file_path
    importMySQLRequested = pyqtSignal()
    refreshRequested = pyqtSignal()  # 请求刷新数据源列表

    def __init__(self, parent=None):
        super().__init__(parent)
        self._data_sources = {"reports": [], "excel_datasets": [], "mysql_tables": []}
        self._field_cache = {}  # {source_type:source_id: [fields]}
        self._setup_ui()

    def _setup_ui(self):
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(4)

        self.setMinimumWidth(180)
        self.setStyleSheet(
            "font-size: 12px;"
            "QComboBox::drop-down { width: 12px; }"
            "QComboBox::down-arrow { width: 8px; height: 8px; }"
            "QToolTip { background-color: #FFFFFF; color: #333333; border: 1px solid #D9D9D9; border-radius: 4px; padding: 4px 6px; }"
        )

        # 标题行：折叠按钮 + 标题
        header_row = QHBoxLayout()
        header_row.setSpacing(4)
        self._collapse_btn = QPushButton("◀")
        self._collapse_btn.setFixedSize(22, 22)
        self._collapse_btn.setToolTip("收起/展开数据源面板")
        self._collapse_btn.setStyleSheet(
            "QPushButton { border: 1px solid #D9D9D9; border-radius: 3px; background: #FFF; font-size: 10px; }"
            "QPushButton:hover { border-color: #1890FF; }"
            "QToolTip { background-color: #FFFFFF; color: #333333; border: 1px solid #D9D9D9; border-radius: 4px; padding: 4px 6px; }"
        )
        self._collapse_btn.clicked.connect(self._toggle_collapse)
        header_row.addWidget(self._collapse_btn)
        header = QLabel("📊 数据源")
        header.setFont(QFont("Microsoft YaHei", 11, QFont.Weight.Bold))
        header_row.addWidget(header, 1)
        layout.addLayout(header_row)

        # 搜索 + 刷新 同行
        search_row = QHBoxLayout()
        search_row.setSpacing(4)
        self._search = QLineEdit()
        self._search.setPlaceholderText("🔍 搜索...")
        self._search.setClearButtonEnabled(True)
        self._search.textChanged.connect(self._on_search)
        search_row.addWidget(self._search, 1)
        refresh_btn = QPushButton("🔄")
        refresh_btn.setToolTip("刷新数据源列表（保留图表）")
        refresh_btn.clicked.connect(self.refresh_data)
        refresh_btn.setFixedHeight(26)
        refresh_btn.setFixedWidth(58)
        search_row.addWidget(refresh_btn)
        layout.addLayout(search_row)

        # 可折叠区域
        self._collapsible = QWidget()
        coll_layout = QVBoxLayout(self._collapsible)
        coll_layout.setContentsMargins(0, 0, 0, 0)
        coll_layout.setSpacing(4)

        # 树形列表
        self._tree = QTreeWidget()
        self._tree.setHeaderHidden(True)
        self._tree.setRootIsDecorated(True)
        self._tree.setIndentation(16)
        self._tree.setAnimated(True)
        self._tree.itemDoubleClicked.connect(self._on_item_double_clicked)
        self._tree.itemClicked.connect(self._on_item_clicked)
        self._tree.setStyleSheet("""
            QTreeWidget { background: #FAFAFA; border: none; font-size: 13px; }
            QTreeWidget::item { padding: 6px 4px; }
            QTreeWidget::item:hover { background: #FFF7E6; }
            QTreeWidget::item:selected { background: #FFD591; color: #333; }
        """)
        coll_layout.addWidget(self._tree, 1)

        # 导入按钮：并排一行
        import_row = QHBoxLayout()
        import_row.setSpacing(4)
        self._import_excel_btn = QPushButton("📤 Excel")
        self._import_excel_btn.clicked.connect(self._on_import_excel)
        self._import_excel_btn.setFixedHeight(28)
        import_row.addWidget(self._import_excel_btn, 1)
        self._import_mysql_btn = QPushButton("🗄️ MySQL")
        self._import_mysql_btn.clicked.connect(lambda: self.importMySQLRequested.emit())
        self._import_mysql_btn.setFixedHeight(28)
        import_row.addWidget(self._import_mysql_btn, 1)
        coll_layout.addLayout(import_row)

        layout.addWidget(self._collapsible, 1)
        self._collapsed = False

    def _toggle_collapse(self):
        self._collapsed = not self._collapsed
        self._collapsible.setVisible(not self._collapsed)
        self._collapse_btn.setText("▶" if self._collapsed else "◀")
        # 收缩时设置最小宽度，展开时恢复
        if self._collapsed:
            self.setFixedWidth(40)
        else:
            self.setMinimumWidth(180)
            self.setMaximumWidth(16777215)  # QWIDGETSIZE_MAX

    def add_mysql_table(self, name: str, row_count: int, columns: list):
        """
        动态添加一个 MySQL 表到数据源列表

        Args:
            name: 表名
            row_count: 行数
            columns: [{key, label, data_type}, ...]
        """
        # 检查是否已存在
        for t in self._data_sources.get('mysql_tables', []):
            if t.get('name') == name:
                return  # 已存在，跳过
        entry = {'name': name, 'row_count': row_count, 'columns': columns}
        self._data_sources.setdefault('mysql_tables', []).append(entry)
        key = f"mysql:{name}"
        self._field_cache[key] = columns
        self._populate_tree()

    def set_data_sources(self, sources: dict):
        """
        设置数据源列表

        Args:
            sources: {
                'reports': [{id, name, row_count, fields, table_name}],
                'excel_datasets': [{id, name, row_count, columns, table_name}],
                'mysql_tables': [{name, row_count, columns}],
            }
        """
        self._data_sources = sources
        # 缓存字段信息
        for r in sources.get('reports', []):
            key = f"report:{r['id']}"
            self._field_cache[key] = r.get('fields', [])
        for ds in sources.get('excel_datasets', []):
            key = f"excel:{ds['id']}"
            self._field_cache[key] = ds.get('columns', [])
        for t in sources.get('mysql_tables', []):
            key = f"mysql:{t['name']}"
            self._field_cache[key] = t.get('columns', [])
        self._populate_tree()
        self.sourcesLoaded.emit(sources)

    def refresh_data(self):
        """刷新数据源列表（发出信号由设计器重新查询，不清理图表数据）"""
        self.refreshRequested.emit()

    def _populate_tree(self, search: str = None):
        self._tree.clear()
        search_lower = (search or '').lower()

        sources = self._data_sources

        # 自定义报表
        reports = sources.get('reports', [])
        if reports:
            report_root = QTreeWidgetItem(["▼ 自定义报表 (%d)" % len(reports)])
            report_root.setData(0, Qt.ItemDataRole.UserRole, "section")
            report_font = QFont()
            report_font.setBold(True)
            report_root.setFont(0, report_font)
            for r in reports:
                name = r.get('name', '')
                if search_lower and search_lower not in name.lower():
                    continue
                row_count = r.get('row_count', 0)
                item = QTreeWidgetItem([f"🗂️ {name}   {row_count}行"])
                item.setData(0, Qt.ItemDataRole.UserRole, f"report:{r['id']}")
                item.setToolTip(0, f"表: {r.get('table_name', '')}\n字段: {len(r.get('fields', []))}个")
                report_root.addChild(item)
            if report_root.childCount() > 0:
                self._tree.addTopLevelItem(report_root)
                report_root.setExpanded(True)

        # Excel 数据集
        datasets = sources.get('excel_datasets', [])
        excel_root = QTreeWidgetItem(["▼ Excel 数据集 (%d)" % len(datasets)])
        excel_root.setData(0, Qt.ItemDataRole.UserRole, "section")
        excel_root.setFont(0, QFont())
        excel_root.font(0).setBold(True)
        for ds in datasets:
            name = ds.get('name', '')
            if search_lower and search_lower not in name.lower():
                continue
            row_count = ds.get('row_count', 0)
            item = QTreeWidgetItem([f"📄 {name}   {row_count}行"])
            item.setData(0, Qt.ItemDataRole.UserRole, f"excel:{ds['id']}")
            item.setToolTip(0, f"源文件: {ds.get('source_file', '')}\n字段: {len(ds.get('columns', []))}个")
            excel_root.addChild(item)
        if excel_root.childCount() > 0:
            self._tree.addTopLevelItem(excel_root)
            excel_root.setExpanded(True)

        # MySQL 表
        tables = sources.get('mysql_tables', [])
        if tables:
            mysql_root = QTreeWidgetItem(["▼ MySQL 表 (%d)" % len(tables)])
            mysql_root.setData(0, Qt.ItemDataRole.UserRole, "section")
            mysql_root.setFont(0, QFont())
            mysql_root.font(0).setBold(True)
            for t in tables:
                name = t.get('name', '')
                if search_lower and search_lower not in name.lower():
                    continue
                row_count = t.get('row_count', 0)
                item = QTreeWidgetItem([f"🗄️ {name}   {row_count}行"])
                item.setData(0, Qt.ItemDataRole.UserRole, f"mysql:{name}")
                mysql_root.addChild(item)
            if mysql_root.childCount() > 0:
                self._tree.addTopLevelItem(mysql_root)
                mysql_root.setExpanded(True)

    def _on_search(self, text: str):
        self._populate_tree(text)

    def _on_item_clicked(self, item: QTreeWidgetItem, column: int):
        """单击选中数据表，通知设计器"""
        key = item.data(0, Qt.ItemDataRole.UserRole)
        if not key or key == "section":
            return
        parts = key.split(':', 1)
        if len(parts) != 2:
            return
        source_type, source_id = parts
        fields = self._field_cache.get(key, [])
        name = item.text(0).replace('🗂️ ', '').replace('📄 ', '').replace('🗄️ ', '').rsplit('   ', 1)[0]
        self.tableClicked.emit(source_type, source_id, name, fields)

    def _on_item_double_clicked(self, item: QTreeWidgetItem, column: int):
        key = item.data(0, Qt.ItemDataRole.UserRole)
        if not key or key == "section":
            return
        parts = key.split(':', 1)
        if len(parts) != 2:
            return
        source_type, source_id = parts
        fields = self._field_cache.get(key, [])

        # 显示字段预览对话框
        dialog = _FieldPreviewDialog(source_type, source_id, fields, self)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            name = item.text(0).replace('🗂️ ', '').replace('📄 ', '').replace('🗄️ ', '').rsplit('   ', 1)[0]
            self.sourceDoubleClicked.emit(source_type, source_id, name, fields)

    def _on_import_excel(self):
        file_path, _ = QFileDialog.getOpenFileName(
            self, "导入数据文件", "",
            "数据文件 (*.xlsx *.xls *.csv *.json);;所有文件 (*.*)"
        )
        if file_path:
            self.importExcelRequested.emit(file_path)


class _FieldPreviewDialog(QDialog):
    """数据源字段预览对话框"""

    def __init__(self, source_type: str, source_id: str, fields: list, parent=None):
        super().__init__(parent)
        self.setWindowTitle("字段预览")
        self.setWindowFlags(self.windowFlags() | Qt.WindowType.FramelessWindowHint)
        self.setMinimumSize(400, 350)
        self.setStyleSheet("QDialog { background: #FAFAFA; }")

        layout = QVBoxLayout(self)

        # 标题
        type_names = {"report": "自定义报表", "excel": "Excel 数据集", "mysql": "MySQL 表"}
        type_name = type_names.get(source_type, source_type)
        layout.addWidget(QLabel(f"<b>{type_name}</b> — {source_id}"))
        layout.addWidget(QLabel(f"共 {len(fields)} 个字段:"))

        # 字段列表
        tree = QTreeWidget()
        tree.setHeaderLabels(["字段名", "类型", "建议用途"])
        for f in fields:
            if isinstance(f, dict):
                name = f.get('key') or f.get('name', '')
                dtype = f.get('data_type', 'text')
                # 推断建议用途
                if dtype in ('number', 'int64', 'float64', 'int', 'float', 'double'):
                    use = "度量（数值）"
                elif dtype in ('date', 'datetime', 'datetime64[ns]'):
                    use = "维度（时间）"
                else:
                    use = "维度（文本）"
            elif isinstance(f, (tuple, list)) and len(f) >= 2:
                name = f[0]
                dtype = 'text'
                use = "维度"
            else:
                name = str(f)
                dtype = 'text'
                use = "—"
            item = QTreeWidgetItem([name, dtype, use])
            tree.addTopLevelItem(item)
        tree.resizeColumnToContents(0)
        layout.addWidget(tree)

        # 按钮
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.accepted.connect(self.accept)
        buttons.rejected.connect(self.reject)
        layout.addWidget(buttons)


# -- custom_report/dashboard/excel_importer.py --
"""
Excel / CSV 导入器

将 Excel/CSV 文件导入为 MySQL 表，供 BI 仪表盘作为数据源使用。
"""

import os
import logging
from datetime import datetime

# pd/np 已在文件顶部延迟导入（_LazyPd/_LazyNp 代理），此处无需重复 import


logger = logging.getLogger(__name__)

# MySQL 列类型映射
_PD_TYPE_TO_MYSQL = {
    'int64': 'BIGINT',
    'int32': 'INT',
    'float64': 'DOUBLE',
    'float32': 'FLOAT',
    'bool': 'TINYINT(1)',
    'datetime64[ns]': 'DATETIME',
    'object': 'LONGTEXT',
    'string': 'VARCHAR(512)',
}

SUPPORTED_EXTENSIONS = ['.xlsx', '.xls', '.csv', '.json']


def _flatten_nested_json(data) -> pd.DataFrame:
    """将嵌套 JSON 数据自动展平为扁平 DataFrame。

    策略：
    - list[flat-dict] → 直接 DataFrame
    - list[nested-dict] → 递归展平，父级标量字段传播到子行
    - dict → 找第一个 list[dict] 字段作为主数据，其余标量作为 meta
    """

    def _is_flat(d: dict) -> bool:
        return all(isinstance(v, (str, int, float, bool, type(None))) for v in d.values())

    def _flatten_rows(rows: list, parent_prefix: str = "") -> list[dict]:
        flat = []
        for item in rows:
            if not isinstance(item, dict):
                continue
            scalar = {}
            nested_lists = {}
            used_keys = set()
            for k, v in item.items():
                col = _clean_column_name(k)
                # 去掉父级前缀，只保留叶子节点名；若冲突则加后缀
                if col in used_keys:
                    col = _clean_column_name(f"{parent_prefix}_{k}" if parent_prefix else k)
                used_keys.add(col)
                if isinstance(v, list):
                    dict_items = [x for x in v if isinstance(x, dict)]
                    if dict_items:
                        nested_lists[col] = dict_items
                    else:
                        scalar[col] = ", ".join(str(x) for x in v if x is not None)
                elif isinstance(v, dict):
                    for sk, sv in v.items():
                        sub_col = _clean_column_name(sk)
                        if sub_col in used_keys:
                            sub_col = _clean_column_name(f"{col}_{sk}")
                        used_keys.add(sub_col)
                        if isinstance(sv, (str, int, float, bool, type(None))):
                            scalar[sub_col] = sv
                        else:
                            scalar[sub_col] = str(sv)
                else:
                    scalar[col] = v
            if nested_lists:
                first_key = list(nested_lists.keys())[0]
                child_rows = _flatten_rows(nested_lists[first_key], first_key)
                for cr in child_rows:
                    flat.append({**scalar, **cr})
            else:
                flat.append(scalar)
        return flat

    if isinstance(data, list):
        if not data:
            return pd.DataFrame()
        if all(isinstance(x, dict) for x in data):
            if all(_is_flat(x) for x in data):
                return pd.DataFrame(data)
            rows = _flatten_rows(data)
            return pd.DataFrame(rows) if rows else pd.DataFrame()
        return pd.DataFrame({"value": data})

    if isinstance(data, dict):
        main_key = None
        for k, v in data.items():
            if isinstance(v, list) and v and all(isinstance(x, dict) for x in v):
                main_key = k
                break
        if main_key:
            meta = {k: v for k, v in data.items()
                    if k != main_key and isinstance(v, (str, int, float, bool, type(None)))}
            rows = data[main_key]
            if all(_is_flat(x) for x in rows):
                df = pd.DataFrame(rows)
            else:
                flat_rows = _flatten_rows(rows, main_key)
                df = pd.DataFrame(flat_rows) if flat_rows else pd.DataFrame()
            for mk, mv in meta.items():
                df[_clean_column_name(mk)] = mv
            return df
        try:
            return pd.json_normalize(data)
        except Exception:
            return pd.DataFrame([data])

    return pd.DataFrame({"value": [data]})


class ExcelImporter:
    """Excel / CSV 文件导入器"""

    def __init__(self, db):
        """
        Args:
            db: ReportDatabase 实例（用于建表 + 写入）
        """
        self._db = db

    @staticmethod
    def get_supported_formats() -> list[str]:
        return SUPPORTED_EXTENSIONS

    @staticmethod
    def preview(file_path: str, nrows: int = 50) -> dict:
        """
        预览文件前 N 行，返回 {columns: [...], rows: [...], total_rows_estimate: int}
        """
        ext = os.path.splitext(file_path)[1].lower()
        try:
            if ext == '.csv':
                df = pd.read_csv(file_path, nrows=nrows)
            elif ext == '.json':
                import json as _json
                with open(file_path, 'r', encoding='utf-8') as f:
                    raw = _json.load(f)
                df = _flatten_nested_json(raw)
                if nrows and len(df) > nrows:
                    df = df.head(nrows)
            else:
                df = pd.read_excel(file_path, nrows=nrows)
        except Exception as e:
            return {'error': str(e), 'columns': [], 'rows': [], 'total_rows_estimate': 0}

        # 推断列信息
        columns = []
        for col in df.columns:
            dtype = df[col].dtype
            col_info = {
                'key': _clean_column_name(str(col)),
                'label': str(col),
                'data_type': _infer_data_type(dtype, df[col]),
            }
            columns.append(col_info)

        # 将 DataFrame 转为 dict 列表（处理 NaN）
        rows = df.rename(columns={c: _clean_column_name(str(c)) for c in df.columns})
        rows = rows.where(pd.notnull(rows), None).to_dict(orient='records')

        return {
            'columns': columns,
            'rows': rows,
            'total_rows_estimate': len(df),
        }

    def import_file(self, file_path: str, progress_callback=None) -> ExcelDataset:
        """
        导入文件到 MySQL，返回 ExcelDataset 对象。

        Args:
            file_path: Excel/CSV 文件路径
            progress_callback: callable(percent, message)

        Returns:
            ExcelDataset 对象

        Raises:
            ValueError: 文件格式不支持或读取失败
            RuntimeError: MySQL 写入失败
        """
        ext = os.path.splitext(file_path)[1].lower()
        if ext not in SUPPORTED_EXTENSIONS:
            raise ValueError(f"不支持的格式: {ext}，支持: {', '.join(SUPPORTED_EXTENSIONS)}")

        # 1. 读取文件
        if progress_callback:
            progress_callback(10, f"读取文件: {os.path.basename(file_path)}")

        try:
            if ext == '.csv':
                df = pd.read_csv(file_path)
            elif ext == '.json':
                import json as _json
                with open(file_path, 'r', encoding='utf-8') as f:
                    raw = _json.load(f)
                df = _flatten_nested_json(raw)
            else:
                df = pd.read_excel(file_path)
        except Exception as e:
            raise ValueError(f"读取文件失败: {e}")

        if df.empty:
            raise ValueError("文件为空，无数据可导入")

        # 2. 清理列名
        rename_map = {c: _clean_column_name(str(c)) for c in df.columns}
        df = df.rename(columns=rename_map)

        # 3. 推断列信息
        columns = []
        for col in df.columns:
            dtype = df[col].dtype
            columns.append({
                'key': col,
                'label': str(col),
                'data_type': _infer_data_type(dtype, df[col]),
            })

        # 4. 创建 MySQL 表
        dataset_id = _new_id()
        table_name = f"ex_{dataset_id}"

        if progress_callback:
            progress_callback(30, f"创建 MySQL 表: {table_name}")

        if not self._db or not self._db.available:
            raise RuntimeError("MySQL 数据库未连接，无法导入")

        try:
            self._create_table(table_name, columns)
        except Exception as e:
            raise RuntimeError(f"创建表失败: {e}")

        # 5. 批量写入数据
        total_rows = len(df)
        batch_size = 500
        written = 0

        if progress_callback:
            progress_callback(40, f"写入数据: 0 / {total_rows}")

        # 处理 NaN / NaT / inf
        import numpy as np
        df = df.replace([np.nan, np.inf, -np.inf, pd.NaT], None)
        df = df.where(pd.notnull(df), None)

        for start in range(0, total_rows, batch_size):
            end = min(start + batch_size, total_rows)
            batch = df.iloc[start:end]
            rows = batch.to_dict(orient='records')

            try:
                self._db.execute_many_insert(table_name, columns, rows)
                written += len(rows)
            except Exception as e:
                raise RuntimeError(f"写入数据失败 (行 {start}-{end}): {e}")

            if progress_callback:
                pct = 40 + int((written / total_rows) * 60)
                progress_callback(pct, f"写入数据: {written} / {total_rows}")

        # 6. 创建 Dataset 对象
        dataset = ExcelDataset(
            id=dataset_id,
            name=os.path.splitext(os.path.basename(file_path))[0],
            source_file=os.path.abspath(file_path),
            file_type=ext.lstrip('.'),
            columns=columns,
            row_count=total_rows,
            mysql_table=table_name,
        )

        if progress_callback:
            progress_callback(100, "导入完成")

        logger.info(f"Excel 导入完成: {dataset.name} → {table_name} ({total_rows} 行)")
        return dataset

    def _create_table(self, table_name: str, columns: list[dict]):
        """创建 MySQL 表"""
        col_defs = []
        for col in columns:
            mysql_type = _PD_TYPE_TO_MYSQL.get(col['data_type'], 'LONGTEXT')
            col_name = _escape_identifier(col['key'])
            col_defs.append(f"`{col_name}` {mysql_type}")

        sql = (
            f"CREATE TABLE IF NOT EXISTS `{table_name}` ("
            + ", ".join(col_defs)
            + ") ENGINE=InnoDB DEFAULT CHARSET=utf8mb4"
        )
        self._db.execute(sql)

    def _insert_batch(self, table_name: str, columns: list[dict], rows: list[dict]):
        """批量插入数据（使用 executemany 优化）"""
        if not rows:
            return

        col_names = [_escape_identifier(c['key']) for c in columns]
        placeholders = ', '.join(['%s'] * len(col_names))
        sql = (
            f"INSERT INTO `{table_name}` "
            f"(`{'`, `'.join(col_names)}`) "
            f"VALUES ({placeholders})"
        )

        values = []
        for row in rows:
            row_values = []
            for col in columns:
                val = row.get(col['key'])
                if isinstance(val, (np.integer,)):
                    val = int(val)
                elif isinstance(val, (np.floating,)):
                    val = None if np.isnan(val) else float(val)
                elif isinstance(val, (np.bool_,)):
                    val = bool(val)
                elif isinstance(val, pd.Timestamp):
                    val = val.to_pydatetime()
                row_values.append(val)
            values.append(row_values)

        # 使用 pymysql executemany 直接写入（绕过 db.execute 的单条限制）
        conn = self._db._get_conn() if hasattr(self._db, '_get_conn') else None
        if conn:
            try:
                with conn.cursor() as cur:
                    cur.executemany(sql, values)
                return
            except Exception:
                pass

        # 回退：逐条插入
        for val in values:
            self._db.execute(sql, val)


def _clean_column_name(name: str) -> str:
    """清理列名：移除特殊字符，确保 MySQL 兼容"""
    import re
    # 去空格
    name = name.strip()
    # 替换中文标点为下划线
    name = name.replace('（', '_').replace('）', '').replace('（', '_').replace('）', '')
    # 替换非字母数字中文下划线为下划线
    name = re.sub(r'[^\w一-鿿]', '_', name)
    # 去连续下划线
    name = re.sub(r'_+', '_', name)
    # 去首尾下划线
    name = name.strip('_')
    if not name:
        name = 'column'
    # 确保不以数字开头
    if name[0].isdigit():
        name = '_' + name
    return name


def _escape_identifier(name: str) -> str:
    """转义 MySQL 标识符中的反引号"""
    return name.replace('`', '``')


def _infer_data_type(dtype, series) -> str:
    """从 pandas dtype 推断统一的数据类型"""
    dtype_str = str(dtype)

    if dtype_str.startswith('int'):
        return 'int64'
    elif dtype_str.startswith('float'):
        return 'float64'
    elif dtype_str.startswith('bool'):
        return 'bool'
    elif dtype_str.startswith('datetime'):
        return 'datetime64[ns]'

    # object 类型：尝试进一步推断
    if dtype_str == 'object':
        # 尝试检测是否为日期
        try:
            pd.to_datetime(series.dropna().head(10))
            return 'datetime64[ns]'
        except (ValueError, TypeError):
            pass
        return 'object'

    return 'object'


# -- custom_report/dashboard/html_template.py --
"""
ECharts HTML/JS 模板生成器 — 简化版

生成完整的仪表盘 HTML 页面字符串。
使用字符串拼接而非 f-string 嵌套，避免转义问题。
"""

import json
from pathlib import Path


def build_dashboard_html(dashboard_config: dict, use_cdn: bool = False, embed_data: bool = True, echarts_dir: str = '') -> str:
    """生成完整的仪表盘 HTML 页面

    Args:
        echarts_dir: echarts 资源目录的本地路径（非 CDN 模式时生成绝对 file:// URL）
    """
    config_json = json.dumps(dashboard_config, ensure_ascii=False)

    if use_cdn:
        echarts_src = 'https://cdn.jsdelivr.net/npm/echarts@5.5.0/dist/echarts.min.js'
        qwebchannel_src = 'https://cdn.jsdelivr.net/npm/qwebchannel@6.2.0/qwebchannel.js'
    else:
        # 使用绝对 file:// URL，不依赖 base_url 的目录斜杠判断
        echarts_src = Path(echarts_dir, 'echarts.min.js').as_uri() if echarts_dir else './echarts/echarts.min.js'
        qwebchannel_src = 'qrc:///qtwebchannel/qwebchannel.js'

    theme = dashboard_config.get('theme', 'light')
    dark_class = 'dark' if theme == 'dark' else ''

    parts = []
    parts.append('''<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
''')
    parts.append(f'<script src="{echarts_src}"></script>\n')
    parts.append(f'<script src="{qwebchannel_src}"></script>\n')
    # ECharts 插件：词云、水球、3D
    for plugin in ('echarts-wordcloud.min.js', 'echarts-liquidfill.min.js', 'echarts-gl.min.js'):
        plugin_path = Path(echarts_dir, plugin)
        if plugin_path.exists():
            parts.append(f'<script src="{plugin_path.as_uri()}"></script>\n')
    parts.append('''<style>
* { margin:0; padding:0; box-sizing:border-box; }
body { font-family: "Microsoft YaHei", sans-serif; background:#F0F2F5; overflow-y:auto; }
body.dark { background:#1A1A2E; }
.grid { display:grid; gap:1px; padding:16px; min-height:100vh; }
.grid.show-lines { background: linear-gradient(to right, #E0E0E0 1px, transparent 1px), linear-gradient(to bottom, #E0E0E0 1px, transparent 1px); }
.grid.show-lines.dark { background: linear-gradient(to right, #444 1px, transparent 1px), linear-gradient(to bottom, #444 1px, transparent 1px); }
.card { background:#FFF; border-radius:4px; box-shadow:0 0 0 3px #F0F2F5; position:relative; overflow:hidden; display:flex; flex-direction:column; min-height:280px; }
body.dark .card { background:#16213E; }
.card .hd { padding:10px 16px 4px; font-size:14px; font-weight:600; color:#333; flex-shrink:0; }
body.dark .card .hd { color:#E0E0E0; }
.card .bd { flex:1; min-height:200px; width:100%; }
.card.selected { box-shadow:0 0 0 2px #FF8C00; }
.kpi { display:flex; flex-direction:column; align-items:center; justify-content:center; padding:16px; }
.kpi .v { font-size:36px; font-weight:bold; color:#FF8C00; }
.kpi .l { font-size:14px; color:#999; margin-top:4px; }
.tbl { padding:8px 16px; overflow:auto; }
.tbl table { width:100%; border-collapse:collapse; font-size:13px; }
.tbl th { background:#FAFAFA; padding:8px 12px; text-align:left; border-bottom:2px solid #E8E8E8; position:sticky; top:0; }
.tbl td { padding:6px 12px; border-bottom:1px solid #F0F0F0; }
.placeholder { border:2px dashed #D9D9D9; border-radius:8px; display:flex; align-items:center; justify-content:center; color:#999; font-size:14px; cursor:pointer; min-height:280px; }
.drill-nav { padding:4px 16px; font-size:12px; }
.drill-nav span { color:#1890FF; cursor:pointer; }
.drill-nav span:hover { text-decoration:underline; }
</style>
</head>
<body class="''' + dark_class + '''">
<div class="grid" id="grid"></div>
<script>
var CONFIG = ''' + config_json + ''';
var ALL_DATA = {};
var chartInstances = {};
var crossFilterState = {};
var _initialized = false;

function initCharts() {
    if (_initialized) return;
    _initialized = true;
    var grid = document.getElementById('grid');
    var cols = CONFIG.grid_columns || 3;
    var rowH = CONFIG.grid_row_height || 320;
    grid.style.gridTemplateColumns = 'repeat(' + cols + ', 1fr)';
    grid.style.gridAutoRows = rowH + 'px';
    // 网格背景大小（虚线对齐）
    grid.style.backgroundSize = (100/cols) + '% ' + rowH + 'px';

    (CONFIG.charts || []).forEach(function(c) {
        var card = document.createElement('div');
        card.className = 'card';
        card.id = 'chart-' + c.id;
        var pos = c.position || [0,0];
        var sz = c.size || [1,1];
        card.style.gridRow = (pos[0]+1) + ' / span ' + sz[0];
        card.style.gridColumn = (pos[1]+1) + ' / span ' + sz[1];
        card._rowSpan = sz[0];
        card._colSpan = sz[1];
        card._chartId = c.id;

        var hd = document.createElement('div');
        hd.className = 'hd';
        hd.textContent = c.title || '';
        hd.style.cursor = 'grab';
        card.appendChild(hd);

        var bd = document.createElement('div');
        bd.className = 'bd';
        card.appendChild(bd);

        // ====== 拖动标题栏移动图表（使用实时 DOM 尺寸，避免 stale config）======
        var dragInfo = null;
        hd.addEventListener('mousedown', function(e) {
            if (e.button !== 0) return;
            e.stopPropagation();
            e.preventDefault();
            var cols = CONFIG.grid_columns || 3;
            var rowH = CONFIG.grid_row_height || 320;
            var colW = grid.offsetWidth / cols;
            // 用 DOM 上实时的行列跨度（resize 更新的），而非 CONFIG 中的可能过时的值
            var curRowSpan = card._rowSpan || sz[0] || 1;
            var curColSpan = card._colSpan || sz[1] || 1;
            dragInfo = {
                startX: e.clientX, startY: e.clientY,
                origRow: pos[0], origCol: pos[1],
                rowSpan: curRowSpan, colSpan: curColSpan,
                colW: colW, rowH: rowH, cols: cols
            };
            card.style.zIndex = '100';
            card.style.opacity = '0.85';
            hd.style.cursor = 'grabbing';
            window._isDragging = true;
        });

        document.addEventListener('mousemove', function(e) {
            if (!dragInfo) return;
            var dx = e.clientX - dragInfo.startX;
            var dy = e.clientY - dragInfo.startY;
            var newCol = Math.max(0, Math.min(dragInfo.cols - Math.ceil(dragInfo.colSpan),
                Math.round(dragInfo.origCol + dx / dragInfo.colW)));
            var newRow = Math.max(0, Math.round(dragInfo.origRow + dy / dragInfo.rowH));
            card.style.gridRow = (newRow+1) + ' / span ' + dragInfo.rowSpan;
            card.style.gridColumn = (newCol+1) + ' / span ' + dragInfo.colSpan;
        });

        document.addEventListener('mouseup', function(e) {
            if (!dragInfo) return;
            var newRow = parseInt(card.style.gridRow) - 1;
            var newCol = parseInt(card.style.gridColumn) - 1;
            if (isNaN(newRow)) newRow = dragInfo.origRow;
            if (isNaN(newCol)) newCol = dragInfo.origCol;
            pos[0] = Math.max(0, newRow);
            pos[1] = Math.max(0, newCol);
            card.style.gridRow = (pos[0]+1) + ' / span ' + dragInfo.rowSpan;
            card.style.gridColumn = (pos[1]+1) + ' / span ' + dragInfo.colSpan;
            card.style.zIndex = '';
            card.style.opacity = '';
            hd.style.cursor = 'grab';
            if (window.bridge) {
                window.bridge.handle_js_action('chart_move', JSON.stringify({chartId: c.id, position: [pos[0], pos[1]]}));
            }
            dragInfo = null;
            setTimeout(function(){ window._isDragging = false; }, 300);
        });

        // ====== 右下角调整大小（固定位置，仅改跨度）======
        var resizeHandle = document.createElement('div');
        resizeHandle.style.cssText =
            'position:absolute;right:0;bottom:0;width:28px;height:28px;'
            + 'cursor:nwse-resize;z-index:100;'
            + 'border-radius:0 0 4px 0;'
            + 'display:flex;align-items:flex-end;justify-content:flex-end;';
        resizeHandle.innerHTML =
            '<svg width="16" height="16" viewBox="0 0 16 16" style="pointer-events:none;opacity:0.5;">'
            + '<path d="M14 2 L14 6 L10 2 Z M14 10 L14 14 L10 14 L6 10 Z" fill="#999"/>'
            + '</svg>';
        resizeHandle.title = '拖拽调整大小';
        var resizeInfo = null;

        resizeHandle.addEventListener('mousedown', function(e) {
            if (e.button !== 0) return;
            e.stopPropagation();
            e.preventDefault();
            var cols = CONFIG.grid_columns || 3;
            var rowH = CONFIG.grid_row_height || 320;
            var colW = grid.offsetWidth / cols;
            // 固定位置：用 grid-row-start / grid-column-start 锁住位置
            var curRowStart = pos[0] + 1;
            var curColStart = pos[1] + 1;
            card.style.gridRow = curRowStart + ' / span ' + (card._rowSpan || 1);
            card.style.gridColumn = curColStart + ' / span ' + (card._colSpan || 1);
            resizeInfo = {
                startX: e.clientX, startY: e.clientY,
                startColSpan: card._colSpan || 1, startRowSpan: card._rowSpan || 1,
                colW: colW, rowH: rowH, cols: cols,
                rowStart: curRowStart, colStart: curColStart,
            };
            window._isResizing = true;
            card.style.zIndex = '50';
        });

        document.addEventListener('mousemove', function(e) {
            if (!resizeInfo) return;
            e.preventDefault();
            var dCol = (e.clientX - resizeInfo.startX) / resizeInfo.colW;
            var dRow = (e.clientY - resizeInfo.startY) / resizeInfo.rowH;
            var newColSpan = Math.max(1, Math.round(resizeInfo.startColSpan + dCol));
            var newRowSpan = Math.max(1, Math.round(resizeInfo.startRowSpan + dRow));
            newColSpan = Math.min(newColSpan, resizeInfo.cols - (resizeInfo.colStart - 1));
            // 仅改跨度，不改起始位置
            card.style.gridRow = resizeInfo.rowStart + ' / span ' + newRowSpan;
            card.style.gridColumn = resizeInfo.colStart + ' / span ' + newColSpan;
        });

        document.addEventListener('mouseup', function(e) {
            if (!resizeInfo) return;
            var newColSpan = Math.max(1, Math.min(resizeInfo.cols,
                Math.round((card._colSpan || resizeInfo.startColSpan))));
            var newRowSpan = Math.max(1, Math.round(card._rowSpan || resizeInfo.startRowSpan));
            // 从 DOM 读取实际吸附结果
            var gridRowVal = card.style.gridRow;
            var gridColVal = card.style.gridColumn;
            // 解析 span 值
            var matchR = gridRowVal.match(/span\\s+(\\d+)/);
            var matchC = gridColVal.match(/span\\s+(\\d+)/);
            if (matchC) newColSpan = Math.max(1, parseInt(matchC[1]));
            if (matchR) newRowSpan = Math.max(1, parseInt(matchR[1]));
            card.style.gridRow = resizeInfo.rowStart + ' / span ' + newRowSpan;
            card.style.gridColumn = resizeInfo.colStart + ' / span ' + newColSpan;
            card._rowSpan = newRowSpan;
            card._colSpan = newColSpan;
            card.style.zIndex = '';
            if (window.bridge) {
                window.bridge.handle_js_action('chart_resize', JSON.stringify({chartId: c.id, size: [newRowSpan, newColSpan]}));
            }
            var inst = chartInstances[c.id];
            if (inst && !inst.isDisposed()) { try { inst.resize(); } catch(x){} }
            resizeInfo = null;
            setTimeout(function(){ window._isResizing = false; }, 300);
        });

        card.appendChild(resizeHandle);
        grid.appendChild(card);

        renderWidget(c, bd, ALL_DATA[c.id] || []);

        // 单击选中（resize/drag 后 300ms 内忽略）
        card.addEventListener('click', function(e) {
            if (dragInfo || resizeInfo || window._isResizing || window._isDragging) return;
            e.stopPropagation();
            selectChartCard(c.id);
        });

        // 右键菜单
        card.addEventListener('contextmenu', function(e) {
            e.preventDefault();
            e.stopPropagation();
            selectChartCard(c.id);
            showChartContextMenu(e.clientX, e.clientY, c.id, c.title);
        });

        // 双击全屏
        card.addEventListener('dblclick', function(e) {
            if (window._isDragging || window._isResizing) return;
            toggleFullscreen(card, c.id);
        });
    });

    // 图表联动：共享 tooltip 十字准星
    connectAllCharts();

    // 全局键盘快捷键
    document.addEventListener('keydown', function(e) {
        if (e.key === 'F5') {
            e.preventDefault();
            if (window.bridge) bridge.handle_js_action('change_query', '{}');
        }
        if (e.key === 'Escape') {
            var fs = document.querySelector('.card.fullscreen');
            if (fs) { fs.classList.remove('fullscreen'); fs.style.cssText = ''; }
            Object.values(chartInstances).forEach(function(i){ try{i.resize();}catch(x){} });
        }
    });
}

// ===== 图表联动 =====
function connectAllCharts() {
    var ids = [];
    for (var k in chartInstances) {
        var inst = chartInstances[k];
        if (inst && !inst.isDisposed()) {
            inst.group = 'dashboard';
            ids.push(inst.id);
        }
    }
    if (ids.length > 1) {
        try { echarts.connect('dashboard'); } catch(e) {}
    }
}

// ===== 全屏切换（保存/恢复原始 grid 位置和大小） =====
function toggleFullscreen(card, chartId) {
    var bd = card.querySelector('.bd');
    if (card.classList.contains('fullscreen')) {
        // 退出全屏 → 精确恢复到原始 grid 位置和跨度
        card.classList.remove('fullscreen');
        var orig = card._fullscreenRestore;
        if (orig) {
            card.style.cssText = '';
            card.style.gridRow = orig.gridRow;
            card.style.gridColumn = orig.gridColumn;
            card._rowSpan = orig.rowSpan;
            card._colSpan = orig.colSpan;
            card._fullscreenRestore = null;
        }
        setTimeout(function(){
            var inst = chartInstances[chartId];
            if (inst && !inst.isDisposed()) inst.resize();
        }, 100);
    } else {
        // 进入全屏 → 保存当前 grid 状态以便恢复
        card._fullscreenRestore = {
            gridRow: card.style.gridRow,
            gridColumn: card.style.gridColumn,
            rowSpan: card._rowSpan,
            colSpan: card._colSpan,
        };
        card.classList.add('fullscreen');
        card.style.cssText = 'position:fixed;top:16px;left:16px;'
            + 'width:calc(100vw - 32px);height:calc(100vh - 32px);z-index:9999;';
        setTimeout(function(){
            var inst = chartInstances[chartId];
            if (inst && !inst.isDisposed()) inst.resize();
        }, 200);
    }
}

function selectChartCard(chartId) {
    document.querySelectorAll('.card.selected').forEach(function(el){ el.classList.remove('selected'); });
    var card = document.getElementById('chart-' + chartId);
    if (card) card.classList.add('selected');
    if (window.bridge) {
        window.bridge.handle_js_action('chart_selected', JSON.stringify({chartId: chartId}));
    }
}

var _contextMenu = null;
var _ctxMenuSkip = false;
function showChartContextMenu(x, y, chartId, title) {
    if (_contextMenu) { _contextMenu.remove(); _contextMenu = null; }
    var menu = document.createElement('div');
    menu.className = 'ctx-menu';
    menu.style.cssText = 'position:fixed;left:'+x+'px;top:'+y+'px;background:#FFF;border:1px solid #D9D9D9;border-radius:4px;box-shadow:0 2px 8px rgba(0,0,0,.15);z-index:9999;min-width:140px;font-size:13px;';
    menu.innerHTML = '<div style="padding:4px 12px;color:#999;font-size:11px;border-bottom:1px solid #F0F0F0;">'+title+'</div>'
        + '<div class="ctx-item" data-action="remove" style="padding:8px 12px;cursor:pointer;">🗑 删除图表</div>';

    var close = function() {
        if (menu.parentNode) { menu.remove(); }
        _contextMenu = null;
        document.removeEventListener('mousedown', onMouseDown, true);
    };

    menu.querySelector('.ctx-item').addEventListener('mousedown', function(e){
        e.stopPropagation();
        e.preventDefault();
        close();
        if (window.bridge) {
            window.bridge.handle_js_action('chart_remove', JSON.stringify({chartId: chartId}));
        }
    });

    function onMouseDown(e) {
        if (_ctxMenuSkip) { _ctxMenuSkip = false; return; }
        if (!menu.contains(e.target)) {
            close();
        }
    }

    document.body.appendChild(menu);
    _contextMenu = menu;
    _ctxMenuSkip = true;
    document.addEventListener('mousedown', onMouseDown, true);
}

function renderWidget(c, el, data) {
    try {
        // card / table 优先用 Python 端预渲染的 HTML
        if (c.chart_type === 'card') {
            if (c._prerendered_html) { el.innerHTML = c._prerendered_html; return; }
            return renderKPI(c, el, data);
        }
        if (c.chart_type === 'table') {
            if (c._prerendered_html) { el.innerHTML = c._prerendered_html; return; }
            return renderTable(c, el, data);
        }
        if (typeof echarts === 'undefined') {
            el.innerHTML = '<div style="color:#FF4D4F;padding:20px;text-align:center;">❌ ECharts 库未加载<br><small>检查 echarts.min.js 路径</small></div>';
            return;
        }
        if (!data || !data.length) {
            el.innerHTML = '<div style="color:#999;padding:20px;text-align:center;">📭 暂无数据<br><small>请刷新数据或检查数据源</small></div>';
            return;
        }
        // 地图类需要先加载 GeoJSON
        if (c.chart_type === 'map_china') {
            loadChinaMap(function() { renderECharts(c, el, data); });
            return;
        }
        renderECharts(c, el, data);
    } catch(e) {
        el.innerHTML = '<div style="color:#FF4D4F;padding:16px;text-align:center;font-size:13px;">❌ ' + (c.title||'图表') + ' 渲染失败<br><small>' + e.message + '</small></div>';
    }
}

function renderECharts(c, el, data) {
    var inst = echarts.init(el);
    // 优先使用 Python 端 pyecharts 预渲染的 ECharts option
    if (c._echarts_option) {
        try {
            // _echarts_option 可能是 JSON 字符串（来自 CONFIG）或 JS 对象（来自直接推送）
            var opt = (typeof c._echarts_option === 'string')
                ? eval('(' + c._echarts_option + ')')
                : c._echarts_option;
            inst.setOption(opt, {notMerge: true});
        } catch(e) {
            if (c.chart_type === 'sankey') {
                el.innerHTML = '<div style=\"color:#FF9800;padding:20px;text-align:center;\">'
                    + '⚠ Sankey 数据存在循环引用<br><small>已自动过滤，请检查数据源</small></div>';
                return;
            }
            inst.setOption(buildOption(c, data));
        }
    } else {
        inst.setOption(buildOption(c, data));
    }
    inst.on('click', function(p) { onChartClick(c.id, p); });
    chartInstances[c.id] = inst;
}

var _chinaMapLoaded = false;
var _chinaMapCallbacks = [];
function loadChinaMap(callback) {
    if (_chinaMapLoaded) { callback(); return; }
    _chinaMapCallbacks.push(callback);
    // 优先使用 Python 端嵌入的 GeoJSON 数据
    if (window._CHINA_GEO) {
        echarts.registerMap('china', window._CHINA_GEO);
        _chinaMapLoaded = true;
        _chinaMapCallbacks.forEach(function(cb){ cb(); });
        _chinaMapCallbacks = [];
    } else {
        // 回退：尝试 fetch（导出 HTML 用）
        if (typeof fetch !== 'undefined') {
            fetch('./china.json').then(function(r){ return r.json(); }).then(function(geo){
                echarts.registerMap('china', geo);
                _chinaMapLoaded = true;
                _chinaMapCallbacks.forEach(function(cb){ cb(); });
                _chinaMapCallbacks = [];
            }).catch(function(){
                _chinaMapCallbacks.forEach(function(cb){ cb(); });
                _chinaMapCallbacks = [];
            });
        } else {
            _chinaMapCallbacks.forEach(function(cb){ cb(); });
            _chinaMapCallbacks = [];
        }
    }
}

function buildOption(c, data) {
    if (!c) return {};
    var xF = c.x_field || '';
    var yfArr = Array.isArray(c.y_fields) ? c.y_fields : [];
    var yF = yfArr[0] || '';
    var cF = c.color_field || '';
    data = Array.isArray(data) ? data : [];
    var categories = [];
    var seen = {};
    data.forEach(function(r) { var v = r[xF]||''; if (!seen[v]) { seen[v]=true; categories.push(v); } });

    function seriesData(field) {
        return categories.map(function(cat) {
            var row = data.find(function(r) { return (r[xF]||'') === cat; });
            return row ? (row[field] || 0) : 0;
        });
    }

    function pieData(nameF, valF) {
        return data.map(function(r) { return { name: r[nameF]||'', value: r[valF]||0 }; });
    }

    var type = c.chart_type;
    var base = {
        tooltip: { trigger: type==='pie' ? 'item' : 'axis' },
        legend: { show: (c.style_config||{}).show_legend!==false, bottom:0, type:'scroll' },
        grid: { left:50, right:30, top:20, bottom:40 },
        animationDuration: 300
    };

    if (type === 'pie') {
        return {
            tooltip: { trigger: 'item' },
            legend: { show: (c.style_config||{}).show_legend!==false, bottom:0 },
            series: [{ type:'pie', radius:['35%','65%'], center:['50%','45%'], data: pieData(xF, yF),
                label: { show: (c.style_config||{}).show_label===true } }]
        };
    }
    if (type === 'gauge') {
        var v = data.length ? (data[0][yF] || 0) : 0;
        return { series: [{ type:'gauge', radius:'85%', center:['50%','55%'],
            startAngle:210, endAngle:-30, min:0, max: Math.max(v*1.5, 100),
            data: [{ value: v, name: c.title||'' }] }] };
    }
    if (type === 'funnel') {
        return { tooltip:{trigger:'item'}, series:[{ type:'funnel', left:'10%',width:'80%',
            data: pieData(xF, yF).sort(function(a,b){ return b.value-a.value; }), sort:'descending' }] };
    }
    if (type === 'radar') {
        var indicators = data.map(function(r){ return { name:r[xF]||'', max: Math.max.apply(null,data.map(function(d){ return d[yF]||0; }))*1.2 }; });
        return { radar:{ indicator:indicators, center:['50%','50%'], radius:'65%' },
            series:[{ type:'radar', data:[{ value: data.map(function(r){ return r[yF]||0; }), name: c.title||'' }] }] };
    }
    if (type === 'treemap') {
        return { tooltip:{trigger:'item'}, series:[{ type:'treemap', data: pieData(xF, yF) }] };
    }
    if (type === 'map_china') {
        var mapData = data.map(function(r){ return { name: r[xF]||'', value: r[yF]||0 }; });
        var maxVal = Math.max.apply(null, mapData.map(function(d){ return d.value; }));
        return { tooltip:{trigger:'item'}, visualMap:{ min:0, max:maxVal||100, left:'left', bottom:10, text:['高','低'], calculable:true },
            series:[{ type:'map', map:'china', roam:true, data:mapData, label:{show:true,fontSize:10} }] };
    }
    if (type === 'sunburst') {
        return { tooltip:{trigger:'item'}, series:[{ type:'sunburst', data: pieData(xF, yF), radius:['15%','80%'] }] };
    }
    if (type === 'heatmap') {
        var hx = Array.from(new Set(data.map(function(r){ return r[xF]||''; })));
        var hy = Array.from(new Set(data.map(function(r){ return r[cF||yF]||''; })));
        var hmData = data.map(function(r){ return [hx.indexOf(r[xF]||''), hy.indexOf(r[cF||yF]||''), r[yF]||0]; });
        return { tooltip:{}, grid:{left:80,right:20,top:20,bottom:40},
            xAxis:{ type:'category', data:hx, splitArea:{show:true} },
            yAxis:{ type:'category', data:hy, splitArea:{show:true} },
            visualMap:{ min:0, max:Math.max.apply(null,hmData.map(function(d){return d[2];})), calculable:true, orient:'horizontal', left:'center', bottom:0 },
            series:[{ type:'heatmap', data:hmData, label:{show:true} }] };
    }
    if (type === 'sankey') {
        var links = data.map(function(r){ return { source: r[xF]||'', target: r[cF||'']||'', value: r[yF]||0 }; });
        return { tooltip:{trigger:'item'}, series:[{ type:'sankey', layout:'none', data: pieData(xF, yF), links:links }] };
    }
    if (type === 'word_cloud') {
        return { tooltip:{}, series:[{ type:'wordCloud', shape:'circle', width:'90%', height:'90%',
            data: data.map(function(r){ return { name: r[xF]||'', value: r[yF]||0 }; }) }] };
    }
    if (type === 'scatter' || type === 'effect_scatter') {
        var scData = data.map(function(r){ return [r[xF]||0, r[yF]||0]; });
        return { xAxis:{}, yAxis:{}, series:[{ type:type==='effect_scatter'?'effectScatter':'scatter', data:scData,
            symbolSize: function(d){ return (c.size_field && data[0] && data[0][c.size_field]) ? (d[2]||10) : 10; } }] };
    }
    if (type === 'calendar') {
        var calData = [];
        data.forEach(function(r){
            var d = r[xF], v = r[yF];
            if (d != null && v != null) {
                calData.push([String(d), Number(v) || 0]);
            }
        });
        if (!calData.length) {
            return { title:{text:'无有效日期数据',left:'center',top:'center'} };
        }
        var calMax = Math.max.apply(null, calData.map(function(d){ return d[1]; }));
        var firstDate = String(calData[0][0] || '');
        var rangeYear = firstDate.length >= 4 ? firstDate.substring(0,4) : '2024';
        return { tooltip:{}, visualMap:{ min:0, max:calMax||100, orient:'horizontal', left:'center', bottom:0 },
            calendar:{ range: rangeYear, cellSize:['auto',20] },
            series:[{ type:'heatmap', coordinateSystem:'calendar', data:calData }] };
    }
    if (type === 'graph') {
        var nodes = []; var nSeen = {};
        data.forEach(function(r){ var n=r[xF]||''; if(!nSeen[n]){ nSeen[n]=true; nodes.push({name:n}); } });
        data.forEach(function(r){ var n=r[cF||'']||''; if(n&&!nSeen[n]){ nSeen[n]=true; nodes.push({name:n}); } });
        var lnks = data.map(function(r){ return { source: r[xF]||'', target: r[cF||'']||'', value: r[yF]||0 }; });
        return { tooltip:{}, series:[{ type:'graph', layout:'force', roam:true, data:nodes, links:lnks,
            force:{ repulsion:200, edgeLength:100 } }] };
    }
    if (type === 'tree') {
        function buildTree(items, parentField, nameField) {
            var map = {}, roots = [];
            items.forEach(function(r){ map[r[nameField]||''] = { name: r[nameField]||'', value: r[yF]||0, children:[] }; });
            items.forEach(function(r){ var p=r[parentField]||'', n=r[nameField]||'';
                if(p && map[p] && map[n]) map[p].children.push(map[n]); else if(map[n]) roots.push(map[n]); });
            return roots.length ? roots[0] : { name:'root', children: Object.values(map) };
        }
        var treeData = buildTree(data, cF||'pid', xF);
        return { tooltip:{trigger:'item'}, series:[{ type:'tree', data:[treeData], orient:'TB', roam:true,
            top:'5%', left:'10%', bottom:'5%', right:'20%' }] };
    }
    if (type === 'parallel') {
        var dims = [xF].concat(c.y_fields||[yF]);
        var pData = data.map(function(r){ return dims.map(function(d){ return r[d]||0; }); });
        return { parallelAxis: dims.map(function(d){ return { dim: dims.indexOf(d), name:d }; }),
            series:[{ type:'parallel', data: pData }] };
    }

    // 图表类型 → ECharts series type 映射
    function seriesType(t) {
        var m = { bar:'bar', line:'line', area:'line', stacked_bar:'bar', stacked_area:'line',
            combo:'bar', pictorial_bar:'pictorialBar', waterfall:'bar', boxplot:'boxplot',
            candlestick:'candlestick', theme_river:'themeRiver', graph:'graph', tree:'tree' };
        return m[t] || 'bar';
    }

    // 基础笛卡尔图表 + 所有未单独处理的类型
    var sType = seriesType(type);
    var isSmooth = (type==='line'||type==='area'||type==='theme_river');
    var isArea = (type==='area'||type==='theme_river');
    var isStacked = (type==='stacked_bar'||type==='stacked_area');

    var seriesArr = [];
    if (cF) {
        var groups = [];
        var gSeen = {};
        data.forEach(function(r) { var g = r[cF]||''; if (!gSeen[g]) { gSeen[g]=true; groups.push(g); } });
        groups.forEach(function(g) {
            var s = { name: g, type: sType,
                data: categories.map(function(cat) {
                    var row = data.find(function(r){ return (r[xF]||'')===cat && (r[cF]||'')===g; });
                    return row ? (row[yF]||0) : 0;
                }) };
            if (isSmooth) s.smooth = true;
            if (isArea) s.areaStyle = {};
            if (isStacked) s.stack = 'total';
            seriesArr.push(s);
        });
    } else {
        (c.y_fields||[yF]).forEach(function(f) {
            var s = { name: f, type: sType, data: seriesData(f) };
            if (isSmooth) s.smooth = true;
            if (isArea) s.areaStyle = {};
            if (isStacked) s.stack = 'total';
            seriesArr.push(s);
        });
    }

    var opt = base;
    opt.xAxis = { type:'category', data:categories, boundaryGap: sType!=='line' };
    opt.yAxis = { type:'value' };
    opt.series = seriesArr;
    return opt;
}

function renderKPI(c, el, data) {
    var v = (data && data.length) ? (data[0][(c.y_fields||[])[0]||''] || 0) : 0;
    var fmt = typeof v === 'number' ? v.toLocaleString() : v;
    el.innerHTML = '<div class="kpi"><div class="v">' + fmt + '</div><div class="l">' + (c.title||'') + '</div></div>';
}

function renderTable(c, el, data) {
    if (!data || !data.length) { el.innerHTML = '<div style="padding:20px;color:#999;">无数据</div>'; return; }
    var cols = Object.keys(data[0]);
    var h = '<div class="tbl"><table><thead><tr>';
    cols.forEach(function(k) { h += '<th>' + k + '</th>'; });
    h += '</tr></thead><tbody>';
    data.forEach(function(r) {
        h += '<tr>';
        cols.forEach(function(k) { h += '<td>' + (r[k]||'') + '</td>'; });
        h += '</tr>';
    });
    h += '</tbody></table></div>';
    el.innerHTML = h;
}

function onChartClick(chartId, params) {
    var c = (CONFIG.charts||[]).find(function(x){ return x.id===chartId; });
    if (!c || c.enable_cross_filter===false) return;
    var val = params.name || params.seriesName || '';
    var field = c.color_field || c.x_field || '';
    if (!field) return;
    if (!crossFilterState[field]) crossFilterState[field] = [];
    var idx = crossFilterState[field].indexOf(val);
    if (idx >= 0) { crossFilterState[field].splice(idx,1); if (!crossFilterState[field].length) delete crossFilterState[field]; }
    else crossFilterState[field].push(val);
    applyCrossFilter();
}

function applyCrossFilter() {
    var entries = Object.entries(crossFilterState).filter(function(e){ return e[1].length>0; });
    Object.entries(chartInstances).forEach(function(e){
        var id = e[0], inst = e[1];
        var c = (CONFIG.charts||[]).find(function(x){ return x.id===id; });
        if (!c || c.chart_type==='card'||c.chart_type==='table') return;
        var fd = (ALL_DATA[id]||[]).slice();
        entries.forEach(function(entry){ fd = fd.filter(function(r){ return entry[1].indexOf(r[entry[0]]||'') >= 0; }); });
        var opt = buildOption(c, fd);
        try { inst.setOption(opt, {notMerge:false}); } catch(e){}
    });
}

// ===== Bridge 函数 =====
function setEditMode(enabled) { document.body.classList.toggle('edit-mode', enabled); }
function selectChart(chartId) { var el = document.getElementById('chart-' + chartId); if (el) el.scrollIntoView({ behavior:'smooth', block:'center' }); }
function requestExportPNG() {}
function applyGlobalFilters(filtersJson) {}
function reloadConfig(configJson) { try { var cfg = JSON.parse(configJson); if (cfg) Object.assign(CONFIG, cfg); } catch(e){} }

window.setEditMode = setEditMode;
window.selectChart = selectChart;
window.toggleGridLines = function(show) {
    var grid = document.getElementById('grid');
    if (grid) { grid.classList.toggle('show-lines', show); }
};
window.requestExportPNG = requestExportPNG;
window.applyGlobalFilters = applyGlobalFilters;
window.reloadConfig = reloadConfig;

window.updateChartConfig = function(chartId, chartCfg) {
    var idx = (CONFIG.charts||[]).findIndex(function(c){ return c.id===chartId; });
    if (idx >= 0) { CONFIG.charts[idx] = chartCfg; }
    else { CONFIG.charts = CONFIG.charts || []; CONFIG.charts.push(chartCfg); }
    var card = document.getElementById('chart-' + chartId);
    if (card) {
        var hd = card.querySelector('.hd');
        if (hd) hd.textContent = chartCfg.title || '';
        // card/table: 直接注入预渲染 HTML
        var ct = chartCfg.chart_type || '';
        if ((ct === 'card' || ct === 'table') && chartCfg._prerendered_html) {
            var bd = card.querySelector('.bd');
            if (bd) bd.innerHTML = chartCfg._prerendered_html;
            return;
        }
    }
    var inst = chartInstances[chartId];
    if (inst && !inst.isDisposed()) {
        var data = ALL_DATA[chartId] || [];
        if (chartCfg._echarts_option) {
            try { inst.setOption(JSON.parse(chartCfg._echarts_option), {notMerge:true}); } catch(e){}
        } else {
            try { inst.setOption(buildOption(chartCfg, data), {notMerge:true}); } catch(e){}
        }
    }
};

window.refreshAllData = function(dataMap) {
    if (!dataMap) return;
    ALL_DATA = dataMap;
    crossFilterState = {};
    Object.entries(dataMap).forEach(function(e) {
        var id = e[0], data = e[1];
        var inst = chartInstances[id];
        if (inst && !inst.isDisposed()) {
            var c = (CONFIG.charts||[]).find(function(x){ return x.id===id; });
            if (c) {
                // 优先使用 Python 预渲染 option
                if (c._echarts_option) {
                    try { inst.setOption(eval('('+c._echarts_option+')'), {notMerge:true}); } catch(ex){}
                } else {
                    try { inst.setOption(buildOption(c, data), {notMerge:true}); } catch(ex){}
                }
            }
        }
    });
};

window.refreshChartData = function(chartId, data) {
    ALL_DATA[chartId] = data;
    var inst = chartInstances[chartId];
    if (inst) {
        var c = (CONFIG.charts||[]).find(function(x){ return x.id===chartId; });
        if (c) {
            if (c._echarts_option) {
                try { inst.setOption(eval('('+c._echarts_option+')'), {notMerge:true}); } catch(e){}
            } else {
                inst.setOption(buildOption(c, data), {notMerge:true});
            }
        }
    }
};

document.addEventListener('DOMContentLoaded', function() {
    try {
        if (window._INITIAL_DATA) { ALL_DATA = window._INITIAL_DATA; window._INITIAL_DATA = null; }
        initCharts();
        if (window.qt && window.qt.webChannelTransport) {
            new QWebChannel(qt.webChannelTransport, function(channel) {
                window.bridge = channel.objects.bridge;
                window.bridge.handle_js_action('page_ready', '{}');
            });
        }
    } catch(e) {
        var grid = document.getElementById('grid');
        if (grid) grid.innerHTML = '<div style="padding:40px;color:#FF4D4F;font-size:18px;text-align:center;">❌ 页面初始化失败<br><small>' + e.message + '</small></div>';
    }
});

window.addEventListener('resize', function() {
    Object.values(chartInstances).forEach(function(inst) {
        try { inst.resize(); } catch(e) {}
    });
});
</script>
</body>
</html>''')
    return ''.join(parts)


# -- custom_report/dashboard/models.py --
"""
BI 仪表盘数据模型

DashboardDefinition 是一份仪表盘的完整定义，包含:
- 基本信息 (名称、布局、主题)
- 图表列表 (类型、数据源、字段映射、样式)
- 全局筛选器
- AI 提供商配置
"""

from dataclasses import dataclass, field, asdict
from enum import Enum
from typing import Optional
import uuid
import json
import copy


# ==================== 工具函数 ====================

def _new_id(length: int = 8) -> str:
    """生成指定长度的 hex ID"""
    return uuid.uuid4().hex[:length]


# ==================== 枚举 ====================

class ChartType(Enum):
    """图表类型（ECharts 全覆盖）"""

    # 基础图表
    BAR = "bar"
    LINE = "line"
    PIE = "pie"
    SCATTER = "scatter"
    AREA = "area"
    TABLE = "table"

    # 指标类
    CARD = "card"
    GAUGE = "gauge"

    # 组合 / 变体
    COMBO = "combo"
    STACKED_BAR = "stacked_bar"
    STACKED_AREA = "stacked_area"
    PICTORIAL_BAR = "pictorial_bar"
    EFFECT_SCATTER = "effect_scatter"
    WATERFALL = "waterfall"

    # 比例 / 构成
    FUNNEL = "funnel"
    TREEMAP = "treemap"
    SUNBURST = "sunburst"

    # 分布 / 统计
    BOXPLOT = "boxplot"
    HEATMAP = "heatmap"
    CALENDAR = "calendar"
    CANDLESTICK = "candlestick"

    # 关系 / 流向
    SANKEY = "sankey"
    GRAPH = "graph"
    TREE = "tree"

    # 多维分析
    RADAR = "radar"
    PARALLEL = "parallel"
    THEME_RIVER = "theme_river"

    # 地理
    MAP_CHINA = "map_china"
    MAP_SCATTER = "map_scatter"
    MAP_LINES = "map_lines"

    # 其他
    WORD_CLOUD = "word_cloud"

    @classmethod
    def from_str(cls, s: str):
        for m in cls:
            if m.value == s:
                return m
        return cls.BAR

    @classmethod
    def category_map(cls) -> dict[str, list["ChartType"]]:
        """返回按分类组织的图表类型"""
        return {
            "基础图表": [cls.BAR, cls.LINE, cls.PIE, cls.SCATTER, cls.AREA, cls.TABLE],
            "指标类": [cls.CARD, cls.GAUGE],
            "组合/变体": [cls.COMBO, cls.STACKED_BAR, cls.STACKED_AREA,
                        cls.PICTORIAL_BAR, cls.EFFECT_SCATTER, cls.WATERFALL],
            "比例/构成": [cls.FUNNEL, cls.TREEMAP, cls.SUNBURST],
            "分布/统计": [cls.BOXPLOT, cls.HEATMAP, cls.CALENDAR, cls.CANDLESTICK],
            "关系/流向": [cls.SANKEY, cls.GRAPH, cls.TREE],
            "多维分析": [cls.RADAR, cls.PARALLEL, cls.THEME_RIVER],
            "地理": [cls.MAP_CHINA, cls.MAP_SCATTER, cls.MAP_LINES],
            "其他": [cls.WORD_CLOUD],
        }


def chart_display_name(chart_type: str) -> str:
    """图表类型中文显示名"""
    names = {
        'bar': '柱状图', 'line': '折线图', 'pie': '饼图', 'scatter': '散点图',
        'area': '面积图', 'table': '表格',
        'card': '指标卡', 'gauge': '仪表盘',
        'combo': '组合图', 'stacked_bar': '堆叠柱状', 'stacked_area': '堆叠面积',
        'pictorial_bar': '象形柱状', 'effect_scatter': '涟漪散点', 'waterfall': '瀑布图',
        'funnel': '漏斗图', 'treemap': '树图', 'sunburst': '旭日图',
        'boxplot': '箱线图', 'heatmap': '热力图', 'calendar': '日历图', 'candlestick': 'K线图',
        'sankey': '桑基图', 'graph': '关系图', 'tree': '树形图',
        'radar': '雷达图', 'parallel': '平行坐标', 'theme_river': '主题河流',
        'map_china': '中国地图', 'map_scatter': '地图散点', 'map_lines': '地图飞线',
        'word_cloud': '词云',
    }
    return names.get(chart_type, chart_type)


class DataSourceType(Enum):
    """数据源类型"""
    REPORT = "report"         # 自定义报表（cr_* 结果表）
    EXCEL = "excel"           # Excel 导入（ex_* 表）
    MYSQL_TABLE = "mysql"     # 直接选 MySQL 表/视图


# ==================== 数据类 ====================

@dataclass
class ChartWidget:
    """仪表盘上的一个图表"""
    id: str = field(default_factory=_new_id)
    chart_type: str = "bar"
    title: str = "未命名图表"

    # 渲染引擎
    render_engine: str = "pyecharts"    # "pyecharts" | "plotly" | "seaborn"

    # 数据源
    data_source_type: str = "report"    # DataSourceType 值
    data_source_id: str = ""            # report_id / excel_dataset_id / mysql_table
    data_source_name: str = ""          # 显示用名称

    # 维度与度量
    x_field: str = ""                   # X 轴 / 维度字段
    y_fields: list[str] = field(default_factory=list)   # Y 轴 / 度量字段
    aggregate_funcs: dict = field(default_factory=dict)  # {field: "SUM"|"AVG"|...}
    color_field: str = ""               # 颜色/系列分组字段
    size_field: str = ""                # 气泡大小（散点图/地图用）

    # 筛选与交互
    filters: list = field(default_factory=list)  # list[FilterCondition]
    drill_path: list = field(default_factory=list)  # ["year","quarter","month","day"]
    enable_cross_filter: bool = True
    enable_drill: bool = False
    enable_brush_link: bool = True      # Brush 刷选联动
    enable_chart_connect: bool = True   # 图表十字准星联动
    magic_type: bool = True             # 显示 柱/折/堆叠 切换按钮

    # 告警
    alert_threshold: float = None       # 阈值 (超过变红)
    alert_color: str = "#F44336"
    normal_color: str = "#4CAF50"

    # 标记线
    show_markline_avg: bool = False     # 显示均值线
    markline_target: float = None       # 目标线数值

    # 布局
    position: tuple = (0, 0)      # (row, col)
    size: tuple = (1, 1)          # (row_span, col_span)

    # 样式
    style_config: dict = field(default_factory=lambda: {
        # 主题与色板
        "theme": "white",                # pyecharts: WHITE/DARK/CHALK/ESSOS/INFOGRAPHIC/
                                        #   MACARONS/PURPLE_PASSION/ROMA/ROMANTIC/
                                        #   SHINE/VINTAGE/WALDEN/WESTEROS/WONDERLAND/HALLOWEEN
        "color_palette": "default",      # "default" 或颜色列表 ["#FF6B6B", ...]

        # 字体
        "font_family": "Microsoft YaHei",
        "title_font_size": 16,
        "label_font_size": 11,

        # 图例与标签
        "show_legend": True,
        "show_label": False,
        "label_position": "top",         # inside/top/bottom/left/right/insideTop...

        # 透明度与边框
        "item_opacity": 0.9,
        "bar_border_radius": 4,          # 柱状图圆角 (0=直角)

        # 背景
        "bg_color": "",                  # 空=默认白色, 支持 "#1A1A2E" 等

        # 坐标轴
        "axis_line_color": "#999",
        "axis_line_width": 1,
        "split_line_type": "dashed",     # solid/dashed/dotted
        "split_line_color": "#E0E0E0",

        # 数据标签格式化
        "label_formatter": "",           # "{c} 万元" / "{c}%" 等
    })
    custom_options: str = ""      # 自定义 ECharts option JSON 片段


@dataclass
class DashboardDefinition:
    """一份仪表盘的完整定义"""
    id: str = field(default_factory=lambda: _new_id(12))
    name: str = "未命名仪表盘"
    description: str = ""

    # 布局
    grid_columns: int = 3              # 网格列数（1-6）
    grid_row_height: int = 320         # 每行高度（px）

    # 内容
    charts: list = field(default_factory=list)  # list[ChartWidget]

    # 全局筛选
    global_filters: list = field(default_factory=list)  # list[FilterCondition]
    date_range_field: str = ""
    date_range_start: str = ""
    date_range_end: str = ""

    # 其他
    auto_refresh_seconds: int = 0      # 自动刷新间隔（0=不自动刷新）
    theme: str = "light"               # "light" | "dark"

    created_at: str = ""
    modified_at: str = ""
    version: int = 0

    def to_dict(self) -> dict:
        """序列化为字典"""
        return _serialize(self)

    @classmethod
    def from_dict(cls, data: dict) -> "DashboardDefinition":
        """从字典反序列化"""
        return _deserialize_dashboard(data)


@dataclass
class ExcelDataset:
    """Excel/CSV 导入后的数据集"""
    id: str = field(default_factory=_new_id)
    name: str = ""
    source_file: str = ""             # 原始文件路径
    file_type: str = ""               # "xlsx" | "xls" | "csv"
    columns: list = field(default_factory=list)  # [{key, label, data_type}]
    row_count: int = 0
    mysql_table: str = ""             # 导入后的表名 "ex_{id}"
    created_at: str = ""

    def to_dict(self) -> dict:
        return _serialize(self)

    @classmethod
    def from_dict(cls, data: dict) -> "ExcelDataset":
        return _deserialize_excel_dataset(data)


@dataclass
class LLMProvider:
    """AI 大模型提供商配置"""
    id: str = ""                # "deepseek" | "xiaomi_mimo" | "zhipu_glm"
    name: str = ""              # "DeepSeek" | "小米 MiMo" | "智谱 GLM"
    api_url: str = ""           # API 端点
    default_model: str = ""     # 默认模型
    models: list = field(default_factory=list)  # 可选模型列表
    api_key: str = ""           # API Key（从配置加载）
    enabled: bool = False

    def to_dict(self) -> dict:
        return _serialize(self)

    @classmethod
    def from_dict(cls, data: dict) -> "LLMProvider":
        return _deserialize_llm_provider(data)


# ==================== 预定义 AI 提供商 ====================

