# ==================== 序列化辅助 ====================

def _serialize(obj) -> dict:
    """递归序列化 dataclass 对象为纯字典"""
    if hasattr(obj, '__dataclass_fields__'):
        result = {}
        for f_name in obj.__dataclass_fields__:
            val = getattr(obj, f_name)
            result[f_name] = _serialize(val)
        return result
    elif isinstance(obj, (list, tuple)):
        return [_serialize(v) for v in obj]
    elif isinstance(obj, dict):
        return {k: _serialize(v) for k, v in obj.items()}
    elif isinstance(obj, Enum):
        return obj.value
    else:
        return obj


def _deserialize_dashboard(data: dict) -> DashboardDefinition:
    """从字典反序列化 DashboardDefinition"""
    d = dict(data)
    # 反序列化图表列表
    if 'charts' in d and isinstance(d['charts'], list):
        d['charts'] = [_deserialize_chart_widget(c) for c in d['charts']]
    # 序列化元组
    if 'position' in d and isinstance(d['position'], list):
        d['position'] = tuple(d['position'])
    if 'size' in d and isinstance(d['size'], list):
        d['size'] = tuple(d['size'])
    return DashboardDefinition(**{k: v for k, v in d.items() if k in DashboardDefinition.__dataclass_fields__})


def _deserialize_chart_widget(data: dict) -> ChartWidget:
    """从字典反序列化 ChartWidget"""
    d = dict(data)
    if 'position' in d and isinstance(d['position'], list):
        d['position'] = tuple(d['position'])
    if 'size' in d and isinstance(d['size'], list):
        d['size'] = tuple(d['size'])
    # 移除不属于 ChartWidget 的键，但补全 style_config 缺失的新增 key (向后兼容)
    valid_keys = set(ChartWidget.__dataclass_fields__.keys())
    filtered = {k: v for k, v in d.items() if k in valid_keys}
    sc = filtered.get('style_config', {}) or {}
    defaults = ChartWidget.__dataclass_fields__['style_config'].default_factory()
    for k, v in defaults.items():
        sc.setdefault(k, v)
    filtered['style_config'] = sc
    return ChartWidget(**filtered)


def _deserialize_excel_dataset(data: dict) -> ExcelDataset:
    """从字典反序列化 ExcelDataset"""
    d = dict(data)
    valid_keys = set(ExcelDataset.__dataclass_fields__.keys())
    return ExcelDataset(**{k: v for k, v in d.items() if k in valid_keys})


def _deserialize_llm_provider(data: dict) -> LLMProvider:
    """从字典反序列化 LLMProvider"""
    d = dict(data)
    valid_keys = set(LLMProvider.__dataclass_fields__.keys())
    return LLMProvider(**{k: v for k, v in d.items() if k in valid_keys})


# -- custom_report/dashboard/pbix_extractor.py --
"""
PBIX 元数据提取器

提取 .pbix 文件（Power BI）中的图表信息和字段映射，
作为在 BI 仪表盘中重建图表的参考。
"""

import zipfile
import json
import os
import re
import logging
from typing import Optional


logger = logging.getLogger(__name__)


def _decode_bytes(data: bytes) -> str:
    """尝试多种编码解码字节数据"""
    for enc in ('utf-8', 'utf-16', 'utf-8-sig', 'utf-16-le', 'utf-16-be', 'gbk', 'gb2312', 'latin-1'):
        try:
            return data.decode(enc)
        except (UnicodeDecodeError, LookupError):
            continue
    return data.decode('utf-8', errors='replace')


def extract_metadata(file_path: str) -> dict:
    """
    从 .pbix 文件中提取可视化元数据

    Args:
        file_path: .pbix 文件路径

    Returns:
        {
            'success': bool,
            'report_name': str,
            'pages': [{'name': str, 'visuals': [...]}],
            'tables': [str],
            'fields': [str],       # 所有引用字段
            'error': str,          # 仅失败时
        }
    """
    result = {
        'success': False,
        'report_name': '',
        'pages': [],
        'tables': [],
        'fields': [],
        'error': '',
    }

    if not os.path.exists(file_path):
        result['error'] = f'文件不存在: {file_path}'
        return result

    ext = os.path.splitext(file_path)[1].lower()
    if ext not in ('.pbix', '.pbit'):
        result['error'] = f'不支持的格式: {ext}，请选择 .pbix 或 .pbit 文件'
        return result

    try:
        with zipfile.ZipFile(file_path, 'r') as zf:
            # 1. 解析 Report/Layout
            layout_json = None
            for name in zf.namelist():
                if name.lower() == 'report/layout':
                    raw = zf.read(name)
                    text = _decode_bytes(raw)
                    layout_json = json.loads(text)
                    break

            if layout_json is None:
                # 尝试 DataModelSchema
                for name in zf.namelist():
                    if 'datamodelschema' in name.lower():
                        result['error'] = '该 .pbix 使用 Live Connection 模式，无可提取的可视化定义'
                        return result
                result['error'] = '未找到 Report/Layout 文件，可能不是标准 .pbix 格式'
                return result

            # 2. 提取报告名称
            result['report_name'] = _extract_report_name(zf, layout_json)

            # 3. 提取页面和可视化
            sections = layout_json.get('sections', [])
            first_container = True
            for section in sections:
                page = {
                    'name': section.get('displayName', section.get('name', '未命名页面')),
                    'visuals': [],
                }
                for container in section.get('visualContainers', []):
                    config_str = container.get('config', '{}')
                    try:
                        config = json.loads(config_str) if isinstance(config_str, str) else config_str
                    except (json.JSONDecodeError, TypeError):
                        config = {}

                    # 诊断：输出第一个有数据的容器的结构
                    if first_container:
                        sv = config.get('singleVisual', {})
                        vt = sv.get('visualType') or container.get('visualType') or ''
                        if vt and vt not in ('shape', 'image', 'actionButton', 'textbox', 'line'):
                            first_container = False
                            print(f"[BI PBIX] visualType: container={container.get('visualType')}, sv={sv.get('visualType')}")
                            print(f"[BI PBIX] vcObjects 键: {list(sv.get('vcObjects', {}).keys())[:15]}")
                            print(f"[BI PBIX] objects 键: {list(sv.get('objects', {}).keys())[:15]}")
                            try:
                                projs = sv.get('projections', config.get('projections'))
                                if isinstance(projs, list):
                                    print(f"[BI PBIX] projections 示例: {json.dumps(projs[:3], ensure_ascii=False)[:300]}")
                                elif isinstance(projs, dict):
                                    print(f"[BI PBIX] projections(dict) 键: {list(projs.keys())[:10]}")
                            except Exception:
                                pass
                            try:
                                for src_name, src in [('vcObjects', sv.get('vcObjects', {})), ('objects', sv.get('objects', {}))]:
                                    title_cfg = src.get('title')
                                    if title_cfg:
                                        print(f"[BI PBIX] {src_name}.title: {json.dumps(title_cfg, ensure_ascii=False)[:300]}")
                            except Exception:
                                pass
                            for role in ['category', 'y', 'values', 'x', 'Color', 'Size', 'X', 'Y', 'Value', 'Category']:
                                if role in sv.get('vcObjects', {}):
                                    try:
                                        role_data = sv['vcObjects'][role]
                                        print(f"[BI PBIX] vcObjects.{role}: {json.dumps(role_data, ensure_ascii=False)[:300]}")
                                    except Exception:
                                        pass
                                    break

                    # 图表类型：singleVisual.visualType > container.visualType
                    sv = config.get('singleVisual', {})
                    raw_type = sv.get('visualType') or container.get('visualType') or container.get('type') or 'unknown'

                    # 跳过装饰元素（形状、图片、按钮、分隔线）
                    _DECOR_TYPES = ('shape', 'image', 'actionButton', 'textbox', 'line', 'basicShape')
                    if raw_type in _DECOR_TYPES:
                        continue

                    visual_type = _map_visual_type(raw_type)

                    name = config.get('name', '')
                    title = _extract_visual_title(config, container)
                    display_name = title.strip("'\"") if title else ''
                    if not display_name or _is_hash_id(display_name):
                        display_name = name if not _is_hash_id(name) else f'未命名{visual_type}'
                    display_name = display_name.strip("'\"")

                    try:
                        fields = _extract_fields(config)
                    except Exception:
                        fields = []

                    page['visuals'].append({
                        'name': display_name,
                        'type': visual_type,
                        'pbix_type': raw_type,
                        'fields': fields,
                    })
                    for f in fields:
                        if f not in result['fields']:
                            result['fields'].append(f)

                result['pages'].append(page)

            # 4. 提取表名
            result['tables'] = _extract_tables(zf)

        result['success'] = True
    except zipfile.BadZipFile:
        result['error'] = '文件损坏或不是有效的 .pbix 文件'
    except Exception as e:
        result['error'] = f'提取失败: {e}'

    return result


def _extract_report_name(zf: zipfile.ZipFile, layout_json: dict) -> str:
    """从布局或连接文件中提取报告名称"""
    name = layout_json.get('displayName', '') or layout_json.get('name', '')
    if name:
        return name

    # 尝试从 Connections 获取
    for fname in zf.namelist():
        if 'connections' in fname.lower():
            try:
                conn = json.loads(_decode_bytes(zf.read(fname)))
                if isinstance(conn, dict):
                    name = conn.get('Name', '') or conn.get('name', '')
            except Exception:
                pass
            if name:
                return name

    return '未命名报告'


def _extract_fields(config: dict) -> list[str]:
    """从可视化配置中递归提取字段引用"""
    fields = []
    if not isinstance(config, dict):
        return fields

    def _add_field(tbl: str, col: str):
        if col and col not in ('undefined', 'null', ''):
            key = f"{tbl}.{col}" if tbl else col
            if key not in fields:
                fields.append(key)

    def _walk(obj, depth=0):
        if depth > 25:
            return
        if isinstance(obj, dict):
            # SourceRef 模式（最常见）
            sr = obj.get('SourceRef')
            if isinstance(sr, dict):
                tbl = sr.get('Entity', '') or sr.get('Table', '')
                col = sr.get('Column', '') or sr.get('Name', '') or sr.get('Property', '')
                _add_field(tbl, col)
            # QueryRef
            qr = obj.get('QueryRef')
            if qr:
                fields.append(str(qr))
            # 遍历子节点
            for key, val in obj.items():
                if key in ('SourceRef', 'QueryRef', 'Literal'):
                    continue  # 已处理或跳过
                _walk(val, depth + 1)
        elif isinstance(obj, list):
            for item in obj:
                _walk(item, depth + 1)
        elif isinstance(obj, str) and depth == 0:
            pass  # 顶层字符串忽略

    # 同时搜索 singleVisual 和 objects
    _walk(config)
    sv = config.get('singleVisual', {})
    _walk(sv.get('objects', {}))
    _walk(sv.get('vcObjects', {}))

    # 从 projections 提取
    if not fields:
        projections = sv.get('projections', config.get('projections', []))
        if isinstance(projections, list):
            for p in projections:
                if isinstance(p, dict):
                    qr = p.get('queryRef', '')
                    if qr:
                        fields.append(str(qr))

    return sorted(set(fields))


def _extract_tables(zf: zipfile.ZipFile) -> list[str]:
    """从 DataModel 中提取表名"""
    tables = []
    for name in zf.namelist():
        if 'datamodel' in name.lower() and name.lower().endswith('.json'):
            try:
                dm = json.loads(_decode_bytes(zf.read(name)))
                if isinstance(dm, dict):
                    model = dm.get('model', dm)
                    for tbl in model.get('tables', []):
                        tbl_name = tbl.get('name', '') or tbl.get('Name', '')
                        if tbl_name and not tbl_name.startswith('_'):
                            tables.append(tbl_name)
            except Exception:
                pass
            if tables:
                break
    return sorted(set(tables))


# 常见 PBIX visualType → 中文名映射
_PBIX_TYPE_MAP = {
    # 柱状图
    'barChart': '柱状图', 'columnChart': '柱状图',
    'clusteredBarChart': '簇状柱状图', 'clusteredColumnChart': '簇状柱状图',
    'stackedBarChart': '堆叠柱状图', 'stackedColumnChart': '堆叠柱状图',
    'hundredPercentStackedBarChart': '百分比堆叠柱状图',
    'hundredPercentStackedColumnChart': '百分比堆叠柱状图',
    'ribbonChart': '带状图',
    # 折线/面积
    'lineChart': '折线图', 'areaChart': '面积图', 'stackedAreaChart': '堆叠面积图',
    # 饼/环形
    'pieChart': '饼图', 'donutChart': '环形图',
    'barOfPieChart': '饼图',
    # 散点/气泡
    'scatterChart': '散点图', 'waterfallChart': '瀑布图',
    # 树图/漏斗
    'treemap': '矩形树图', 'funnel': '漏斗图',
    'decompositionTree': '分解树', 'decompositionTreeVisual': '分解树',
    # 卡片/KPI
    'card': '指标卡', 'cardVisual': '指标卡', 'multiRowCard': '多行卡片', 'kpi': 'KPI',
    # 表/矩阵
    'tableEx': '表格', 'pivotTable': '透视表', 'matrix': '矩阵',
    # 仪表
    'gauge': '仪表盘',
    # 切片器
    'slicer': '切片器',
    # 地图
    'map': '地图', 'filledMap': '填充地图', 'shapeMap': '形状地图',
    # 自定义
    'scriptVisual': '脚本可视化', 'customVisual': '自定义可视化',
    # 装饰
    'shape': '形状(装饰)', 'image': '图片(装饰)', 'actionButton': '按钮(装饰)',
    'textbox': '文本框(装饰)', 'line': '分隔线(装饰)',
    # 其他
    'qna': '问答', 'keyDriversVisual': '关键影响因素',
}


def _map_visual_type(pbix_type: str) -> str:
    """将 PBIX visualType 映射为中文名"""
    if pbix_type in _PBIX_TYPE_MAP:
        return _PBIX_TYPE_MAP[pbix_type]
    # 处理带 GUID/Hex 后缀的自定义视觉（如 deneb7E15..., barOfPieChartEF91...）
    import re
    base = re.sub(r'[0-9A-F]{20,}$', '', pbix_type)
    if base and base != pbix_type and base in _PBIX_TYPE_MAP:
        return _PBIX_TYPE_MAP[base]
    if base and base != pbix_type:
        return f'自定义({base})'
    return f'自定义({pbix_type[:20]})'


def _extract_visual_title(config: dict, container: dict) -> str:
    """从 PBIX 可视化配置中提取标题（多路径 fallback）"""
    # 路径 1: container 上的直接属性
    for key in ('friendlyName', 'displayName', 'title'):
        val = container.get(key, '')
        if val and not _is_hash_id(str(val)):
            return str(val)

    # 路径 2: vcObjects.title / objects.title
    for src_key in ('vcObjects', 'objects'):
        try:
            src = config.get('singleVisual', {}).get(src_key, {})
            title_cfg = src.get('title', [])
            if isinstance(title_cfg, list) and title_cfg:
                val = _extract_literal_value(title_cfg[0])
                if val:
                    return val
        except Exception:
            pass

    # 路径 3: 全量扫描 Literal.Value，找最长的人类可读文本
    return _deep_find_title(config)


def _extract_literal_value(obj, depth=0) -> str:
    """从嵌套对象中提取 Literal.Value"""
    if depth > 8:
        return ''
    if isinstance(obj, dict):
        if 'Literal' in obj and isinstance(obj['Literal'], dict):
            val = obj['Literal'].get('Value', '')
            if isinstance(val, str) and len(val) > 1:
                return val
        if 'Value' in obj and isinstance(obj['Value'], str) and len(obj['Value']) > 1:
            return obj['Value']
        for v in obj.values():
            r = _extract_literal_value(v, depth + 1)
            if r:
                return r
    elif isinstance(obj, list):
        for item in obj:
            r = _extract_literal_value(item, depth + 1)
            if r:
                return r
    return ''


def _deep_find_title(obj, depth=0) -> str:
    """全量扫描所有 Literal.Value，返回最可能是标题的文本（最长非哈希字符串）"""
    if depth > 8:
        return ''
    candidates = []

    def _collect(obj, d):
        if d > 8:
            return
        if isinstance(obj, dict):
            if 'Literal' in obj and isinstance(obj['Literal'], dict):
                val = obj['Literal'].get('Value', '')
                if isinstance(val, str) and len(val) > 2 and not _is_hash_id(val):
                    candidates.append(val)
            for v in obj.values():
                _collect(v, d + 1)
        elif isinstance(obj, list):
            for item in obj:
                _collect(item, d + 1)

    _collect(obj, 0)
    # 返回最长的候选（排除包含 SQL/DAX 代码特征的）
    candidates = [c for c in candidates if not c.startswith('let ') and '=' not in c[:3]]
    return max(candidates, key=len) if candidates else ''


def _is_hash_id(s: str) -> bool:
    """判断字符串是否为哈希 ID（16~24 位 hex）"""
    s = (s or '').strip("'\"")
    return bool(re.match(r'^[0-9a-fA-F]{12,30}$', s))


# ====== PBIX 类型 → 我们的图表类型 ======
_PBIX_TO_OUR_TYPE = {
    'barChart': 'bar', 'columnChart': 'bar', 'clusteredBarChart': 'bar',
    'clusteredColumnChart': 'bar', 'stackedBarChart': 'stacked_bar',
    'stackedColumnChart': 'stacked_bar',
    'lineChart': 'line', 'areaChart': 'area', 'stackedAreaChart': 'stacked_area',
    'pieChart': 'pie', 'donutChart': 'pie',
    'scatterChart': 'scatter', 'waterfallChart': 'waterfall',
    'treemap': 'treemap', 'funnel': 'funnel',
    'card': 'card', 'cardVisual': 'card', 'kpi': 'card',
    'tableEx': 'table', 'matrix': 'table', 'pivotTable': 'table',
    'gauge': 'gauge', 'slicer': 'table',
    'map': 'map_china', 'filledMap': 'map_china',
    'decompositionTree': 'tree', 'decompositionTreeVisual': 'tree',
    'ribbonChart': 'bar', 'keyDriversVisual': 'bar',
}


def _get_role_field(role_data) -> str:
    """从 PBIX role 数据中提取字段引用"""
    if not role_data:
        return ''
    data = role_data[0] if isinstance(role_data, list) else role_data
    if not isinstance(data, dict):
        return ''
    # 尝试 SourceRef
    sr = data.get('expr', {}).get('SourceRef', data.get('SourceRef', {}))
    if isinstance(sr, dict):
        col = sr.get('Column', '') or sr.get('Name', '') or sr.get('Property', '')
        return col
    # 尝试 queryRef
    qr = data.get('queryRef', '')
    if qr and isinstance(qr, str):
        return qr.split('.')[-1] if '.' in qr else qr
    return ''


def extract_to_dashboard(file_path: str) -> dict:
    """
    从 .pbix/.pbit 文件直接生成仪表盘定义，含图表和字段映射。

    Returns:
        {
            'success': bool,
            'dashboard': DashboardDefinition or None,
            'report_name': str,
            'chart_count': int,
            'error': str,
        }
    """
    result = {
        'success': False,
        'dashboard': None,
        'report_name': '',
        'chart_count': 0,
        'error': '',
    }

    if not os.path.exists(file_path):
        result['error'] = f'文件不存在: {file_path}'
        return result

    ext = os.path.splitext(file_path)[1].lower()
    if ext not in ('.pbix', '.pbit'):
        result['error'] = f'不支持的格式: {ext}'
        return result

    try:
        with zipfile.ZipFile(file_path, 'r') as zf:
            layout_json = None
            for name in zf.namelist():
                if name.lower() == 'report/layout':
                    layout_json = json.loads(_decode_bytes(zf.read(name)))
                    break
            if not layout_json:
                result['error'] = '未找到 Report/Layout'
                return result

            report_name = _extract_report_name(zf, layout_json)
            dashboard = DashboardDefinition(name=report_name or 'PBIX 导入')
            charts = []
            _DECOR_TYPES = ('shape', 'image', 'actionButton', 'textbox', 'line', 'basicShape')

            for section in layout_json.get('sections', []):
                for container in section.get('visualContainers', []):
                    config_str = container.get('config', '{}')
                    try:
                        config = json.loads(config_str) if isinstance(config_str, str) else config_str
                    except Exception:
                        config = {}

                    sv = config.get('singleVisual', {})
                    raw_type = sv.get('visualType') or container.get('visualType') or ''
                    if raw_type in _DECOR_TYPES:
                        continue

                    # 图表类型
                    our_type = _PBIX_TO_OUR_TYPE.get(raw_type, 'bar')
                    # 标题
                    title = _extract_visual_title(config, container).strip("'\"")
                    if not title or _is_hash_id(title):
                        title = _map_visual_type(raw_type)

                    # 提取字段映射
                    vc = sv.get('vcObjects', {})
                    x_field = _get_role_field(vc.get('category') or vc.get('Category') or vc.get('x') or vc.get('X') or vc.get('Axis'))
                    y_field = _get_role_field(vc.get('y') or vc.get('Y') or vc.get('values') or vc.get('Values') or vc.get('measures') or vc.get('Measure'))
                    color_field = _get_role_field(vc.get('Color') or vc.get('Legend') or vc.get('series') or vc.get('Series'))
                    size_field = _get_role_field(vc.get('Size') or vc.get('bubbleSize'))

                    # 如果没有从 vcObjects 提取到，尝试从 projections 提取
                    if not x_field or not y_field:
                        projs = sv.get('projections', config.get('projections', []))
                        if isinstance(projs, list) and len(projs) >= 2:
                            if not x_field and len(projs) > 0:
                                x_field = str(projs[0].get('queryRef', '')).split('.')[-1]
                            if not y_field and len(projs) > 1:
                                y_field = str(projs[1].get('queryRef', '')).split('.')[-1]

                    # 位置：从 PBIX 容器坐标推算
                    x = container.get('x', 0)
                    y = container.get('y', 0)
                    w = container.get('width', 400)
                    h = container.get('height', 300)
                    col = max(0, int(x / 400))
                    row = max(0, int(y / 300))
                    col_span = max(1, int(w / 400))
                    row_span = max(1, int(h / 300))

                    y_fields = [y_field] if y_field else []
                    chart = ChartWidget(
                        id=_new_id(),
                        chart_type=our_type,
                        title=title,
                        x_field=x_field,
                        y_fields=y_fields,
                        aggregate_funcs={y_field: 'SUM'} if y_field else {},
                        color_field=color_field or '',
                        size_field=size_field or '',
                        position=(row, col),
                        size=(row_span, col_span),
                        data_source_type='report',
                        data_source_id='',
                        data_source_name='(需手动选择数据源)',
                    )
                    charts.append(chart)

            dashboard.charts = charts
            result['dashboard'] = dashboard
            result['chart_count'] = len(charts)
            result['report_name'] = report_name
            result['success'] = True

    except Exception as e:
        result['error'] = str(e)

    return result


# -- custom_report/dashboard/pyecharts_renderer.py --
"""
pyecharts 渲染引擎 — 完整实现
===============================

将 ChartWidget 数据模型 + 查询结果数据 → pyecharts 图表 → HTML 片段。
替代 html_template.py 中的 buildOption() 手写 JS (331-505 行)。

支持的图表类型 (28 种)：
    基础: bar, line, pie, scatter, area, table
    指标: card, gauge
    变体: combo, stacked_bar, stacked_area, pictorial_bar,
          effect_scatter, waterfall
    构成: funnel, treemap, sunburst
    分布: boxplot, heatmap, calendar, candlestick
    流向: sankey, graph, tree
    多维: radar, parallel, theme_river
    地理: map_china, map_scatter, map_lines
    其他: word_cloud

额外支持的 pyecharts 独有类型：
    liquid (水球图), polar (极坐标), chord (和弦图)

依赖: pyecharts >= 2.0
"""

# ============================================================================
# 导入
# ============================================================================

import os
import sys
from typing import Any, Dict, List, Optional, Sequence, Tuple, Union

# ============================================================================
# 自动发现 pyecharts 源码路径
# ============================================================================

_pyecharts_loaded = False
_possible_pyecharts_dirs = [
    os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', 'pyecharts-master'),
    os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', '..', 'pyecharts-master'),
    os.path.join(os.path.dirname(os.path.abspath(__file__)), 'pyecharts-master'),
]
for _d in _possible_pyecharts_dirs:
    _d = os.path.normpath(os.path.abspath(_d))
    if os.path.isdir(_d) and _d not in sys.path:
        sys.path.insert(0, _d)

def _ensure_pyecharts():
    """确保 pyecharts 可用；返回 True/False"""
    try:
        import pyecharts  # noqa: F401
        return True
    except ImportError:
        return False

# ============================================================================
# pyecharts 全局配置 (离线环境)
# ============================================================================

# 让 pyecharts 使用本地 ECharts 文件而非 CDN
# 在初始化时由外部调用 set_echarts_base_url() 配置

_echarts_base_dir: str = ""


def set_echarts_base_dir(dir_path: str):
    """
    设置 ECharts 资源的本地目录。

    Args:
        dir_path: echarts.min.js 等文件所在目录的绝对路径
                  通常是 custom_report/dashboard/echarts/
    """
    global _echarts_base_dir
    _echarts_base_dir = dir_path

    # 配置 pyecharts 使用本地文件
    if _ensure_pyecharts():
        from pyecharts.globals import CurrentConfig
        # 使用 file:// 协议指向本地文件
        CurrentConfig.ONLINE_HOST = f"file:///{dir_path.replace(os.sep, '/')}/"


# ============================================================================
# 工具函数
# ============================================================================

def _safe_float(v: Any, default: float = 0.0) -> float:
    """安全转换为 float"""
    try:
        return float(v) if v is not None else default
    except (ValueError, TypeError):
        return default


def _safe_str(v: Any, default: str = "") -> str:
    """安全转换为 str"""
    if v is None:
        return default
    return str(v)


def _extract_x(data: List[dict], x_field: str) -> list:
    """从数据列表提取 X 轴去重值（保持顺序）"""
    if not x_field:
        return []
    seen = set()
    result = []
    for row in data:
        v = _safe_str(row.get(x_field, ""))
        if v not in seen:
            seen.add(v)
            result.append(v)
    return result


def _extract_y(data: List[dict], x_field: str, y_field: str) -> list:
    """按 X 轴顺序提取 Y 值"""
    if not y_field:
        return []
    x_values = _extract_x(data, x_field)
    mapping = {}
    for row in data:
        xv = _safe_str(row.get(x_field, ""))
        mapping[xv] = _safe_float(row.get(y_field, 0))
    return [mapping.get(x, 0) for x in x_values]


def _group_by_color(
    data: List[dict],
    x_field: str,
    y_field: str,
    color_field: str,
) -> Dict[str, list]:
    """按 color_field 分组，返回 {group_name: [y_value_per_x]}"""
    x_values = _extract_x(data, x_field)
    groups: Dict[str, Dict[str, float]] = {}

    for row in data:
        g = _safe_str(row.get(color_field, ""))
        xv = _safe_str(row.get(x_field, ""))
        yv = _safe_float(row.get(y_field, 0))
        if g not in groups:
            groups[g] = {x: 0.0 for x in x_values}
        groups[g][xv] = yv

    return {g: [vals[x] for x in x_values] for g, vals in groups.items()}


def _pie_pairs(data: List[dict], name_field: str, value_field: str) -> list:
    """生成饼图数据 [(name, value), ...]"""
    return [(_safe_str(r.get(name_field, "")), _safe_float(r.get(value_field, 0)))
            for r in data]


def _apply_filters(rows: list, filters: list) -> list:
    """对数据行应用筛选条件（与 dashboard_designer._apply_filters 同步）"""
    if not filters or not rows:
        return rows
    result = list(rows)
    for f in filters:
        field = (f.get('field') or '').strip()
        op = (f.get('op') or '').strip()
        value = (f.get('value') or '').strip()
        if not field:
            continue
        if op in ('为空', '不为空'):
            result = [r for r in result
                      if (not str(r.get(field, '')).strip()) == (op == '为空')]
        elif op == '属于' and value:
            vals = set(v.strip() for v in value.split(',') if v.strip())
            result = [r for r in result if str(r.get(field, '')).strip() in vals] if vals else result
        elif op == '不属于' and value:
            vals = set(v.strip() for v in value.split(',') if v.strip())
            result = [r for r in result if str(r.get(field, '')).strip() not in vals] if vals else result
        elif op == '包含' and value:
            result = [r for r in result if value.lower() in str(r.get(field, '')).lower()]
        elif op == '不包含' and value:
            result = [r for r in result if value.lower() not in str(r.get(field, '')).lower()]
        elif op in ('等于', '不等于', '大于', '小于', '大于等于', '小于等于') and value:
            # 尝试数值比较，失败则退化为字符串比较
            try:
                v_num = float(value)
                is_numeric = True
            except (ValueError, TypeError):
                v_num = 0
                is_numeric = False
            filtered = []
            for r in result:
                rv_str = str(r.get(field, ''))
                if is_numeric:
                    try:
                        rv = float(rv_str)
                    except (ValueError, TypeError):
                        rv = rv_str
                else:
                    rv = rv_str
                if op == '等于':
                    ok = (rv == v_num) if is_numeric else (rv_str == value)
                elif op == '不等于':
                    ok = (rv != v_num) if is_numeric else (rv_str != value)
                elif op in ('大于', '小于', '大于等于', '小于等于'):
                    if not is_numeric or not isinstance(rv, (int, float)):
                        continue
                    ok = {'大于': rv > v_num, '小于': rv < v_num,
                          '大于等于': rv >= v_num, '小于等于': rv <= v_num}[op]
                else:
                    ok = False
                if ok:
                    filtered.append(r)
            result = filtered
    return result


# ============================================================================
# 图表渲染器
# ============================================================================

class PyechartsRenderer:
    """
    将 ChartWidget + 查询数据 → pyecharts 图表 → HTML 片段。

    用法:
        from pyecharts_renderer import PyechartsRenderer

        html = PyechartsRenderer.render(chart_widget, data_rows)
        # → 可直接嵌入 <div class="card bd"> 的 HTML 字符串
    """

    # ================================================================
    # 主入口
    # ================================================================

    @classmethod
    def render(cls, chart: Any, data: List[dict]) -> str:
        """
        主入口：ChartWidget + 数据 → HTML 片段。
        """
        chart_type = (chart.chart_type or "bar").lower() if hasattr(chart, 'chart_type') else "bar"

        # 纯 HTML 类型
        if chart_type == "card":
            return cls._render_card(chart, data)
        if chart_type == "table":
            return cls._render_table(chart, data)

        # 应用筛选条件
        filters = getattr(chart, 'filters', None) or []
        if filters:
            data = _apply_filters(data, filters)

        # 空数据处理
        if not data:
            return cls._render_empty(chart)

        # 分发到具体渲染方法
        if not _ensure_pyecharts():
            return cls._render_empty(chart)

        handler = cls._DISPATCH.get(chart_type)
        if handler is None:
            return cls._render_unsupported(chart_type)

        try:
            c = handler(chart, data)
            if c is None:
                return cls._render_unsupported(chart_type)

            # 应用样式：色板
            cls._apply_colors(c, chart)
            # 应用样式：主题 / 背景
            style = cls._get_style(chart)
            bg = style.get('bg_color', '')
            if bg:
                c.options.update(backgroundColor=bg)
            theme = (style.get('theme') or 'white').lower()
            if theme == 'dark':
                c.set_dark_mode(dark_mode_bg_color=bg or '#100C2A')

            # 应用全局选项 (标题/图例/toolbox/Brush/DataZoom)
            cls._apply_global_opts(c, chart)

            # 生成 ECharts option — 直接嵌入为 JS 对象字面量，避免 JSON.parse 环节
            opt_json = c.dump_options_with_quotes()

            # 将 option JSON 附着到 chart_widget 对象上 (副作用)
            if hasattr(chart, '__dict__'):
                object.__setattr__(chart, '_echarts_option', opt_json)

            return c.render_embed()
        except Exception as e:
            return cls._render_error(chart, str(e))

    # ================================================================
    # 图表类型分发表
    # ================================================================

    _DISPATCH: Dict[str, Any] = {}  # 在类定义完成后填充

    # ================================================================
    # 空数据 / 错误占位
    # ================================================================

    @classmethod
    def _render_empty(cls, chart: Any) -> str:
        title = getattr(chart, 'title', '') or '图表'
        return (
            f'<div style="color:#999;padding:20px;text-align:center;">'
            f'📭 暂无数据<br><small>{title}</small></div>'
        )

    @classmethod
    def _render_unsupported(cls, chart_type: str) -> str:
        return (
            f'<div style="color:#FF4D4F;padding:20px;text-align:center;">'
            f'❌ 不支持的图表类型: {chart_type}</div>'
        )

    @classmethod
    def _render_error(cls, chart: Any, error_msg: str) -> str:
        title = getattr(chart, 'title', '') or '图表'
        return (
            f'<div style="color:#FF4D4F;padding:16px;text-align:center;font-size:13px;">'
            f'❌ {title} 渲染失败<br><small>{error_msg}</small></div>'
        )

    # ================================================================
    # 纯 HTML 渲染 (card / table)
    # ================================================================

    @classmethod
    def _render_card(cls, chart: Any, data: List[dict]) -> str:
        """指标卡 — 纯 HTML/CSS"""
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        title = getattr(chart, 'title', '') or ''
        if data and y_field:
            v = data[0].get(y_field, 0)
        else:
            v = 0
        if isinstance(v, (int, float)):
            formatted = f"{v:,.0f}"
        else:
            formatted = str(v)
        return (
            f'<div class="kpi">'
            f'<div class="v">{formatted}</div>'
            f'<div class="l">{title}</div>'
            f'</div>'
        )

    @classmethod
    def _render_table(cls, chart: Any, data: List[dict]) -> str:
        """表格 — y_fields 指定显示列，为空则显示全部列"""
        if not data:
            return '<div style="padding:20px;color:#999;text-align:center;">无数据</div>'
        y_fields = getattr(chart, 'y_fields', []) or []
        if y_fields:
            cols = [f for f in y_fields if f in data[0]]
            if not cols:
                cols = list(data[0].keys())
        else:
            cols = list(data[0].keys())
        parts = ['<div class="tbl"><table><thead><tr>']
        for col in cols:
            parts.append(f'<th>{col}</th>')
        parts.append('</tr></thead><tbody>')
        for row in data:
            parts.append('<tr>')
            for col in cols:
                parts.append(f'<td>{row.get(col, "")}</td>')
            parts.append('</tr>')
        parts.append('</tbody></table></div>')
        return ''.join(parts)

    # ================================================================
    # 基础图表
    # ================================================================

    @classmethod
    def _bar(cls, chart: Any, data: List[dict]):
        """柱状图"""
        from pyecharts.charts import Bar
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        color_field = getattr(chart, 'color_field', '')

        x_data = _extract_x(data, x_field)
        c = Bar()
        c.add_xaxis(x_data)

        if color_field:
            groups = _group_by_color(data, x_field, y_field, color_field)
            for g_name, g_vals in groups.items():
                c.add_yaxis(series_name=g_name, y_axis=g_vals)
        else:
            y_data = _extract_y(data, x_field, y_field)
            c.add_yaxis(series_name=getattr(chart, 'title', '') or y_field, y_axis=y_data)

        series_opts = cls._make_series_opts(chart, 'bar')
        c.set_series_opts(**series_opts)
        return c

    @classmethod
    def _stacked_bar(cls, chart: Any, data: List[dict]):
        """堆叠柱状图"""
        from pyecharts.charts import Bar
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        color_field = getattr(chart, 'color_field', '')

        x_data = _extract_x(data, x_field)
        c = Bar()
        c.add_xaxis(x_data)

        if color_field:
            groups = _group_by_color(data, x_field, y_field, color_field)
            for g_name, g_vals in groups.items():
                c.add_yaxis(series_name=g_name, y_axis=g_vals, stack="total")
        else:
            y_data = _extract_y(data, x_field, y_field)
            c.add_yaxis(
                series_name=getattr(chart, 'title', '') or y_field,
                y_axis=y_data, stack="total",
            )

        series_opts = cls._make_series_opts(chart, 'stacked_bar')
        c.set_series_opts(**series_opts)
        return c

    @classmethod
    def _line(cls, chart: Any, data: List[dict]):
        """折线图"""
        from pyecharts.charts import Line
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        color_field = getattr(chart, 'color_field', '')

        x_data = _extract_x(data, x_field)
        c = Line()
        c.add_xaxis(x_data)

        if color_field:
            groups = _group_by_color(data, x_field, y_field, color_field)
            for g_name, g_vals in groups.items():
                c.add_yaxis(
                    series_name=g_name, y_axis=g_vals,
                    is_smooth=True, is_symbol_show=True,
                )
        else:
            y_data = _extract_y(data, x_field, y_field)
            c.add_yaxis(
                series_name=getattr(chart, 'title', '') or y_field,
                y_axis=y_data, is_smooth=True, is_symbol_show=True,
            )

        c.set_series_opts(**cls._make_series_opts(chart, 'line'))
        return c

    @classmethod
    def _area(cls, chart: Any, data: List[dict]):
        """面积图"""
        from pyecharts.charts import Line
        from pyecharts import options as opts
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        color_field = getattr(chart, 'color_field', '')

        x_data = _extract_x(data, x_field)
        c = Line()
        c.add_xaxis(x_data)

        area_opts = opts.AreaStyleOpts(opacity=0.5)
        if color_field:
            groups = _group_by_color(data, x_field, y_field, color_field)
            for g_name, g_vals in groups.items():
                c.add_yaxis(
                    series_name=g_name, y_axis=g_vals,
                    areastyle_opts=area_opts, is_smooth=True,
                )
        else:
            y_data = _extract_y(data, x_field, y_field)
            c.add_yaxis(
                series_name=getattr(chart, 'title', '') or y_field,
                y_axis=y_data, areastyle_opts=area_opts, is_smooth=True,
            )
        return c

    @classmethod
    def _stacked_area(cls, chart: Any, data: List[dict]):
        """堆叠面积图"""
        from pyecharts.charts import Line
        from pyecharts import options as opts
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        color_field = getattr(chart, 'color_field', '')

        x_data = _extract_x(data, x_field)
        c = Line()
        c.add_xaxis(x_data)

        area_opts = opts.AreaStyleOpts(opacity=0.5)
        if color_field:
            groups = _group_by_color(data, x_field, y_field, color_field)
            for g_name, g_vals in groups.items():
                c.add_yaxis(
                    series_name=g_name, y_axis=g_vals,
                    areastyle_opts=area_opts, stack="total", is_smooth=True,
                )
        else:
            y_data = _extract_y(data, x_field, y_field)
            c.add_yaxis(
                series_name=getattr(chart, 'title', '') or y_field,
                y_axis=y_data, areastyle_opts=area_opts, stack="total", is_smooth=True,
            )
        return c

    @classmethod
    def _pie(cls, chart: Any, data: List[dict]):
        """饼图"""
        from pyecharts.charts import Pie
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""

        c = Pie()
        pairs = _pie_pairs(data, x_field, y_field)
        c.add(
            series_name=getattr(chart, 'title', '') or y_field,
            data_pair=pairs,
            radius=["35%", "65%"],
        )
        c.set_series_opts(**cls._make_series_opts(chart, 'pie'))
        return c

    @classmethod
    def _scatter(cls, chart: Any, data: List[dict]):
        """散点图"""
        from pyecharts.charts import Scatter
        from pyecharts import options as opts
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""

        x_vals = [_safe_float(r.get(x_field, 0)) for r in data]
        y_vals = [_safe_float(r.get(y_field, 0)) for r in data]

        c = Scatter()
        c.add_xaxis(x_vals)
        c.add_yaxis(
            series_name=getattr(chart, 'title', '') or y_field,
            y_axis=y_vals,
            symbol_size=10,
            label_opts=opts.LabelOpts(is_show=False),
        )
        return c

    # ================================================================
    # 指标类
    # ================================================================

    @classmethod
    def _gauge(cls, chart: Any, data: List[dict]):
        """仪表盘"""
        from pyecharts.charts import Gauge
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        title = getattr(chart, 'title', '') or y_field
        v = _safe_float(data[0].get(y_field, 0)) if data else 0

        c = Gauge()
        c.add(
            series_name=title,
            data_pair=[(title, v)],
            max_=max(v * 1.5, 100),
        )
        return c

    # ================================================================
    # 组合 / 变体
    # ================================================================

    @classmethod
    def _combo(cls, chart: Any, data: List[dict]):
        """组合图 (柱状 + 折线)"""
        from pyecharts.charts import Bar, Line
        from pyecharts.charts.composite_charts import Grid
        from pyecharts import options as opts
        x_field = getattr(chart, 'x_field', '')
        y_fields = chart.y_fields if hasattr(chart, 'y_fields') else []
        title = getattr(chart, 'title', '')

        x_data = _extract_x(data, x_field)
        bar = Bar()
        bar.add_xaxis(x_data)

        line = Line()
        line.add_xaxis(x_data)

        # 第一个度量用柱状，第二个用折线
        if len(y_fields) >= 1:
            y1 = y_fields[0]
            bar.add_yaxis(series_name=y1, y_axis=_extract_y(data, x_field, y1))
        if len(y_fields) >= 2:
            y2 = y_fields[1]
            line.add_yaxis(
                series_name=y2, y_axis=_extract_y(data, x_field, y2),
                is_smooth=True,
            )

        bar.set_global_opts(
            title_opts=opts.TitleOpts(title=title),
            tooltip_opts=opts.TooltipOpts(trigger="axis"),
        )

        c = Grid()
        c.add(bar, grid_opts=opts.GridOpts(pos_left="10%", pos_right="10%"))
        c.add(line, grid_opts=opts.GridOpts(pos_left="10%", pos_right="10%"))
        return c

    @classmethod
    def _pictorial_bar(cls, chart: Any, data: List[dict]):
        """象形柱状图"""
        from pyecharts.charts import PictorialBar
        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""

        x_data = _extract_x(data, x_field)
        y_data = _extract_y(data, x_field, y_field)

        c = PictorialBar()
        c.add_xaxis(x_data)
        c.add_yaxis(
            series_name=getattr(chart, 'title', '') or y_field,
            y_axis=y_data,
            symbol="roundRect",
            symbol_size=[20, 10],
        )
        c.set_series_opts(**cls._make_series_opts(chart, 'pictorial_bar'))
        return c

    @classmethod
    def _effect_scatter(cls, chart: Any, data: List[dict]):
        """涟漪散点图"""
        from pyecharts.charts import EffectScatter
        from pyecharts import options as opts

        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""

        x_vals = [_safe_float(r.get(x_field, 0)) for r in data]
        y_vals = [_safe_float(r.get(y_field, 0)) for r in data]

        c = EffectScatter()
        c.add_xaxis(x_vals)
        c.add_yaxis(
            series_name=getattr(chart, 'title', '') or y_field,
            y_axis=y_vals,
            effect_opts=opts.EffectOpts(scale=3.5, brush_type="stroke"),
            label_opts=opts.LabelOpts(is_show=False),
        )
        return c

    @classmethod
    def _waterfall(cls, chart: Any, data: List[dict]):
        """瀑布图 (通过堆叠柱状 + 透明底柱实现)"""
        from pyecharts.charts import Bar
        from pyecharts import options as opts

        x_field = getattr(chart, 'x_field', '')
        y_field = (chart.y_fields or [""])[0] if hasattr(chart, 'y_fields') else ""
        title = getattr(chart, 'title', '')

        vals = [_safe_float(r.get(y_field, 0)) for r in data]
        x_data = [_safe_str(r.get(x_field, "")) for r in data]

        # 瀑布图逻辑：计算累计值
        base = []
        increase = []
        decrease = []
        running = 0.0
        for v in vals:
            if v >= 0:
                base.append(running)
                increase.append(v)
                decrease.append("-")
            else:
                base.append(running + v)
                increase.append("-")
                decrease.append(-v)
            running += v if v else 0

        c = Bar()
        c.add_xaxis(x_data)
        c.add_yaxis("增加", increase, stack="waterfall",
                     itemstyle_opts=opts.ItemStyleOpts(color="#4CAF50"))
        c.add_yaxis("减少", decrease, stack="waterfall",
                     itemstyle_opts=opts.ItemStyleOpts(color="#F44336"))
        c.add_yaxis("base", base, stack="waterfall",
                     itemstyle_opts=opts.ItemStyleOpts(color="transparent"),
                     label_opts=opts.LabelOpts(is_show=False))
        c.set_series_opts(**cls._make_series_opts(chart, 'waterfall'))
        return c

