        self._excel_repo = excel_repo
        self._table_data: dict[str, dict] = {}  # {table_name: {display_name, fields, source_type, ...}}
        self._name_map: dict[str, str] = {}  # {raw_name: mapped_name}
        self._bg_processing = False  # 后台数据加载标志
